def _parse_optional_percentage_form(value: Optional[str]) -> Optional[float]:
    raw = (value or "").strip()
    if not raw:
        return None
    return normalize_hospedaje_rate(raw)


def _parse_optional_money_form(value: Optional[str]) -> Optional[float]:
    raw = (value or "").strip()
    if not raw:
        return None
    try:
        return round(float(raw), 2)
    except (TypeError, ValueError):
        return None


def _repo_root() -> Path:
    return Path(__file__).resolve().parents[4]


def _bank_upload_cache_path(filename: str) -> Path:
    return _repo_root() / "data" / "accounting" / "bank_uploads" / Path(filename or "bank.csv").name


def _admin_subprocess_env() -> dict[str, str]:
    env = os.environ.copy()
    env_path = _repo_root() / ".env"
    env.update({k: v for k, v in dotenv_values(env_path).items() if v is not None})
    return env


async def _reconciliation_period_stats(
    session: AsyncSession,
    start_dt: datetime,
    end_dt: datetime,
) -> dict[str, int]:
    total_result = await session.execute(
        select(func.count(BankMovement.id)).where(
            BankMovement.fecha >= start_dt,
            BankMovement.fecha < end_dt,
        )
    )
    matched_expense_result = await session.execute(
        select(func.count(BankMovement.id)).where(
            BankMovement.fecha >= start_dt,
            BankMovement.fecha < end_dt,
            BankMovement.matched_expense_id.isnot(None),
        )
    )
    unmatched_result = await session.execute(
        select(func.count(BankMovement.id)).where(
            BankMovement.fecha >= start_dt,
            BankMovement.fecha < end_dt,
            BankMovement.conciliacion_estado == "unmatched",
        )
    )
    return {
        "total": int(total_result.scalar() or 0),
        "matched_expense": int(matched_expense_result.scalar() or 0),
        "unmatched": int(unmatched_result.scalar() or 0),
    }


def _safe_redirect_base(return_to: Optional[str], fallback: str = "/admin/contabilidad/conciliacion") -> str:
    redirect_base = (return_to or fallback).strip()
    if not redirect_base.startswith("/"):
        return fallback
    return redirect_base


async def _resolve_latest_bank_source(session: AsyncSession) -> tuple[AccountingImportRun, Path]:
    latest_run_result = await session.execute(
        select(AccountingImportRun)
        .where(
            AccountingImportRun.source_type == "banco",
            AccountingImportRun.mode == "apply",
            AccountingImportRun.status == "completed",
        )
        .order_by(AccountingImportRun.started_at.desc())
        .limit(1)
    )
    latest_run = latest_run_result.scalar_one_or_none()
    if not latest_run:
        raise RuntimeError("No existe una importación bancaria previa para recalcular.")

    cache_path = _bank_upload_cache_path(latest_run.filename)
    if cache_path.exists():
        return latest_run, cache_path

    repo_root = _repo_root()
    repo_candidate = repo_root / Path(latest_run.filename).name
    if repo_candidate.exists():
        return latest_run, repo_candidate

    raw_candidate = repo_root / latest_run.filename
    if raw_candidate.exists():
        return latest_run, raw_candidate

    raise RuntimeError(
        f"No se encontró el CSV fuente para recalcular banco: {latest_run.filename}"
    )


@router.get("/api/contabilidad/historica/snapshot", response_class=JSONResponse)
async def api_contabilidad_historica_snapshot(
    year: int = Query(..., ge=2023, le=2100),
    company_code: str = Query("01"),
    session: AsyncSession = Depends(get_db_session),
    current_empleado: Empleado = require_admin_finanzas(),
) -> JSONResponse:
    """Canonical persisted historical accounting snapshot for BI/platform consumers."""
    snapshot = await load_historical_accounting_snapshot(
        session,
        fiscal_year=year,
        company_code=company_code,
    )
    if snapshot is None:
        return JSONResponse(
            status_code=404,
            content={
                "ok": False,
                "error": "historical_snapshot_not_found",
                "fiscal_year": year,
                "company_code": company_code,
            },
        )

    payload = {
        **snapshot,
        "fiscal_year": year,
        "requested_by": {
            "empleado_id": str(current_empleado.id)
            if getattr(current_empleado, "id", None)
            else None,
            "rol": getattr(current_empleado, "rol", None),
        },
    }
    return JSONResponse(content=payload)


