@router.get("/api/contabilidad/historica/reporte", response_class=JSONResponse)
async def api_contabilidad_historica_reporte(
    report_type: str = Query(..., pattern="^(diario|mayor|balanza)$"),
    year: int = Query(..., ge=2023, le=2100),
    company_code: str = Query("01"),
    month: Optional[int] = Query(None, ge=1, le=12),
    tipo_poliza: str = Query("all"),
    cuenta_codigo: str = Query("all"),
    q: str = Query(""),
    limit: int = Query(120, ge=10, le=300),
    session: AsyncSession = Depends(get_db_session),
    current_empleado: Empleado = require_admin_finanzas(),
) -> JSONResponse:
    """Canonical persisted historical accounting report for BI/platform consumers."""
    report = await _load_historical_accounting_tables_report(
        session,
        report_type=report_type,
        year=year,
        company_code=company_code,
        month=month,
        q=q,
        cuenta_codigo=cuenta_codigo,
        tipo_poliza=tipo_poliza,
        row_limit=limit,
    )
    if report is None:
        return JSONResponse(
            status_code=404,
            content={
                "ok": False,
                "error": "historical_report_not_found",
                "report_type": report_type,
                "fiscal_year": year,
                "company_code": company_code,
                "fiscal_month": month,
            },
        )

    payload = {
        "ok": True,
        "report_type": report_type,
        "fiscal_year": year,
        "fiscal_month": month,
        "requested_by": {
            "empleado_id": str(current_empleado.id)
            if getattr(current_empleado, "id", None)
            else None,
            "rol": getattr(current_empleado, "rol", None),
        },
        **report,
    }
    return JSONResponse(content=payload)


@router.get("/admin/contabilidad/historica", response_class=HTMLResponse)
async def contabilidad_historica_view(
    request: Request,
    session: AsyncSession = Depends(get_db_session),
    current_empleado: Empleado = require_admin_finanzas(),
) -> str:
    now = datetime.utcnow()
    selected_year = int(request.query_params.get("year") or now.year)
    selected_month = request.query_params.get("month") or ""
    selected_report = (request.query_params.get("report_type") or "mayor").strip().lower()
    if selected_report not in {"diario", "mayor", "balanza"}:
        selected_report = "mayor"
    selected_tipo = (request.query_params.get("tipo_poliza") or "all").strip()
    selected_cuenta = (request.query_params.get("cuenta_codigo") or "all").strip()
    selected_q = (request.query_params.get("q") or "").strip()
    selected_limit = max(10, min(int(request.query_params.get("limit") or 120), 300))
    selected_company = (request.query_params.get("company_code") or "01").strip().zfill(2)
    company_options_data = await list_historical_accounting_companies(
        session,
        fiscal_year=selected_year,
    )
    coverage_rows = await list_historical_accounting_coverage(
        session,
        year_from=max(2023, selected_year - 1),
        year_to=max(2023, selected_year),
    )
    if not company_options_data:
        company_options_data = [{"company_code": "01", "company_label": "PSP1705058S4"}]
    if selected_company not in {item["company_code"] for item in company_options_data}:
        selected_company = company_options_data[0]["company_code"]
    company_options = "".join(
        f'<option value="{escape(item["company_code"])}" {"selected" if item["company_code"] == selected_company else ""}>{escape(item["company_code"])} · {escape(item["company_label"])} · pólizas {int(item.get("policy_periods") or 0)}/12</option>'
        for item in company_options_data
    )
    company_coverage_html = "".join(
        f"""
        <div class="stat">
            <div class="label">Empresa {escape(item["company_code"])}</div>
            <div class="value" style="font-size:16px;">{escape(item["company_label"])}</div>
            <div class="muted" style="margin-top:6px;">Balanza {int(item.get("trial_balance_periods") or 0)}/12 · Pólizas {int(item.get("policy_periods") or 0)}/12</div>
        </div>
        """
        for item in company_options_data
    )
    coverage_matrix_rows = "".join(
        f"""
        <tr>
            <td>{int(item.get("fiscal_year") or 0)}</td>
            <td><code>{escape(str(item.get("company_code") or ""))}</code></td>
            <td>{escape(str(item.get("company_label") or ""))}</td>
            <td>{escape(str(item.get("coverage_status") or "unknown"))}</td>
            <td>{int(item.get("trial_balance_periods") or 0)}/12</td>
            <td>{int(item.get("policy_periods") or 0)}/12</td>
            <td>{int(item.get("policy_headers") or 0):,}</td>
            <td>{int(item.get("policy_lines") or 0):,}</td>
        </tr>
        """
        for item in coverage_rows
    )

    report_options = "".join(
        f'<option value="{value}" {"selected" if value == selected_report else ""}>{label}</option>'
        for value, label in (
            ("diario", "Diario"),
            ("mayor", "Mayor"),
            ("balanza", "Balanza"),
        )
    )
    month_options = '<option value="">Todo el año</option>' + "".join(
        f'<option value="{month}" {"selected" if str(month) == selected_month else ""}>{month:02d}</option>'
        for month in range(1, 13)
    )
    selected_company_entry = next(
        (item for item in company_options_data if str(item.get("company_code") or "") == selected_company),
        company_options_data[0] if company_options_data else {"company_code": selected_company, "company_label": "Sin etiqueta"},
    )
    selected_company_label = str(selected_company_entry.get("company_label") or selected_company)
    selected_coverage_entry = next(
        (
            item
            for item in coverage_rows
            if int(item.get("fiscal_year") or 0) == int(selected_year)
            and str(item.get("company_code") or "") == selected_company
        ),
        None,
    )
    comparison_year_from = max(2023, selected_year - 2)
    selected_coverage_status = (
        str(selected_coverage_entry.get("coverage_status") or "unknown")
        if selected_coverage_entry
        else "pending_lookup"
    )
    filter_chips = [
        f'<span class="hist-filter-chip">Año · {selected_year}</span>',
        f'<span class="hist-filter-chip">Empresa · {escape(selected_company)} · {escape(selected_company_label)}</span>',
        f'<span class="hist-filter-chip">Reporte · {escape(selected_report)}</span>',
        (
            f'<span class="hist-filter-chip">Mes · {escape(selected_month.zfill(2))}</span>'
            if selected_month
            else '<span class="hist-filter-chip hist-filter-chip-muted">Mes · todo el año</span>'
        ),
        f'<span class="hist-filter-chip">Cobertura · {escape(selected_coverage_status)}</span>',
    ]
    quick_cards = "".join(
        [
            f"""
            <article class="hist-stat-card hist-stat-card-primary">
                <div class="hist-stat-label">Empresa activa</div>
                <div class="hist-stat-value">{escape(selected_company)}</div>
                <div class="hist-stat-note">{escape(selected_company_label)} · pólizas {int(selected_company_entry.get("policy_periods") or 0)}/12.</div>
            </article>
            """,
            f"""
            <article class="hist-stat-card hist-stat-card-info">
                <div class="hist-stat-label">Cobertura {selected_year}</div>
                <div class="hist-stat-value">{escape(selected_coverage_status)}</div>
                <div class="hist-stat-note">Balanza {int(selected_company_entry.get("trial_balance_periods") or 0)}/12 · período comparativo desde {comparison_year_from}.</div>
            </article>
            """,
            f"""
            <article class="hist-stat-card hist-stat-card-warning">
                <div class="hist-stat-label">Rango visible</div>
                <div class="hist-stat-value">{len(coverage_rows)}</div>
                <div class="hist-stat-note">Filas en matriz multiempresa / multiaño para el corte actual.</div>
            </article>
            """,
            f"""
            <article class="hist-stat-card hist-stat-card-dark">
                <div class="hist-stat-label">Límite de reporte</div>
                <div class="hist-stat-value">{selected_limit}</div>
                <div class="hist-stat-note">Consulta preparada para {escape(selected_report)} con filtros persistidos en plataforma.</div>
            </article>
            """,
        ]
    )
    spotlight_cards = "".join(
        [
            f"""
            <article class="hist-spotlight-card">
                <div class="hist-spotlight-label">Empresa</div>
                <div class="hist-spotlight-title">{escape(selected_company)} · {escape(selected_company_label)}</div>
                <div class="hist-spotlight-meta">La vista ya sale desde `historical_*`, no desde CSV ni fallbacks legacy.</div>
            </article>
            """,
            f"""
            <article class="hist-spotlight-card">
                <div class="hist-spotlight-label">Cobertura anual</div>
                <div class="hist-spotlight-title">{escape(selected_coverage_status)}</div>
                <div class="hist-spotlight-meta">Balanza {int(selected_company_entry.get("trial_balance_periods") or 0)}/12 · pólizas {int(selected_company_entry.get("policy_periods") or 0)}/12.</div>
            </article>
            """,
            f"""
            <article class="hist-spotlight-card">
                <div class="hist-spotlight-label">Comparativo</div>
                <div class="hist-spotlight-title">{comparison_year_from} → {selected_year}</div>
                <div class="hist-spotlight-meta">Serie histórica preparada para comparar años de la misma empresa COI.</div>
            </article>
            """,
            f"""
            <article class="hist-spotlight-card">
                <div class="hist-spotlight-label">Reporte activo</div>
                <div class="hist-spotlight-title">{escape(selected_report)}</div>
                <div class="hist-spotlight-meta">Mes {escape(selected_month.zfill(2)) if selected_month else 'todo el año'} · búsqueda {escape(selected_q or 'sin filtro')}.</div>
            </article>
            """,
        ]
    )

    html = f"""
    <!DOCTYPE html>
    <html>
    <head>
        <meta charset="utf-8">
        <meta name="viewport" content="width=device-width, initial-scale=1">
        <title>Contabilidad histórica</title>
        <style>
            :root {{
                --hist-line:#dbe2ea;
                --hist-ink:#0f172a;
                --hist-muted:#64748b;
            }}
            body {{
                font-family:"Segoe UI","Helvetica Neue",sans-serif;
                background:
                    radial-gradient(circle at top left, rgba(15,118,110,.10), transparent 24%),
                    radial-gradient(circle at top right, rgba(29,78,216,.08), transparent 22%),
                    linear-gradient(180deg,#eaf1f6 0%,#dfe9f1 100%);
                margin:0;
                padding:20px;
                color:var(--hist-ink);
            }}
            .container {{ max-width: 1520px; margin:0 auto; }}
            .card {{
                background:linear-gradient(180deg,#ffffff 0%,#f8fafc 100%);
                border:1px solid var(--hist-line);
                border-radius:20px;
                padding:18px;
                margin-bottom:16px;
                box-shadow:0 12px 30px rgba(15,23,42,.06);
            }}
            .toolbar {{ display:grid; grid-template-columns:repeat(auto-fit,minmax(180px,1fr)); gap:12px; }}
            input, select {{ width:100%; padding:8px 10px; border:1px solid #d1d5db; border-radius:8px; box-sizing:border-box; }}
            table {{ width:100%; border-collapse:collapse; }}
            th, td {{ padding:10px 12px; border-bottom:1px solid #e5e7eb; text-align:left; font-size:13px; vertical-align:top; }}
            th {{ background:#f3f4f6; }}
            .button {{ display:inline-block; padding:10px 14px; border-radius:12px; text-decoration:none; background:#111827; color:#fff; border:none; cursor:pointer; font-weight:700; }}
            .button.secondary {{ background:#e5e7eb; color:#111827; }}
            .muted {{ color:#6b7280; font-size:13px; }}
            .stats {{ display:grid; grid-template-columns:repeat(auto-fit,minmax(180px,1fr)); gap:12px; }}
            .stat {{ border:1px solid #e5e7eb; border-radius:14px; padding:14px; background:#f8fafc; }}
            .stat .label {{ color:#64748b; font-size:12px; margin-bottom:6px; text-transform:uppercase; letter-spacing:.06em; }}
            .stat .value {{ color:#0f172a; font-size:22px; font-weight:800; }}
            .notice {{ padding:12px 14px; border-radius:10px; margin-bottom:16px; }}
            .notice.error {{ background:#fee2e2; color:#991b1b; border:1px solid #fecaca; }}
            .notice.info {{ background:#eff6ff; color:#1d4ed8; border:1px solid #bfdbfe; }}
            code {{ background:#f1f5f9; padding:2px 6px; border-radius:6px; }}
            .hist-toolbar {{ display:grid; gap:14px; }}
            .hist-filter-strip {{ display:flex; flex-wrap:wrap; gap:8px; }}
            .hist-filter-chip {{
                display:inline-flex;
                align-items:center;
                padding:7px 11px;
                border-radius:999px;
                background:rgba(15,118,110,.10);
                border:1px solid rgba(15,118,110,.16);
                color:#0f766e;
                font-size:11px;
                font-weight:700;
                letter-spacing:.04em;
            }}
            .hist-filter-chip-muted {{ background:#f8fafc; border-color:#dbe2ea; color:#64748b; }}
            .hist-control-card {{
                border:1px solid rgba(15,23,42,.08);
                border-radius:20px;
                background:linear-gradient(135deg,rgba(255,255,255,.96),rgba(241,245,249,.96));
                padding:18px;
                box-shadow:0 10px 24px rgba(15,23,42,.05);
            }}
            .hist-control-card h2 {{ margin:0; font-size:1.08rem; letter-spacing:-.02em; }}
            .hist-control-card p {{ margin:6px 0 0; color:#475569; font-size:13px; line-height:1.55; }}
            .hist-stat-grid {{ display:grid; grid-template-columns:repeat(auto-fit,minmax(230px,1fr)); gap:14px; }}
            .hist-stat-card {{
                border-radius:20px;
                padding:18px;
                color:#fff;
                box-shadow:0 14px 28px rgba(15,23,42,.10);
            }}
            .hist-stat-card-primary {{ background:linear-gradient(135deg,#0f766e,#14b8a6); }}
            .hist-stat-card-info {{ background:linear-gradient(135deg,#1d4ed8,#38bdf8); }}
            .hist-stat-card-warning {{ background:linear-gradient(135deg,#b45309,#f59e0b); }}
            .hist-stat-card-dark {{ background:linear-gradient(135deg,#0f172a,#334155); }}
            .hist-stat-label {{ font-size:11px; text-transform:uppercase; letter-spacing:.14em; opacity:.82; }}
            .hist-stat-value {{ margin-top:10px; font-size:2rem; font-weight:800; letter-spacing:-.04em; }}
            .hist-stat-note {{ margin-top:8px; font-size:12px; line-height:1.5; opacity:.82; }}
            .hist-spotlight-grid {{ display:grid; grid-template-columns:repeat(auto-fit,minmax(220px,1fr)); gap:14px; }}
            .hist-spotlight-card {{
                border:1px solid var(--hist-line);
                border-radius:18px;
                background:#fff;
                padding:16px;
                box-shadow:0 10px 24px rgba(15,23,42,.04);
            }}
            .hist-spotlight-label {{ font-size:11px; text-transform:uppercase; letter-spacing:.12em; color:var(--hist-muted); }}
            .hist-spotlight-title {{ margin-top:10px; font-size:1.15rem; font-weight:800; letter-spacing:-.03em; color:var(--hist-ink); }}
            .hist-spotlight-meta {{ margin-top:8px; font-size:12px; line-height:1.55; color:#475569; }}
        </style>
    </head>
    <body>
        <div class="container">
            {render_top_navigation(current_empleado, "contabilidad")}
            {_contabilidad_subnav("historica")}
            <div class="card">
                <h1 style="margin:0 0 8px 0;">Contabilidad histórica canónica</h1>
                <p class="muted" style="margin:0 0 16px 0;">Consulta snapshots y reportes históricos persistidos desde <code>historical_*</code>, sin depender de CSV ni de fallbacks legacy.</p>
                <div class="hist-toolbar">
                    <div class="hist-filter-strip">
                        {"".join(filter_chips)}
                    </div>
                    <div class="hist-control-card">
                        <h2>Pulso ejecutivo</h2>
                        <p>Lectura operativa de cobertura histórica por empresa COI, con snapshot, reconciliación, comparativo y detalle persistidos en plataforma.</p>
                        <form id="historica-form" class="toolbar" style="margin-top:14px;">
                            <div><label>Año</label><input type="number" name="year" value="{selected_year}" min="2023" max="2100"></div>
                            <div><label>Empresa COI</label><select name="company_code">{company_options}</select></div>
                            <div><label>Reporte</label><select name="report_type">{report_options}</select></div>
                            <div><label>Mes</label><select name="month">{month_options}</select></div>
                            <div><label>Tipo póliza</label><input type="text" name="tipo_poliza" value="{_html_value(selected_tipo)}" placeholder="all, E, I, D..."></div>
                            <div><label>Cuenta</label><input type="text" name="cuenta_codigo" value="{_html_value(selected_cuenta)}" placeholder="all o código"></div>
                            <div><label>Búsqueda</label><input type="text" name="q" value="{_html_value(selected_q)}" placeholder="Concepto, cuenta, póliza"></div>
                            <div><label>Límite</label><input type="number" name="limit" min="10" max="300" value="{selected_limit}"></div>
                            <div style="display:flex;align-items:end;gap:8px;flex-wrap:wrap;">
                                <button type="submit" class="button">Consultar</button>
                                <a href="/admin/contabilidad/historica" class="button secondary">Limpiar</a>
                            </div>
                        </form>
                    </div>
                </div>
                <div class="stats" style="margin-top:12px;">
                    {company_coverage_html}
                </div>
            </div>
            <div class="card">
                <h2 style="margin:0 0 12px 0;">Resumen</h2>
                <p class="muted" style="margin:0 0 12px 0;">Empresa activa, cobertura y rango comparativo antes de bajar al snapshot y al reporte.</p>
                <div class="hist-stat-grid">
                    {quick_cards}
                </div>
            </div>
            <div class="card">
                <h2 style="margin:0 0 12px 0;">Spotlight</h2>
                <p class="muted" style="margin:0 0 12px 0;">Los cuatro focos que más rápido explican el corte histórico elegido.</p>
                <div class="hist-spotlight-grid">
                    {spotlight_cards}
                </div>
            </div>
            <div class="card">
                <h2 style="margin:0 0 12px 0;">Cobertura multiempresa / multiaño</h2>
                <p class="muted" style="margin:0 0 12px 0;">Matriz rápida de cobertura histórica ya absorbida en tablas canónicas para ubicar qué empresa y año tiene balanza o pólizas completas.</p>
                <table>
                    <thead>
                        <tr>
                            <th>Año</th>
                            <th>Empresa</th>
                            <th>Etiqueta</th>
                            <th>Cobertura</th>
                            <th>Balanza</th>
                            <th>Pólizas</th>
                            <th>Headers</th>
                            <th>Movimientos</th>
                        </tr>
                    </thead>
                    <tbody>
                        {coverage_matrix_rows or '<tr><td colspan="8" class="muted">Sin cobertura histórica visible todavía.</td></tr>'}
                    </tbody>
                </table>
            </div>
            <div id="historica-error"></div>
            <div class="card">
                <h2 style="margin:0 0 12px 0;">Snapshot persistido</h2>
                <div id="historica-snapshot" class="muted">Cargando snapshot...</div>
            </div>
            <div class="card">
                <h2 style="margin:0 0 12px 0;">Reconciliación por período</h2>
                <div id="historica-reconciliation" class="muted">Cargando reconciliación...</div>
            </div>
            <div class="card">
                <h2 style="margin:0 0 12px 0;">Comparativo multi-período</h2>
                <div id="historica-comparison" class="muted">Cargando comparativo...</div>
            </div>
            <div class="card">
                <h2 style="margin:0 0 12px 0;">Detalle del reporte</h2>
                <div id="historica-report" class="muted">Cargando reporte...</div>
            </div>
        </div>
        <script>
            const form = document.getElementById('historica-form');
            const errorBox = document.getElementById('historica-error');
            const snapshotBox = document.getElementById('historica-snapshot');
            const reconciliationBox = document.getElementById('historica-reconciliation');
            const comparisonBox = document.getElementById('historica-comparison');
            const reportBox = document.getElementById('historica-report');
            function esc(value) {{
                return String(value ?? '').replace(/&/g, '&amp;').replace(/</g, '&lt;').replace(/>/g, '&gt;').replace(/"/g, '&quot;');
            }}
            function money(value) {{
                const n = Number(value || 0);
                return new Intl.NumberFormat('es-MX', {{ style: 'currency', currency: 'MXN' }}).format(n);
            }}
            function paramsFromForm() {{
                const fd = new FormData(form);
                const params = new URLSearchParams();
                for (const [key, value] of fd.entries()) {{
                    const normalized = String(value || '').trim();
                    if (!normalized) continue;
                    if ((key === 'tipo_poliza' || key === 'cuenta_codigo') && normalized.toLowerCase() === 'all') {{
                        params.set(key, 'all');
                        continue;
                    }}
                    params.set(key, normalized);
                }}
                if (!params.get('tipo_poliza')) params.set('tipo_poliza', 'all');
                if (!params.get('cuenta_codigo')) params.set('cuenta_codigo', 'all');
                if (!params.get('limit')) params.set('limit', '120');
                return params;
            }}
            function renderSnapshot(payload) {{
                const summary = payload.summary || {{}};
                snapshotBox.innerHTML = `
                    <div class="stats">
                        <div class="stat"><div class="label">Año</div><div class="value">${{esc(payload.fiscal_year)}}</div></div>
                        <div class="stat"><div class="label">Empresa</div><div class="value">${{esc(summary.company_code || payload.company_code || '-')}}</div></div>
                        <div class="stat"><div class="label">Corrida</div><div class="value">${{esc(payload.import_run_id || '-')}}</div></div>
                        <div class="stat"><div class="label">Balanza</div><div class="value">${{esc(summary.trial_balance_rows || 0)}}</div></div>
                        <div class="stat"><div class="label">Pólizas</div><div class="value">${{esc(summary.policy_headers || 0)}}</div></div>
                        <div class="stat"><div class="label">Movimientos</div><div class="value">${{esc(summary.policy_lines || 0)}}</div></div>
                        <div class="stat"><div class="label">Meses</div><div class="value">${{esc((summary.reconciliation || {{}}).months_detected || 0)}}</div></div>
                    </div>
                    <p class="muted" style="margin-top:12px;">Empresa: <code>${{esc(summary.company_label || summary.company_code || '-')}}</code> · Fuente: <code>${{esc(summary.source || '-')}}</code></p>
                `;
            }}
            function renderReconciliation(payload) {{
                const periods = ((payload.summary || {{}}).reconciliation || {{}}).periods || {{}};
                const rows = Object.entries(periods).map(([period, item]) => `
                    <tr>
                        <td>${{esc(period)}}</td>
                        <td>${{esc(item.trial_balance_rows || 0)}}</td>
                        <td>${{esc(item.policy_headers || 0)}}</td>
                        <td>${{esc(item.policy_lines || 0)}}</td>
                        <td>${{money(item.trial_balance_debits)}}</td>
                        <td>${{money(item.trial_balance_credits)}}</td>
                        <td>${{money(item.policy_line_debits)}}</td>
                        <td>${{money(item.policy_line_credits)}}</td>
                        <td>${{esc(item.unbalanced_policy_headers || 0)}}</td>
                    </tr>
                `).join('');
                reconciliationBox.innerHTML = rows ? `
                    <table>
                        <thead><tr><th>Periodo</th><th>Filas balanza</th><th>Pólizas</th><th>Movimientos</th><th>Cargos balanza</th><th>Abonos balanza</th><th>Debe líneas</th><th>Haber líneas</th><th>Desbalanceadas</th></tr></thead>
                        <tbody>${{rows}}</tbody>
                    </table>
                ` : '<div class="muted">Sin reconciliación persistida.</div>';
            }}
            function renderComparison(payload) {{
                const rows = payload.rows || [];
                if (!rows.length) {{
                    comparisonBox.innerHTML = '<div class="muted">Sin serie histórica visible para esta empresa en el rango solicitado.</div>';
                    return;
                }}
                const body = rows.map(item => `
                    <tr>
                        <td>${{esc(item.fiscal_year)}}</td>
                        <td>${{esc(item.coverage_status || '-')}}</td>
                        <td>${{esc(item.trial_balance_periods || 0)}}/12</td>
                        <td>${{esc(item.policy_periods || 0)}}/12</td>
                        <td>${{esc(item.policy_headers || 0)}}</td>
                        <td>${{esc(item.policy_headers_delta ?? '-')}}</td>
                        <td>${{esc(item.policy_lines || 0)}}</td>
                        <td>${{esc(item.policy_lines_delta ?? '-')}}</td>
                    </tr>
                `).join('');
                comparisonBox.innerHTML = `
                    <div class="notice info"><strong>${{esc(payload.company_label || payload.company_code || 'Empresa')}}</strong><br><span class="muted">Serie comparativa por año para la misma empresa COI.</span></div>
                    <table>
                        <thead><tr><th>Año</th><th>Cobertura</th><th>Balanza</th><th>Pólizas</th><th>Headers</th><th>Delta headers</th><th>Movimientos</th><th>Delta movimientos</th></tr></thead>
                        <tbody>${{body}}</tbody>
                    </table>
                `;
            }}
            function renderReport(payload) {{
                const rows = payload.rows || payload.movements || payload.summary_by_account || [];
                const headers = rows.length ? Object.keys(rows[0]) : [];
                if (!rows.length) {{
                    reportBox.innerHTML = '<div class="muted">Sin filas para el filtro seleccionado.</div>';
                    return;
                }}
                const thead = headers.map(h => `<th>${{esc(h)}}</th>`).join('');
                const body = rows.slice(0, 120).map(row => `<tr>${{headers.map(h => `<td>${{esc(row[h])}}</td>`).join('')}}</tr>`).join('');
                reportBox.innerHTML = `
                    <div class="notice info"><strong>${{esc(payload.title || 'Reporte histórico')}}</strong><br><span class="muted">Fuente: ${{esc(payload.source || '-')}}</span></div>
                    <table>
                        <thead><tr>${{thead}}</tr></thead>
                        <tbody>${{body}}</tbody>
                    </table>
                `;
            }}
            async function loadHistoricalView(pushState = true) {{
                const params = paramsFromForm();
                const query = params.toString();
                if (pushState) {{
                    window.history.replaceState(null, '', `/admin/contabilidad/historica?${{query}}`);
                }}
                errorBox.innerHTML = '';
                snapshotBox.innerHTML = '<div class="muted">Cargando snapshot...</div>';
                reconciliationBox.innerHTML = '<div class="muted">Cargando reconciliación...</div>';
                comparisonBox.innerHTML = '<div class="muted">Cargando comparativo...</div>';
                reportBox.innerHTML = '<div class="muted">Cargando reporte...</div>';
                const year = params.get('year');
                const companyCode = params.get('company_code') || '01';
                const snapshotResp = await fetch(`/api/contabilidad/historica/snapshot?year=${{encodeURIComponent(year)}}&company_code=${{encodeURIComponent(companyCode)}}`, {{ headers: {{ Accept: 'application/json' }} }});
                const snapshotPayload = await snapshotResp.json();
                if (!snapshotResp.ok) {{
                    errorBox.innerHTML = `<div class="notice error"><strong>No hay snapshot persistido para ${{esc(year)}} / empresa ${{esc(companyCode)}}.</strong></div>`;
                    snapshotBox.innerHTML = '<div class="muted">Snapshot no disponible.</div>';
                    reconciliationBox.innerHTML = '<div class="muted">Reconciliación no disponible.</div>';
                }} else {{
                    renderSnapshot(snapshotPayload);
                    renderReconciliation(snapshotPayload);
                }}
                const comparisonFrom = Math.max(2023, Number(year || 2023) - 2);
                const comparisonResp = await fetch(`/api/contabilidad/historica/comparativo?company_code=${{encodeURIComponent(companyCode)}}&year_from=${{encodeURIComponent(comparisonFrom)}}&year_to=${{encodeURIComponent(year)}}`, {{ headers: {{ Accept: 'application/json' }} }});
                const comparisonPayload = await comparisonResp.json();
                if (!comparisonResp.ok) {{
                    comparisonBox.innerHTML = '<div class="muted">Comparativo histórico no disponible.</div>';
                }} else {{
                    renderComparison(comparisonPayload);
                }}
                const reportResp = await fetch(`/api/contabilidad/historica/reporte?${{query}}`, {{ headers: {{ Accept: 'application/json' }} }});
                const reportPayload = await reportResp.json();
                if (!reportResp.ok) {{
                    reportBox.innerHTML = '<div class="muted">Reporte histórico no disponible para ese filtro.</div>';
                    if (snapshotResp.ok) {{
                        errorBox.innerHTML = `<div class="notice error"><strong>El snapshot existe, pero ese reporte/filtro no devolvió filas persistidas.</strong></div>`;
                    }}
                    return;
                }}
                renderReport(reportPayload);
            }}
            form.addEventListener('submit', (event) => {{
                event.preventDefault();
                loadHistoricalView(true);
            }});
            loadHistoricalView(false);
        </script>
    </body>
    </html>
    """
    return html


def _billing_system_status() -> tuple[str, str]:
    """Return billing system connection label and CSS class."""
    configured = bool(
        os.getenv("TOCINO_BASE_URL", "").strip()
        and os.getenv("TOCINO_API_KEY", "").strip()
    )
    if configured:
        return "Sistema conectado", "connected"
    return "Sistema no conectado", "disconnected"


def _truthy_form(value: Optional[str]) -> bool:
    return str(value or "").strip().lower() in {"1", "true", "on", "yes", "si"}


def _form_list(form_data: object, key: str) -> List[str]:
    if hasattr(form_data, "getlist"):
        return list(form_data.getlist(key))
    value = form_data.get(key, []) if hasattr(form_data, "get") else []
    if isinstance(value, list):
        return [str(item) for item in value]
    return [str(value)] if value else []


def _sum_active_expense_amounts(expenses: List[ExpenseReport]) -> float:
    """Sum expense amounts using the same rounding already used for document totals."""
    total_decimal = sum(
        (Decimal(str(exp.gasto_cantidad or 0)) for exp in expenses),
        Decimal("0"),
    )
    return float(total_decimal.quantize(Decimal("0.01"), rounding=ROUND_HALF_UP))


def _sum_requested_document_amounts(documentos: List[Documento]) -> float:
    """Sum requested amounts using the same 2-decimal rounding as other document totals."""
    total_decimal = sum(
        (Decimal(str(doc.monto_solicitado or 0)) for doc in documentos),
        Decimal("0"),
    )
    return float(total_decimal.quantize(Decimal("0.01"), rounding=ROUND_HALF_UP))


def _informe_amex_cell(expense: ExpenseReport, *, can_manage: bool) -> str:
    amex_effective = is_company_amex_expense(expense)
    is_cancelled = expense.estado_gasto == "cancelado"
    if can_manage and not is_cancelled:
        return (
            f'<input type="checkbox" name="expense_ids" value="{expense.id}" '
            f'aria-label="Seleccionar gasto '
            f'{escape(expense.numero_referencia or str(expense.id))}">'
            f'<div class="status-chip {"info" if amex_effective else ""}" '
            f'style="margin-top:6px;">'
            f'{"AMEX empresa" if amex_effective else "Empleado"}</div>'
        )
    if amex_effective:
        return '<span class="status-chip info">AMEX empresa</span>'
    return '<span class="status-chip">Empleado</span>'


async def _derive_informe_monto_total(
    session: AsyncSession,
    documento: Documento,
) -> float:
    """
    Derive the INFORME total from active expenses only.

    This intentionally mirrors the export scope so the detail-page total box matches
    "Descargar informe de gastos" without changing export behavior or table layout.
    """
    expense_conditions = [
        ExpenseReport.documento_id == documento.id,
        ExpenseReport.informe_documento_id == documento.id,
    ]
    if documento.cuenta_gastos_id:
        expense_conditions.append(ExpenseReport.cuenta_gastos_id == documento.cuenta_gastos_id)

    expenses_result = await session.execute(
        select(ExpenseReport).where(
            and_(
                or_(*expense_conditions),
                ExpenseReport.estado_gasto != 'cancelado'
            )
        )
    )
    active_expenses = expenses_result.scalars().all()
    derived_total = _sum_active_expense_amounts(active_expenses)
    stored_total = documento.monto_total

    if stored_total is None or Decimal(str(stored_total)) != Decimal(str(derived_total)):
        documento.monto_total = derived_total
        await session.commit()

    return derived_total


async def _load_informe_solicitudes(session: AsyncSession, documento: Documento) -> List[Documento]:
    """Load transfer requests scoped to the same cuenta for the informe detail page."""
    if not documento.cuenta_gastos_id:
        return []

    solicitudes_result = await session.execute(
        select(Documento).where(
            and_(
                Documento.cuenta_gastos_id == documento.cuenta_gastos_id,
                Documento.tipo == 'SOLICITUD'
            )
        )
    )
    return solicitudes_result.scalars().all()


