def _accounting_month_bounds(year: int, month: int) -> tuple[datetime, datetime]:
    start_dt = datetime(year, month, 1)
    end_dt = datetime(year + 1, 1, 1) if month == 12 else datetime(year, month + 1, 1)
    return start_dt, end_dt


async def _get_accounting_close_period(
    session: AsyncSession,
    *,
    fiscal_year: int,
    fiscal_month: int,
) -> Optional[AccountingClosePeriod]:
    return await session.scalar(
        select(AccountingClosePeriod).where(
            AccountingClosePeriod.fiscal_year == fiscal_year,
            AccountingClosePeriod.fiscal_month == fiscal_month,
        )
    )


async def _is_accounting_period_closed(
    session: AsyncSession,
    *,
    fiscal_year: int,
    fiscal_month: int,
) -> bool:
    period = await _get_accounting_close_period(
        session,
        fiscal_year=fiscal_year,
        fiscal_month=fiscal_month,
    )
    return bool(period and (period.status or "").strip().lower() == "closed")


async def _ensure_accounting_period_open(
    session: AsyncSession,
    *,
    fiscal_year: int,
    fiscal_month: int,
    redirect_to: str,
):
    if await _is_accounting_period_closed(session, fiscal_year=fiscal_year, fiscal_month=fiscal_month):
        return RedirectResponse(
            url=_safe_redirect_base(redirect_to, "/admin/contabilidad/cierres")
            + "?error_msg="
            + quote(f"El período {fiscal_year}-{fiscal_month:02d} está cerrado y no acepta cambios contables."),
            status_code=303,
    )
    return None


def _accounting_role(current_empleado: Empleado) -> str:
    return (getattr(current_empleado, "rol", "") or "").strip().lower()


def _can_manage_accounting_structure(current_empleado: Empleado) -> bool:
    role = _accounting_role(current_empleado)
    if role in {"admin", "superadmin", "super_admin"}:
        return True
    return any(
        has_permission(current_empleado, permission)
        for permission in (
            "admin.finanzas.structural",
            "admin.finanzas.close",
            "admin.finanzas.delete",
            "admin.finanzas.reclass",
            "contabilidad.manage_structure",
            "contabilidad.close_periods",
            "contabilidad.delete_polizas",
            "contabilidad.reclassify",
        )
    )


def _can_edit_accounting_headers(current_empleado: Empleado) -> bool:
    role = _accounting_role(current_empleado)
    if role in {"admin", "superadmin", "super_admin"}:
        return True
    return any(
        has_permission(current_empleado, permission)
        for permission in (
            "admin.finanzas.edit_headers",
            "admin.finanzas.structural",
            "contabilidad.edit_headers",
            "contabilidad.manage_structure",
        )
    )


def _ensure_accounting_role_capability(
    current_empleado: Empleado,
    *,
    allowed: bool,
    redirect_to: str,
    message: str,
):
    if allowed:
        return None
    return RedirectResponse(
        url=_safe_redirect_base(redirect_to, "/admin/contabilidad/estado") + "?error_msg=" + quote(message),
        status_code=303,
    )


