async def _ensure_accounting_close_period_record(
    session: AsyncSession,
    *,
    fiscal_year: int,
    fiscal_month: int,
) -> AccountingClosePeriod:
    period = await _get_accounting_close_period(session, fiscal_year=fiscal_year, fiscal_month=fiscal_month)
    if period is not None:
        return period
    period = AccountingClosePeriod(
        id=uuid4(),
        fiscal_year=fiscal_year,
        fiscal_month=fiscal_month,
        status="open",
    )
    session.add(period)
    await session.flush()
    return period


async def _ensure_accounting_close_checklist_seed(
    session: AsyncSession,
    *,
    fiscal_year: int,
    fiscal_month: int,
) -> tuple[AccountingClosePeriod, list[AccountingCloseChecklistItem]]:
    period = await _ensure_accounting_close_period_record(
        session,
        fiscal_year=fiscal_year,
        fiscal_month=fiscal_month,
    )
    existing_items = (
        await session.execute(
            select(AccountingCloseChecklistItem)
            .options(selectinload(AccountingCloseChecklistItem.completed_by))
            .where(AccountingCloseChecklistItem.close_period_id == period.id)
            .order_by(AccountingCloseChecklistItem.label.asc())
        )
    ).scalars().all()
    existing_codes = {item.task_code for item in existing_items}
    created = False
    for template in _default_accounting_close_checklist_items():
        if template["task_code"] in existing_codes:
            continue
        session.add(
            AccountingCloseChecklistItem(
                id=uuid4(),
                close_period_id=period.id,
                task_code=template["task_code"],
                label=template["label"],
                owner_role=template["owner_role"],
                status="pending",
            )
        )
        created = True
    if created:
        await session.flush()
        existing_items = (
            await session.execute(
                select(AccountingCloseChecklistItem)
                .options(selectinload(AccountingCloseChecklistItem.completed_by))
                .where(AccountingCloseChecklistItem.close_period_id == period.id)
                .order_by(AccountingCloseChecklistItem.label.asc())
            )
        ).scalars().all()
    return period, existing_items


def _render_manual_poliza_line_rows(
    cuentas: list[CuentaContable],
    *,
    rows: list[dict[str, Any]],
) -> str:
    cuenta_options = "".join(
        f'<option value="{cuenta.id}" data-code="{escape(cuenta.codigo)}">{escape(cuenta.codigo)} · {escape(cuenta.nombre)}</option>'
        for cuenta in cuentas
    )
    rendered: list[str] = []
    for idx, row in enumerate(rows, start=1):
        cuenta_contable_id = str(row.get("cuenta_contable_id") or "")
        option_markup = "".join(
            f'<option value="{cuenta.id}" data-code="{escape(cuenta.codigo)}" {"selected" if cuenta_contable_id == str(cuenta.id) else ""}>{escape(cuenta.codigo)} · {escape(cuenta.nombre)}</option>'
            for cuenta in cuentas
        )
        rendered.append(
            f"""
            <tr class="manual-line-row">
                <td>{idx}</td>
                <td><input type="text" name="cuenta_codigo" value="{_html_value(row.get('cuenta_codigo'))}" placeholder="Ej. 5100-001"></td>
                <td>
                    <select name="cuenta_contable_id" data-autofill-code="1">
                        <option value="">Cuenta del sistema (opcional)</option>
                        {option_markup or cuenta_options}
                    </select>
                </td>
                <td><input type="text" name="concepto_linea" value="{_html_value(row.get('concepto'))}" placeholder="Concepto de la partida"></td>
                <td><input type="text" name="movimiento_no" value="{_html_value(row.get('movimiento_no'))}" placeholder="Mov."></td>
                <td><input type="number" step="0.01" min="0" name="debe" value="{_html_value(row.get('debe'))}"></td>
                <td><input type="number" step="0.01" min="0" name="haber" value="{_html_value(row.get('haber'))}"></td>
                <td><button type="button" class="button secondary" data-remove-line="1">Quitar</button></td>
            </tr>
            """
        )
    return "".join(rendered)


