def _next_manual_poliza_number(existing_numbers: list[str], tipo_poliza: str) -> str:
    cleaned = [str(number or "").strip() for number in existing_numbers if str(number or "").strip()]
    if not cleaned:
        return f"{tipo_poliza}-0001"

    def _score(number: str) -> tuple[int, int]:
        match = re.search(r"(\d+)(?!.*\d)", number)
        if not match:
            return (0, 0)
        return (int(match.group(1)), len(match.group(1)))

    best = max(cleaned, key=_score)
    match = re.search(r"(\d+)(?!.*\d)", best)
    if not match:
        return f"{tipo_poliza}-0001"
    width = len(match.group(1))
    next_value = int(match.group(1)) + 1
    return f"{best[:match.start(1)]}{str(next_value).zfill(width)}{best[match.end(1):]}"


def _parse_money_decimal(value: Any, field_label: str) -> Decimal:
    try:
        amount = Decimal(str(value or "0").replace(",", "").strip() or "0")
    except Exception as exc:
        raise ValueError(f"{field_label} no es un importe válido") from exc
    return amount.quantize(Decimal("0.01"), rounding=ROUND_HALF_UP)


def _build_ingreso_cobrado_line_payload(
    *,
    total_cobrado: Decimal,
    iva_trasladado: Decimal,
    cuenta_banco: CuentaContable,
    cuenta_ingreso: CuentaContable,
    cuenta_iva: Optional[CuentaContable],
    concepto: str,
) -> tuple[list[dict[str, Any]], Decimal]:
    if total_cobrado <= 0:
        raise ValueError("El monto cobrado debe ser mayor a cero")
    if iva_trasladado < 0:
        raise ValueError("El IVA trasladado no puede ser negativo")
    if iva_trasladado >= total_cobrado:
        raise ValueError("El IVA trasladado debe ser menor al monto cobrado")
    if iva_trasladado > 0 and cuenta_iva is None:
        raise ValueError("Selecciona la cuenta de IVA trasladado")

    ingreso_base = (total_cobrado - iva_trasladado).quantize(
        Decimal("0.01"),
        rounding=ROUND_HALF_UP,
    )
    lines = [
        {
            "cuenta_codigo": cuenta_banco.codigo,
            "cuenta_contable_id": cuenta_banco.id,
            "concepto": concepto,
            "movimiento_no": "1",
            "debe": float(total_cobrado),
            "haber": 0.0,
        },
        {
            "cuenta_codigo": cuenta_ingreso.codigo,
            "cuenta_contable_id": cuenta_ingreso.id,
            "concepto": concepto,
            "movimiento_no": "1",
            "debe": 0.0,
            "haber": float(ingreso_base),
        },
    ]
    if iva_trasladado > 0 and cuenta_iva is not None:
        lines.append(
            {
                "cuenta_codigo": cuenta_iva.codigo,
                "cuenta_contable_id": cuenta_iva.id,
                "concepto": f"{concepto} / IVA trasladado",
                "movimiento_no": "1",
                "debe": 0.0,
                "haber": float(iva_trasladado),
            }
        )
    return lines, ingreso_base


