@router.get("/admin/nomina/cuentas", response_class=HTMLResponse)
async def nomina_cuentas_view(
    request: Request,
    session: AsyncSession = Depends(get_db_session),
    current_empleado: Empleado = require_admin_finanzas(),
) -> str:
    success_msg = request.query_params.get("success_msg", "")
    error_msg = request.query_params.get("error_msg", "")

    employers = (
        await session.execute(select(PayrollEmployer).where(PayrollEmployer.active == True).order_by(PayrollEmployer.legal_name.asc()))
    ).scalars().all()
    cuentas = (
        await session.execute(select(CuentaContable).where(CuentaContable.activo == True).order_by(CuentaContable.codigo.asc()))
    ).scalars().all()
    mappings = (
        await session.execute(
            select(PayrollAccountMapping)
            .options(
                selectinload(PayrollAccountMapping.payroll_employer),
                selectinload(PayrollAccountMapping.cuenta_contable),
                selectinload(PayrollAccountMapping.created_by),
            )
            .order_by(PayrollAccountMapping.payroll_employer_id.asc().nullsfirst(), PayrollAccountMapping.purpose_key.asc())
        )
    ).scalars().all()
    active_mappings = [mapping for mapping in mappings if mapping.active]

    employer_options = '<option value="">Global</option>' + "".join(
        f'<option value="{employer.id}">{escape(employer.legal_name)} · {escape(employer.rfc or "-")}</option>'
        for employer in employers
    )
    purpose_options = "".join(
        f'<option value="{key}">{escape(label)}</option>' for key, label in _PAYROLL_ACCOUNT_PURPOSES
    )
    cuenta_options = "".join(
        f'<option value="{cuenta.id}">{escape(cuenta.codigo)} · {escape(cuenta.nombre)}</option>'
        for cuenta in cuentas
    )
    rows_html = "".join(
        f"""
        <tr>
            <td>{escape(mapping.payroll_employer.legal_name if mapping.payroll_employer else 'Global')}</td>
            <td>{escape(dict(_PAYROLL_ACCOUNT_PURPOSES).get(mapping.purpose_key, mapping.purpose_key))}</td>
            <td>{escape(mapping.cuenta_contable.codigo if mapping.cuenta_contable else '-')}</td>
            <td>{escape(mapping.cuenta_contable.nombre if mapping.cuenta_contable else '-')}</td>
            <td>{'Sí' if mapping.active else 'No'}</td>
            <td>{escape(mapping.notes or '-')}</td>
        </tr>
        """
        for mapping in mappings
    )
    purpose_keys = [key for key, _ in _PAYROLL_ACCOUNT_PURPOSES]
    coverage_rows: list[str] = []
    coverage_targets: list[tuple[Optional[UUIDType], str]] = [(None, "Global")]
    coverage_targets.extend((employer.id, employer.legal_name) for employer in employers)
    for employer_id, employer_name in coverage_targets:
        effective_details: list[str] = []
        missing_labels: list[str] = []
        explicit_count = 0
        inherited_count = 0
        for purpose_key, purpose_label in _PAYROLL_ACCOUNT_PURPOSES:
            explicit_mapping = next(
                (
                    mapping
                    for mapping in active_mappings
                    if mapping.payroll_employer_id == employer_id and mapping.purpose_key == purpose_key
                ),
                None,
            )
            global_mapping = next(
                (
                    mapping
                    for mapping in active_mappings
                    if mapping.payroll_employer_id is None and mapping.purpose_key == purpose_key
                ),
                None,
            )
            if explicit_mapping:
                explicit_count += 1
                detail_code = explicit_mapping.cuenta_contable.codigo if explicit_mapping.cuenta_contable else "sin-cuenta"
                effective_details.append(f"{purpose_label}: {detail_code}")
            elif employer_id is not None and global_mapping:
                inherited_count += 1
                detail_code = global_mapping.cuenta_contable.codigo if global_mapping.cuenta_contable else "sin-cuenta"
                effective_details.append(f"{purpose_label}: global {detail_code}")
            elif employer_id is None and global_mapping:
                explicit_count += 1
                detail_code = global_mapping.cuenta_contable.codigo if global_mapping.cuenta_contable else "sin-cuenta"
                effective_details.append(f"{purpose_label}: {detail_code}")
            else:
                missing_labels.append(purpose_label)
        coverage_rows.append(
            f"""
            <tr>
                <td>{escape(employer_name)}</td>
                <td>{explicit_count + inherited_count}/{len(purpose_keys)}</td>
                <td>{explicit_count}</td>
                <td>{inherited_count}</td>
                <td>{escape(", ".join(missing_labels) if missing_labels else "Ninguno")}</td>
                <td>{escape(" | ".join(effective_details[:4]))}{' ...' if len(effective_details) > 4 else ''}</td>
            </tr>
            """
        )

    html = f"""
    <!DOCTYPE html>
    <html><head><meta charset="utf-8"><meta name="viewport" content="width=device-width, initial-scale=1"><title>Cuentas de Nómina</title>
    <style>
    body {{ font-family: Arial, sans-serif; background:#f6f8fb; margin:0; padding:20px; }}
    .container {{ max-width: 1400px; margin:0 auto; }} .card {{ background:#fff; border:1px solid #e5e7eb; border-radius:10px; padding:16px; margin-bottom:16px; }}
    .grid {{ display:grid; grid-template-columns:repeat(auto-fit,minmax(220px,1fr)); gap:12px; }}
    input, select {{ width:100%; padding:8px 10px; border:1px solid #d1d5db; border-radius:8px; box-sizing:border-box; }}
    table {{ width:100%; border-collapse:collapse; }} th, td {{ padding:10px 12px; border-bottom:1px solid #e5e7eb; text-align:left; font-size:13px; }} th {{ background:#f3f4f6; }}
    .button {{ display:inline-block; padding:10px 14px; border-radius:8px; text-decoration:none; background:#111827; color:#fff; border:none; cursor:pointer; }}
    .muted {{ color:#6b7280; font-size:13px; }}
    </style></head>
    <body><div class="container">{render_top_navigation(current_empleado, "nomina")}{_payroll_subnav("cuentas")}
    <div class="card">
        <h1 style="margin:0 0 8px 0;">Cuentas contables de nómina</h1>
        <p class="muted" style="margin:0 0 16px 0;">Configura el mapping contable por propósito. Si existe mapping por patrón, gana sobre el mapping global. La póliza automática de nómina ya usa esta tabla.</p>
        {f'<div style="background:#d1fae5;color:#065f46;border:1px solid #a7f3d0;border-radius:10px;padding:12px 14px;margin:0 0 16px 0;"><strong>✅ Éxito:</strong> {escape(success_msg)}</div>' if success_msg else ''}
        {f'<div style="background:#fee2e2;color:#991b1b;border:1px solid #fecaca;border-radius:10px;padding:12px 14px;margin:0 0 16px 0;"><strong>❌ Error:</strong> {escape(error_msg)}</div>' if error_msg else ''}
        <form method="POST" action="/admin/nomina/cuentas">
            <div class="grid">
                <div><label>Patrón</label><select name="payroll_employer_id">{employer_options}</select></div>
                <div><label>Propósito</label><select name="purpose_key" required>{purpose_options}</select></div>
                <div><label>Cuenta contable</label><select name="cuenta_contable_id" required>{cuenta_options}</select></div>
                <div><label>Notas</label><input type="text" name="notes"></div>
                <div><label><input type="checkbox" name="active" value="1" checked> Activo</label></div>
            </div>
            <div style="margin-top:12px;"><button class="button" type="submit">Guardar mapping</button></div>
        </form>
    </div>
    <div class="card">
        <h2 style="margin:0 0 12px 0;">Mappings vigentes</h2>
        <table><thead><tr><th>Patrón</th><th>Propósito</th><th>Código</th><th>Cuenta</th><th>Activa</th><th>Notas</th></tr></thead>
        <tbody>{rows_html if rows_html else '<tr><td colspan="6" class="muted">No hay mappings todavía.</td></tr>'}</tbody></table>
    </div>
    <div class="card">
        <h2 style="margin:0 0 12px 0;">Cobertura efectiva</h2>
        <p class="muted" style="margin:0 0 12px 0;">Esta tabla ya considera que un patrón puede heredar el mapping global cuando no tiene uno propio.</p>
        <table><thead><tr><th>Ámbito</th><th>Cobertura</th><th>Explícitos</th><th>Hereda global</th><th>Faltantes</th><th>Detalle</th></tr></thead>
        <tbody>{''.join(coverage_rows)}</tbody></table>
    </div>
    </div></body></html>
    """
    return html


@router.post("/admin/nomina/cuentas")
async def nomina_cuentas_create(
    payroll_employer_id: Optional[UUIDType] = Form(None),
    purpose_key: str = Form(...),
    cuenta_contable_id: UUIDType = Form(...),
    notes: Optional[str] = Form(None),
    active: Optional[str] = Form(None),
    session: AsyncSession = Depends(get_db_session),
    current_empleado: Empleado = require_admin_finanzas(),
):
    existing = (
        await session.execute(
            select(PayrollAccountMapping).where(
                PayrollAccountMapping.payroll_employer_id == payroll_employer_id,
                PayrollAccountMapping.purpose_key == (purpose_key or "").strip(),
            )
        )
    ).scalar_one_or_none()
    mapping = existing or PayrollAccountMapping(
        payroll_employer_id=payroll_employer_id,
        purpose_key=(purpose_key or "").strip(),
        created_by_empleado_id=current_empleado.id,
    )
    mapping.cuenta_contable_id = cuenta_contable_id
    mapping.notes = _clean_optional_text(notes)
    mapping.active = _truthy_form(active)
    if existing is None:
        session.add(mapping)
    await session.commit()
    return RedirectResponse(url="/admin/nomina/cuentas?success_msg=" + quote("Mapping guardado"), status_code=303)


@router.get("/admin/nomina/cfdi", response_class=HTMLResponse)
async def nomina_cfdi_view(
    request: Request,
    session: AsyncSession = Depends(get_db_session),
    current_empleado: Empleado = require_admin_finanzas(),
) -> str:
    success_msg = request.query_params.get("success_msg", "")
    error_msg = request.query_params.get("error_msg", "")
    await ensure_payroll_sat_seed(session)
    catalog_entries, explicit_mappings, concept_rows = await load_payroll_sat_reference_data(session)

    mapping_rows = build_cfdi_mapping_rows(
        concepts=concept_rows,
        explicit_mappings=explicit_mappings,
        catalog_entries=catalog_entries,
    )
    def _catalog_select_html(sat_group: str, selected_code: str) -> str:
        return "".join(
            f'<option value="{escape(entry.code)}" {"selected" if entry.code == selected_code else ""}>{escape(entry.code)} · {escape(entry.description)}</option>'
            for entry in catalog_entries
            if entry.sat_group == sat_group
        )

    mapping_table_rows = "".join(
        f"""
        <tr>
            <td>{escape(_PAYROLL_SAT_GROUP_LABELS.get(row["sat_group"], row["sat_group"]))}</td>
            <td>{escape(row["concept_label"])}</td>
            <td><code>{escape(row["concept_key"])}</code></td>
            <td>{escape(row["sat_code"])}</td>
            <td>{escape(row["sat_description"])}</td>
            <td>{escape(row["mapping_basis"])}</td>
            <td style="min-width:340px;">
                <form method="POST" action="/admin/nomina/cfdi/mapping/save" style="display:grid;grid-template-columns:1fr 1fr auto;gap:8px;align-items:end;">
                    <input type="hidden" name="sat_group" value="{escape(row["sat_group"])}">
                    <input type="hidden" name="concept_key" value="{escape(row["concept_key"])}">
                    <div>
                        <label style="font-size:12px;color:#6b7280;">Clave SAT</label>
                        <select name="sat_code" required>{_catalog_select_html(row["sat_group"], row["sat_code"])}</select>
                    </div>
                    <div>
                        <label style="font-size:12px;color:#6b7280;">Notas</label>
                        <input type="text" name="notes" value="{_html_value(row["notes"])}" placeholder="Manual, validado con despacho, etc.">
                    </div>
                    <div><button type="submit" class="button">Guardar</button></div>
                </form>
            </td>
        </tr>
        """
        for row in mapping_rows
    )

    html = f"""
    <!DOCTYPE html>
    <html><head><meta charset="utf-8"><meta name="viewport" content="width=device-width, initial-scale=1"><title>CFDI SAT Nómina</title>
    <style>
    body {{ font-family: Arial, sans-serif; background:#f6f8fb; margin:0; padding:20px; }}
    .container {{ max-width: 1500px; margin:0 auto; }}
    .card {{ background:#fff; border:1px solid #e5e7eb; border-radius:10px; padding:16px; margin-bottom:16px; }}
    table {{ width:100%; border-collapse:collapse; }}
    th, td {{ padding:10px 12px; border-bottom:1px solid #e5e7eb; text-align:left; font-size:13px; vertical-align:top; }}
    th {{ background:#f3f4f6; }}
    input, select {{ width:100%; padding:8px 10px; border:1px solid #d1d5db; border-radius:8px; box-sizing:border-box; }}
    .button {{ display:inline-block; padding:10px 14px; border-radius:8px; text-decoration:none; background:#111827; color:#fff; border:none; cursor:pointer; }}
    .muted {{ color:#6b7280; font-size:13px; }}
    code {{ font-size:12px; }}
    </style></head>
    <body><div class="container">{render_top_navigation(current_empleado, "nomina")}{_payroll_subnav("cfdi")}
    <div class="card">
        <h1 style="margin:0 0 8px 0;">Mapeo SAT para CFDI de nómina</h1>
        <p class="muted" style="margin:0 0 16px 0;">Este bloque no timbra todavía. Proyecta el prerrecibo a catálogos SAT para detectar gaps antes del CFDI real. Los defaults sembrados son conservadores y editables.</p>
        <div class="muted" style="margin:0 0 10px 0;">Fuente oficial base: <a href="{SAT_GUIDE_URL}" target="_blank" rel="noopener">Guía de llenado SAT nómina</a></div>
        {f'<div style="background:#d1fae5;color:#065f46;border:1px solid #a7f3d0;border-radius:10px;padding:12px 14px;margin:0 0 16px 0;"><strong>✅ Éxito:</strong> {escape(success_msg)}</div>' if success_msg else ''}
        {f'<div style="background:#fee2e2;color:#991b1b;border:1px solid #fecaca;border-radius:10px;padding:12px 14px;margin:0 0 16px 0;"><strong>❌ Error:</strong> {escape(error_msg)}</div>' if error_msg else ''}
        <table>
            <thead><tr><th>Grupo SAT</th><th>Concepto interno</th><th>Clave interna</th><th>Clave SAT</th><th>Descripción SAT</th><th>Origen</th><th>Configurar</th></tr></thead>
            <tbody>{mapping_table_rows}</tbody>
        </table>
    </div>
    </div></body></html>
    """
    return html


@router.post("/admin/nomina/cfdi/mapping/save")
async def nomina_cfdi_mapping_save(
    sat_group: str = Form(...),
    concept_key: str = Form(...),
    sat_code: str = Form(...),
    notes: Optional[str] = Form(None),
    session: AsyncSession = Depends(get_db_session),
    current_empleado: Empleado = require_admin_finanzas(),
):
    await ensure_payroll_sat_seed(session)
    sat_group_clean = (sat_group or "").strip().lower()
    concept_key_clean = (concept_key or "").strip()
    sat_code_clean = (sat_code or "").strip()
    catalog_entry = await session.scalar(
        select(PayrollSATCatalogEntry).where(
            PayrollSATCatalogEntry.sat_group == sat_group_clean,
            PayrollSATCatalogEntry.code == sat_code_clean,
            PayrollSATCatalogEntry.active.is_(True),
        )
    )
    if catalog_entry is None:
        return RedirectResponse(url="/admin/nomina/cfdi?error_msg=" + quote("La clave SAT seleccionada no existe en el catálogo activo"), status_code=303)

    mapping = await session.scalar(
        select(PayrollSATConceptMapping).where(
            PayrollSATConceptMapping.sat_group == sat_group_clean,
            PayrollSATConceptMapping.concept_key == concept_key_clean,
        )
    )
    if mapping is None:
        mapping = PayrollSATConceptMapping(
            sat_group=sat_group_clean,
            concept_key=concept_key_clean,
            sat_code=sat_code_clean,
            active=True,
            mapping_basis="manual",
            notes=_clean_optional_text(notes),
            created_by_empleado_id=current_empleado.id,
        )
        session.add(mapping)
    else:
        mapping.sat_code = sat_code_clean
        mapping.mapping_basis = "manual"
        mapping.notes = _clean_optional_text(notes)
        mapping.active = True
        if not mapping.created_by_empleado_id:
            mapping.created_by_empleado_id = current_empleado.id

    await session.commit()
    return RedirectResponse(url="/admin/nomina/cfdi?success_msg=" + quote("Mapping SAT actualizado"), status_code=303)


@router.get("/admin/nomina/empleados", response_class=HTMLResponse)
async def nomina_empleados_view(
    request: Request,
    session: AsyncSession = Depends(get_db_session),
    current_empleado: Empleado = require_admin_finanzas(),
) -> str:
    """Payroll employee master data admin aligned to the Runa layout."""
    success_msg = request.query_params.get("success_msg", "")
    error_msg = request.query_params.get("error_msg", "")
    selected_empleado_id = (request.query_params.get("empleado_id") or "").strip()

    payroll_records = (
        await session.execute(
            select(PayrollEmployee)
            .options(
                selectinload(PayrollEmployee.empleado),
                selectinload(PayrollEmployee.employer_registration).selectinload(PayrollEmployerRegistration.employer),
                selectinload(PayrollEmployee.compensation_profile),
                selectinload(PayrollEmployee.payment_profile),
                selectinload(PayrollEmployee.deduction_profile),
                selectinload(PayrollEmployee.benefit_profile),
                selectinload(PayrollEmployee.address_profile),
            )
            .order_by(PayrollEmployee.active.desc(), PayrollEmployee.updated_at.desc())
        )
    ).scalars().all()
    payroll_by_empleado = {str(pay.empleado_id): pay for pay in payroll_records}
    selected_payroll = payroll_by_empleado.get(selected_empleado_id)

    all_empleados = (
        await session.execute(
            select(Empleado)
            .where(Empleado.activo == True)
            .order_by(Empleado.nombre.asc(), Empleado.correo.asc())
        )
    ).scalars().all()
    employer_registrations = (
        await session.execute(
            select(PayrollEmployerRegistration)
            .options(selectinload(PayrollEmployerRegistration.employer))
            .where(PayrollEmployerRegistration.active == True)
            .order_by(PayrollEmployerRegistration.registration_code.asc())
        )
    ).scalars().all()

    empleado_options = ['<option value="">Selecciona empleado</option>']
    for emp in all_empleados:
        configured = payroll_by_empleado.get(str(emp.id))
        badge = " · configurado" if configured else ""
        selected = "selected" if str(emp.id) == selected_empleado_id else ""
        empleado_options.append(
            f'<option value="{emp.id}" {selected}>{escape(emp.nombre or emp.correo or str(emp.id))} · {escape(emp.correo or "-")}{badge}</option>'
        )

    pay = selected_payroll
    comp = pay.compensation_profile if pay else None
    payment = pay.payment_profile if pay else None
    deduction = pay.deduction_profile if pay else None
    benefit = pay.benefit_profile if pay else None
    address = pay.address_profile if pay else None

    rows_html = "".join(
        f"""
        <tr>
            <td>{escape((pay.empleado.nombre if pay.empleado else None) or '-')}</td>
            <td>{escape((pay.empleado.email if pay.empleado else None) or '-')}</td>
            <td>{escape(pay.employee_number or '-')}</td>
            <td>{escape(pay.employee_type or '-')}</td>
            <td>{escape(pay.contract_type or '-')}</td>
            <td>{escape((comp.compensation_regime if comp else None) or '-')}</td>
            <td>{escape((pay.employer_registration.registration_code if pay.employer_registration else None) or '-')}</td>
            <td>{escape((payment.bank_name if payment else pay.bank_name) or '-')}</td>
            <td>{escape((benefit.voucher_provider if benefit else None) or '-')}</td>
            <td>{'Sí' if pay.active else 'No'}</td>
            <td><a class="button secondary" style="padding:6px 10px;" href="/admin/nomina/empleados?empleado_id={pay.empleado_id}">Editar</a></td>
        </tr>
        """
        for pay in payroll_records
    )

    form_mode = "Editar empleado de nómina" if selected_payroll else "Alta de empleado de nómina"
    submit_label = "Actualizar ficha" if selected_payroll else "Guardar ficha"
    context_note = (
        f"Editando la ficha de {escape((selected_payroll.empleado.nombre if selected_payroll and selected_payroll.empleado else None) or (selected_payroll.empleado.email if selected_payroll and selected_payroll.empleado else '') or 'empleado')}"
        if selected_payroll
        else "Captura maestra alineada al layout Runa: identidad fiscal, empleo, compensación, pago, deducciones, beneficios y domicilio."
    )
    employer_registration_options = ['<option value="">Sin asignar</option>']
    for registration in employer_registrations:
        selected = "selected" if pay and pay.employer_registration_id == registration.id else ""
        label = f"{registration.registration_code} · {registration.employer.legal_name if registration.employer else '-'}"
        employer_registration_options.append(f'<option value="{registration.id}" {selected}>{escape(label)}</option>')

    html = f"""
    <!DOCTYPE html>
    <html>
    <head>
        <meta charset="utf-8">
        <meta name="viewport" content="width=device-width, initial-scale=1">
        <title>Empleados de Nómina</title>
        <style>
            body {{ font-family: Arial, sans-serif; background:#f6f8fb; margin:0; padding:20px; }}
            .container {{ max-width: 1480px; margin:0 auto; }}
            .card {{ background:#fff; border:1px solid #e5e7eb; border-radius:10px; padding:16px; margin-bottom:16px; }}
            .grid {{ display:grid; grid-template-columns:repeat(auto-fit,minmax(200px,1fr)); gap:12px; }}
            .grid.two {{ grid-template-columns:repeat(auto-fit,minmax(260px,1fr)); }}
            table {{ width:100%; border-collapse:collapse; }}
            th, td {{ padding:10px 12px; border-bottom:1px solid #e5e7eb; text-align:left; font-size:13px; }}
            th {{ background:#f3f4f6; }}
            input, select {{ width:100%; padding:8px 10px; border:1px solid #d1d5db; border-radius:8px; box-sizing:border-box; }}
            .button {{ display:inline-block; padding:10px 14px; border-radius:8px; text-decoration:none; background:#111827; color:#fff; border:none; cursor:pointer; }}
            .button.secondary {{ background:#e5e7eb; color:#111827; }}
            .tabbar {{ display:flex; gap:8px; flex-wrap:wrap; margin:0 0 16px 0; }}
            .tabbar button {{ border:none; border-radius:999px; padding:8px 12px; cursor:pointer; background:#e5e7eb; color:#111827; }}
            .tabbar button.active {{ background:#111827; color:#fff; }}
            .tab-panel {{ display:none; }}
            .tab-panel.active {{ display:block; }}
            .muted {{ color:#6b7280; font-size:13px; }}
            .section-title {{ margin:0 0 10px 0; font-size:16px; }}
        </style>
    </head>
    <body>
        <div class="container">
            {render_top_navigation(current_empleado, "nomina")}
            {_payroll_subnav("empleados")}
            <div class="card">
                <h1 style="margin:0 0 8px 0;">{form_mode}</h1>
                <p style="margin:0 0 16px 0;color:#6b7280;">{context_note}</p>
                <div style="margin:0 0 16px 0;"><a href="/admin/nomina/runa/carga-masiva" class="button secondary">Importar layout Runa</a></div>
                {f'<div style="background:#d1fae5;color:#065f46;border:1px solid #a7f3d0;border-radius:10px;padding:12px 14px;margin:0 0 16px 0;"><strong>✅ Éxito:</strong> {escape(success_msg)}</div>' if success_msg else ''}
                {f'<div style="background:#fee2e2;color:#991b1b;border:1px solid #fecaca;border-radius:10px;padding:12px 14px;margin:0 0 16px 0;"><strong>❌ Error:</strong> {escape(error_msg)}</div>' if error_msg else ''}
                <form method="POST" action="/admin/nomina/empleados">
                    <div class="grid two" style="margin-bottom:16px;">
                        <div><label>Empleado interno</label><select name="empleado_id" required>{"".join(empleado_options)}</select></div>
                        <div><label>Número empleado</label><input type="text" name="employee_number" value="{_html_value(pay.employee_number if pay else None)}"></div>
                    </div>
                    <div class="tabbar">
                        <button type="button" class="active" data-tab-target="tab-fiscal">Datos fiscales</button>
                        <button type="button" data-tab-target="tab-empleo">Empleo</button>
                        <button type="button" data-tab-target="tab-comp">Compensación</button>
                        <button type="button" data-tab-target="tab-pago">Pago</button>
                        <button type="button" data-tab-target="tab-deducciones">Deducciones</button>
                        <button type="button" data-tab-target="tab-beneficios">Beneficios</button>
                        <button type="button" data-tab-target="tab-direccion">Dirección fiscal</button>
                    </div>

                    <div id="tab-fiscal" class="tab-panel active">
                        <h3 class="section-title">Datos fiscales y personales</h3>
                        <div class="grid">
                            <div><label>Fecha nacimiento</label><input type="date" name="birth_date" value="{_html_value(pay.birth_date if pay else None)}"></div>
                            <div><label>Lugar nacimiento</label><input type="text" name="birth_place" value="{_html_value(pay.birth_place if pay else None)}"></div>
                            <div><label>Género</label><select name="gender"><option value=""></option><option value="Masculino" {_selected_attr(pay.gender if pay else None, "Masculino")}>Masculino</option><option value="Femenino" {_selected_attr(pay.gender if pay else None, "Femenino")}>Femenino</option></select></div>
                            <div><label>RFC</label><input type="text" name="rfc" value="{_html_value(pay.rfc if pay else None)}"></div>
                            <div><label>CURP</label><input type="text" name="curp" value="{_html_value(pay.curp if pay else None)}"></div>
                            <div><label>NSS</label><input type="text" name="nss" value="{_html_value(pay.nss if pay else None)}"></div>
                            <div><label>Régimen fiscal</label><input list="tax-regimes" type="text" name="tax_regime" value="{_html_value(pay.tax_regime if pay else None)}"></div>
                            <div><label>Email notificaciones</label><input type="email" name="personal_email" value="{_html_value(pay.personal_email if pay else None)}"></div>
                            <div><label>Email laboral</label><input type="email" name="work_email" value="{_html_value(pay.work_email if pay else None)}"></div>
                            <div><label>Código postal personal</label><input type="text" name="personal_postal_code" value="{_html_value(pay.personal_postal_code if pay else None)}"></div>
                            <div><label>UMF</label><input type="text" name="umf" value="{_html_value(benefit.umf if benefit else None)}"></div>
                        </div>
                    </div>

                    <div id="tab-empleo" class="tab-panel">
                        <h3 class="section-title">Empleo actual</h3>
                        <div class="grid">
                            <div><label>Fecha ingreso</label><input type="date" name="hire_date" value="{_html_value(pay.hire_date if pay else None)}"></div>
                            <div><label>Fecha antigüedad</label><input type="date" name="seniority_date" value="{_html_value(pay.seniority_date if pay else None)}"></div>
                            <div><label>Inicio contrato</label><input type="date" name="contract_start_date" value="{_html_value(pay.contract_start_date if pay else None)}"></div>
                            <div><label>Fin contrato</label><input type="date" name="contract_end_date" value="{_html_value(pay.contract_end_date if pay else None)}"></div>
                            <div><label>Estado empleo</label><input type="text" name="employment_state" value="{_html_value(pay.employment_state if pay else None)}"></div>
                            <div><label>Puesto</label><input type="text" name="job_title" value="{_html_value(pay.job_title if pay else None)}"></div>
                            <div><label>Área</label><input type="text" name="department_name" value="{_html_value(pay.department_name if pay else None)}"></div>
                            <div><label>Registro patronal</label><select name="employer_registration_id">{"".join(employer_registration_options)}</select></div>
                            <div><label>Tipo empleado</label><input type="text" name="employee_type" value="{_html_value(pay.employee_type if pay else None)}"></div>
                            <div><label>Tipo contrato</label><input type="text" name="contract_type" value="{_html_value(pay.contract_type if pay else None)}"></div>
                            <div><label>Política</label><input type="text" name="policy_name" value="{_html_value(pay.policy_name if pay else None)}"></div>
                            <div><label>Tipo trabajador</label><input list="worker-types" type="text" name="worker_type" value="{_html_value(pay.worker_type if pay else None)}"></div>
                            <div><label>Área geográfica</label><select name="geographic_area"><option value=""></option><option value="Área general" {_selected_attr(pay.geographic_area if pay else None, "Área general")}>Área general</option><option value="Zona libre de la frontera norte" {_selected_attr(pay.geographic_area if pay else None, "Zona libre de la frontera norte")}>Zona libre de la frontera norte</option></select></div>
                            <div><label>Esquema jornada</label><input type="text" name="schedule_scheme" value="{_html_value(pay.schedule_scheme if pay else None)}"></div>
                            <div><label>Semana/jornada reducida</label><input type="text" name="reduced_workweek_type" value="{_html_value(pay.reduced_workweek_type if pay else None)}"></div>
                            <div><label>Número días laborados</label><input type="number" step="0.01" name="worked_days_override" value="{_html_value(pay.worked_days_override if pay else None)}"></div>
                            <div><label>Frecuencia</label><select name="payroll_frequency"><option value="biweekly" {_selected_attr(pay.payroll_frequency if pay else None, "biweekly")}>Quincenal</option><option value="weekly" {_selected_attr(pay.payroll_frequency if pay else None, "weekly")}>Semanal</option><option value="monthly" {_selected_attr(pay.payroll_frequency if pay else None, "monthly")}>Mensual</option></select></div>
                            <div><label>Zona salarial</label><select name="salary_zone"><option value="general" {_selected_attr(pay.salary_zone if pay else None, "general")}>General</option><option value="zlfn" {_selected_attr(pay.salary_zone if pay else None, "zlfn")}>ZLFN</option></select></div>
                            <div><label><input type="checkbox" name="active" value="1" {"checked" if (pay.active if pay else True) else ""}> Activo</label></div>
                        </div>
                    </div>

                    <div id="tab-comp" class="tab-panel">
                        <h3 class="section-title">Detalle de compensación</h3>
                        <div class="grid">
                            <div><label>Régimen compensación</label><select name="compensation_regime"><option value=""></option><option value="Sueldos y Salarios" {_selected_attr(comp.compensation_regime if comp else None, "Sueldos y Salarios")}>Sueldos y Salarios</option><option value="Asimilado" {_selected_attr(comp.compensation_regime if comp else None, "Asimilado")}>Asimilado</option></select></div>
                            <div><label>Tipo sueldo</label><select name="salary_type"><option value=""></option><option value="Fijo" {_selected_attr(comp.salary_type if comp else None, "Fijo")}>Fijo</option><option value="Variable" {_selected_attr(comp.salary_type if comp else None, "Variable")}>Variable</option><option value="Mixto" {_selected_attr(comp.salary_type if comp else None, "Mixto")}>Mixto</option></select></div>
                            <div><label>Salario neto mensual</label><input type="number" step="0.01" name="monthly_net_salary" value="{_html_value(comp.monthly_net_salary if comp else None)}"></div>
                            <div><label>Sueldo diario</label><input type="number" step="0.01" name="daily_salary" value="{_html_value(comp.daily_salary if comp else (pay.daily_salary if pay else None))}"></div>
                            <div><label>SBC</label><input type="number" step="0.01" name="integrated_daily_salary" value="{_html_value(comp.integrated_daily_salary if comp else (pay.integrated_daily_salary if pay else None))}"></div>
                            <div><label>Salario variable</label><input type="number" step="0.01" name="variable_salary" value="{_html_value(comp.variable_salary if comp else (pay.variable_salary if pay else None))}"></div>
                            <div><label>Salario indemnización</label><input type="number" step="0.01" name="severance_daily_salary" value="{_html_value(comp.severance_daily_salary if comp else None)}"></div>
                            <div><label>Riesgo patronal</label><input type="text" value="{_html_value((pay.employer_registration.registration_code + ' · clase ' + (pay.employer_registration.risk_class or '-')) if pay and pay.employer_registration else '')}" disabled></div>
                        </div>
                    </div>

                    <div id="tab-pago" class="tab-panel">
                        <h3 class="section-title">Datos de pago</h3>
                        <div class="grid">
                            <div><label>Método de pago</label><select name="payment_method"><option value="transfer" {_selected_attr(payment.payment_method if payment else pay.payment_method if pay else None, "transfer")}>Transferencia</option><option value="check" {_selected_attr(payment.payment_method if payment else pay.payment_method if pay else None, "check")}>Cheque</option><option value="cash" {_selected_attr(payment.payment_method if payment else pay.payment_method if pay else None, "cash")}>Efectivo</option></select></div>
                            <div><label>Banco</label><input type="text" name="bank_name" value="{_html_value(payment.bank_name if payment else (pay.bank_name if pay else None))}"></div>
                            <div><label>Número de cuenta</label><input type="text" name="account_number" value="{_html_value(payment.account_number if payment else None)}"></div>
                            <div><label>CLABE</label><input type="text" name="clabe" value="{_html_value(payment.clabe if payment else None)}"></div>
                            <div><label>Número de cliente</label><input type="text" name="customer_number" value="{_html_value(payment.customer_number if payment else None)}"></div>
                        </div>
                    </div>

                    <div id="tab-deducciones" class="tab-panel">
                        <h3 class="section-title">Deducciones periódicas</h3>
                        <div class="grid">
                            <div><label>Nombre descuento</label><input type="text" name="deduction_name" value="{_html_value(deduction.deduction_name if deduction else None)}"></div>
                            <div><label>Tipo descuento INFONAVIT</label><select name="infonavit_discount_type"><option value=""></option><option value="Porcentaje" {_selected_attr(deduction.infonavit_discount_type if deduction else None, "Porcentaje")}>Porcentaje</option><option value="Cuota Fija" {_selected_attr(deduction.infonavit_discount_type if deduction else None, "Cuota Fija")}>Cuota Fija</option><option value="Valor de descuento Infonavit 2018" {_selected_attr(deduction.infonavit_discount_type if deduction else None, "Valor de descuento Infonavit 2018")}>Valor de descuento Infonavit 2018</option></select></div>
                            <div><label>Valor descuento INFONAVIT</label><input type="number" step="0.01" name="infonavit_discount_value" value="{_html_value(deduction.infonavit_discount_value if deduction else None)}"></div>
                            <div><label>Folio aviso INFONAVIT</label><input type="text" name="infonavit_notice_folio" value="{_html_value(deduction.infonavit_notice_folio if deduction else None)}"></div>
                            <div><label>No. crédito INFONAVIT</label><input type="text" name="infonavit_credit_number" value="{_html_value(deduction.infonavit_credit_number if deduction else None)}"></div>
                            <div><label>Fecha inicio INFONAVIT</label><input type="date" name="infonavit_start_date" value="{_html_value(deduction.infonavit_start_date if deduction else None)}"></div>
                            <div><label>Saldo préstamo</label><input type="number" step="0.01" name="loan_balance" value="{_html_value(deduction.loan_balance if deduction else None)}"></div>
                            <div><label>Monto mensual descuento</label><input type="number" step="0.01" name="monthly_deduction_amount" value="{_html_value(deduction.monthly_deduction_amount if deduction else None)}"></div>
                            <div><label>Descuento nómina</label><input type="text" name="payroll_deduction_name" value="{_html_value(deduction.payroll_deduction_name if deduction else None)}"></div>
                            <div><label>Folio crédito FONACOT</label><input type="text" name="fonacot_credit_folio" value="{_html_value(deduction.fonacot_credit_folio if deduction else None)}"></div>
                            <div><label>Tipo descuento FONACOT</label><select name="fonacot_discount_type"><option value=""></option><option value="Cuota Fija" {_selected_attr(deduction.fonacot_discount_type if deduction else None, "Cuota Fija")}>Cuota Fija</option><option value="Porcentaje Neto" {_selected_attr(deduction.fonacot_discount_type if deduction else None, "Porcentaje Neto")}>Porcentaje Neto</option><option value="Porcentaje Bruto" {_selected_attr(deduction.fonacot_discount_type if deduction else None, "Porcentaje Bruto")}>Porcentaje Bruto</option></select></div>
                            <div><label>Valor descuento FONACOT</label><input type="number" step="0.01" name="fonacot_discount_value" value="{_html_value(deduction.fonacot_discount_value if deduction else None)}"></div>
                            <div><label>Fecha inicio FONACOT</label><input type="date" name="fonacot_start_date" value="{_html_value(deduction.fonacot_start_date if deduction else None)}"></div>
                            <div><label>Pensión alimenticia (%)</label><input type="number" step="0.01" name="alimony_percentage" value="{_html_value(deduction.alimony_percentage if deduction else None)}"></div>
                            <div><label>Modo pensión alimenticia</label><select name="alimony_mode"><option value=""></option><option value="percent_net" {_selected_attr(deduction.alimony_mode if deduction else None, "percent_net")}>% sobre neto</option><option value="percent_gross" {_selected_attr(deduction.alimony_mode if deduction else None, "percent_gross")}>% sobre bruto</option><option value="fixed_amount" {_selected_attr(deduction.alimony_mode if deduction else None, "fixed_amount")}>Monto fijo</option></select></div>
                            <div><label>Monto fijo pensión</label><input type="number" step="0.01" name="alimony_fixed_amount" value="{_html_value(deduction.alimony_fixed_amount if deduction else None)}"></div>
                            <div><label>Expediente / caso</label><input type="text" name="alimony_case_number" value="{_html_value(deduction.alimony_case_number if deduction else None)}"></div>
                            <div><label>Beneficiario</label><input type="text" name="alimony_beneficiary_name" value="{_html_value(deduction.alimony_beneficiary_name if deduction else None)}"></div>
                            <div><label>Banco beneficiario</label><input type="text" name="alimony_beneficiary_bank" value="{_html_value(deduction.alimony_beneficiary_bank if deduction else None)}"></div>
                            <div><label>Cuenta beneficiario</label><input type="text" name="alimony_beneficiary_account" value="{_html_value(deduction.alimony_beneficiary_account if deduction else None)}"></div>
                            <div><label>CLABE beneficiario</label><input type="text" name="alimony_beneficiary_clabe" value="{_html_value(deduction.alimony_beneficiary_clabe if deduction else None)}"></div>
                            <div><label>Vigencia desde</label><input type="date" name="alimony_effective_from" value="{_html_value(deduction.alimony_effective_from if deduction else None)}"></div>
                            <div><label>Vigencia hasta</label><input type="date" name="alimony_effective_to" value="{_html_value(deduction.alimony_effective_to if deduction else None)}"></div>
                            <div><label>Juzgado</label><input type="text" name="alimony_court_name" value="{_html_value(deduction.alimony_court_name if deduction else None)}"></div>
                            <div><label>Oficio / referencia</label><input type="text" name="alimony_office_reference" value="{_html_value(deduction.alimony_office_reference if deduction else None)}"></div>
                            <div><label>Orden de prioridad</label><input type="number" step="1" name="alimony_priority_order" value="{_html_value(deduction.alimony_priority_order if deduction else None)}"></div>
                            <div><label><input type="checkbox" name="alimony_apply_to_extraordinary" value="1" {"checked" if (deduction.alimony_apply_to_extraordinary if deduction else False) else ""}> Aplicar a percepciones extraordinarias</label></div>
                        </div>
                    </div>

                    <div id="tab-beneficios" class="tab-panel">
                        <h3 class="section-title">Beneficios</h3>
                        <div class="grid">
                            <div><label>Saldo vacaciones</label><input type="number" step="0.01" name="vacation_balance" value="{_html_value(benefit.vacation_balance if benefit else None)}"></div>
                            <div><label>Proveedor vales</label><input type="text" name="voucher_provider" value="{_html_value(benefit.voucher_provider if benefit else None)}"></div>
                            <div><label>Número cuenta vales</label><input type="text" name="voucher_account_number" value="{_html_value(benefit.voucher_account_number if benefit else None)}"></div>
                            <div><label>Número tarjeta vales</label><input type="text" name="voucher_card_number" value="{_html_value(benefit.voucher_card_number if benefit else None)}"></div>
                        </div>
                    </div>

                    <div id="tab-direccion" class="tab-panel">
                        <h3 class="section-title">Dirección fiscal</h3>
                        <div class="grid">
                            <div><label>Calle</label><input type="text" name="street" value="{_html_value(address.street if address else None)}"></div>
                            <div><label>Número exterior</label><input type="text" name="exterior_number" value="{_html_value(address.exterior_number if address else None)}"></div>
                            <div><label>Número interior</label><input type="text" name="interior_number" value="{_html_value(address.interior_number if address else None)}"></div>
                            <div><label>Colonia</label><input type="text" name="neighborhood" value="{_html_value(address.neighborhood if address else None)}"></div>
                            <div><label>Municipio</label><input type="text" name="municipality" value="{_html_value(address.municipality if address else None)}"></div>
                            <div><label>Estado</label><input type="text" name="address_state" value="{_html_value(address.state if address else None)}"></div>
                            <div><label>Código postal</label><input type="text" name="address_postal_code" value="{_html_value(address.postal_code if address else None)}"></div>
                        </div>
                    </div>

                    <datalist id="tax-regimes">
                        <option value="Sueldos y Salarios e Ingresos Asimilados a Salarios"></option>
                        <option value="Personas Físicas con Actividades Empresariales y Profesionales"></option>
                        <option value="Arrendamiento"></option>
                        <option value="Demás ingresos"></option>
                    </datalist>
                    <datalist id="worker-types">
                        <option value="Trabajador Permanente"></option>
                        <option value="Trabajador Eventual"></option>
                        <option value="Trabajador Eventual para Construcción"></option>
                        <option value="Trabajador Eventual para Campo"></option>
                    </datalist>
                    <div style="margin-top:14px;display:flex;gap:10px;align-items:center;">
                        <button type="submit" class="button">{submit_label}</button>
                        {f'<a href="/admin/nomina/empleados" class="button secondary">Nueva captura</a>' if selected_payroll else ''}
                    </div>
                </form>
            </div>
            <div class="card">
                <h2 style="margin:0 0 12px 0;">Empleados registrados</h2>
                <table>
                    <thead><tr><th>Empleado</th><th>Email</th><th>Número</th><th>Tipo empleado</th><th>Contrato</th><th>Régimen</th><th>Registro patronal</th><th>Banco</th><th>Vales</th><th>Activo</th><th></th></tr></thead>
                    <tbody>{rows_html if rows_html else '<tr><td colspan="11" style="color:#6b7280;">Sin empleados de nómina todavía</td></tr>'}</tbody>
                </table>
            </div>
        </div>
        <script>
            const tabButtons = document.querySelectorAll('[data-tab-target]');
            const tabPanels = document.querySelectorAll('.tab-panel');
            tabButtons.forEach((button) => {{
                button.addEventListener('click', () => {{
                    const target = button.getAttribute('data-tab-target');
                    tabButtons.forEach((b) => b.classList.remove('active'));
                    tabPanels.forEach((panel) => panel.classList.remove('active'));
                    button.classList.add('active');
                    const panel = document.getElementById(target);
                    if (panel) panel.classList.add('active');
                }});
            }});
        </script>
    </body>
    </html>
    """
    return html


def _safe_export_filename(value: Optional[str], fallback: str = "documento") -> str:
    text_value = str(value or fallback).strip() or fallback
    cleaned = re.sub(r"[^A-Za-z0-9._-]+", "_", text_value).strip("._-")
    return cleaned or fallback


