@router.get("/admin/contabilidad/mayor/export.pdf")
async def contabilidad_mayor_export_pdf(
    session: AsyncSession = Depends(get_db_session),
    current_empleado: Empleado = require_admin_finanzas(),
    year: Optional[int] = Query(None),
    month: Optional[int] = Query(None),
    cuenta_codigo: str = Query("all"),
    q: str = Query(""),
):
    from reportlab.lib.pagesizes import A4, landscape
    from reportlab.pdfgen import canvas

    now = datetime.utcnow()
    selected_year = year or now.year
    selected_month = month or now.month
    selected_cuenta = (cuenta_codigo or "all").strip()
    selected_q = (q or "").strip()

    start_dt = datetime(selected_year, selected_month, 1)
    end_dt = datetime(selected_year + 1, 1, 1) if selected_month == 12 else datetime(selected_year, selected_month + 1, 1)
    conditions = [
        AccountingPoliza.fecha_poliza.isnot(None),
        AccountingPoliza.fecha_poliza >= start_dt,
        AccountingPoliza.fecha_poliza < end_dt,
    ]
    if selected_q:
        token = f"%{selected_q}%"
        conditions.append(
            or_(
                AccountingPolizaLine.concepto.ilike(token),
                AccountingPoliza.numero_poliza.ilike(token),
                AccountingPoliza.beneficiario_nombre.ilike(token),
            )
        )
    if selected_cuenta != "all":
        conditions.append(AccountingPolizaLine.cuenta_codigo == selected_cuenta)

    lines = (
        await session.execute(
            select(AccountingPolizaLine)
            .join(AccountingPoliza, AccountingPoliza.id == AccountingPolizaLine.poliza_id)
            .options(selectinload(AccountingPolizaLine.poliza))
            .where(and_(*conditions))
            .order_by(AccountingPolizaLine.cuenta_codigo.asc(), AccountingPoliza.fecha_poliza.asc(), AccountingPoliza.numero_poliza.asc(), AccountingPolizaLine.line_no.asc())
        )
    ).scalars().all()

    output = io.BytesIO()
    page_width, page_height = landscape(A4)
    pdf = canvas.Canvas(output, pagesize=(page_width, page_height))
    y = page_height - 40

    def _draw_header():
        nonlocal y
        pdf.setFont("Helvetica-Bold", 12)
        pdf.drawString(30, y, f"Mayor contable {selected_year}-{selected_month:02d}")
        y -= 18
        pdf.setFont("Helvetica", 8)
        pdf.drawString(30, y, f"Filtros: cuenta={selected_cuenta}, q={selected_q or '—'}")
        y -= 20
        headers = ["Fecha", "Tipo", "Poliza", "Cuenta", "Concepto", "Debe", "Haber", "Saldo"]
        positions = [30, 92, 135, 195, 260, 610, 690, 770]
        for idx, header in enumerate(headers):
            pdf.drawString(positions[idx], y, header)
        y -= 12
        pdf.line(30, y, page_width - 30, y)
        y -= 12
        return positions

    positions = _draw_header()
    running_balance = 0.0
    running_code = None
    for line in lines:
        if running_code != line.cuenta_codigo:
            running_balance = 0.0
            running_code = line.cuenta_codigo
        running_balance += float(line.debe or 0) - float(line.haber or 0)
        poliza = line.poliza
        if y < 40:
            pdf.showPage()
            y = page_height - 40
            positions = _draw_header()
        values = [
            poliza.fecha_poliza.date().isoformat() if poliza and poliza.fecha_poliza else "",
            poliza.tipo_poliza if poliza else "",
            poliza.numero_poliza if poliza else "",
            (line.cuenta_codigo or "")[:10],
            (line.concepto or (poliza.concepto_resumen if poliza else "") or "")[:54],
            f"{float(line.debe or 0):,.2f}",
            f"{float(line.haber or 0):,.2f}",
            f"{running_balance:,.2f}",
        ]
        for idx, value in enumerate(values):
            pdf.drawString(positions[idx], y, str(value))
        y -= 12
    pdf.save()
    output.seek(0)
    return Response(
        content=output.getvalue(),
        media_type="application/pdf",
        headers={"Content-Disposition": f'attachment; filename=\"mayor_{selected_year}_{selected_month:02d}.pdf\"'},
    )


@router.get("/admin/contabilidad/balanza", response_class=HTMLResponse)
async def contabilidad_balanza_view(
    request: Request,
    session: AsyncSession = Depends(get_db_session),
    current_empleado: Empleado = require_admin_finanzas(),
    year: Optional[int] = Query(None),
    month: Optional[int] = Query(None),
    q: str = Query(""),
) -> str:
    now = datetime.utcnow()
    success_msg = request.query_params.get("success_msg", "")
    error_msg = request.query_params.get("error_msg", "")
    selected_year = year or now.year
    selected_month = month or now.month
    selected_q = (q or "").strip()

    start_dt = datetime(selected_year, selected_month, 1)
    end_dt = datetime(selected_year + 1, 1, 1) if selected_month == 12 else datetime(selected_year, selected_month + 1, 1)
    prior_dt = start_dt

    aux_conditions = [AuxLedgerEntry.fecha.isnot(None), AuxLedgerEntry.fecha >= start_dt, AuxLedgerEntry.fecha < end_dt]
    if selected_q:
        token = f"%{selected_q}%"
        aux_conditions.append(or_(AuxLedgerEntry.cuenta_codigo.ilike(token), AuxLedgerEntry.cuenta_nombre.ilike(token), AuxLedgerEntry.concepto.ilike(token)))

    aux_entries = (
        await session.execute(
            select(AuxLedgerEntry)
            .options(selectinload(AuxLedgerEntry.cuenta_contable))
            .where(and_(*aux_conditions))
            .order_by(AuxLedgerEntry.cuenta_codigo.asc(), AuxLedgerEntry.fecha.asc(), AuxLedgerEntry.source_row_number.asc())
        )
    ).scalars().all()

    opening_entries = (
        await session.execute(
            select(AuxLedgerEntry)
            .where(AuxLedgerEntry.fecha.isnot(None), AuxLedgerEntry.fecha < prior_dt)
            .order_by(AuxLedgerEntry.cuenta_codigo.asc(), AuxLedgerEntry.fecha.desc(), AuxLedgerEntry.source_row_number.desc())
        )
    ).scalars().all()
    opening_by_code: dict[str, float] = {}
    for entry in opening_entries:
        if entry.cuenta_codigo and entry.cuenta_codigo not in opening_by_code:
            opening_by_code[entry.cuenta_codigo] = float(entry.saldo or entry.saldo_inicial or 0)

    balances: dict[str, dict[str, Any]] = {}
    for entry in aux_entries:
        code = entry.cuenta_codigo or "Sin cuenta"
        bucket = balances.setdefault(
            code,
            {
                "nombre": (entry.cuenta_nombre or (entry.cuenta_contable.nombre if entry.cuenta_contable else "")),
                "saldo_inicial": opening_by_code.get(code, float(entry.saldo_inicial or 0)),
                "debe": 0.0,
                "haber": 0.0,
                "saldo_final": 0.0,
                "movimientos": 0,
            },
        )
        bucket["debe"] += float(entry.debe or 0)
        bucket["haber"] += float(entry.haber or 0)
        bucket["movimientos"] += 1
        bucket["saldo_final"] = float(entry.saldo or 0)
        if not bucket["nombre"] and entry.cuenta_contable:
            bucket["nombre"] = entry.cuenta_contable.nombre or ""

    rows = "".join(
        f"""
        <tr>
            <td><a href="/admin/contabilidad/mayor?year={selected_year}&month={selected_month}&cuenta_codigo={quote(code)}">{escape(code)}</a></td>
            <td>{escape(stats["nombre"] or "-")}</td>
            <td>{format_currency(stats["saldo_inicial"])}</td>
            <td>{format_currency(stats["debe"])}</td>
            <td>{format_currency(stats["haber"])}</td>
            <td>{format_currency(stats["saldo_final"] if stats["movimientos"] else stats["saldo_inicial"])}</td>
            <td>{int(stats["movimientos"])}</td>
        </tr>
        """
        for code, stats in sorted(balances.items())
    )

    totals = {
        "saldo_inicial": sum(stats["saldo_inicial"] for stats in balances.values()),
        "debe": sum(stats["debe"] for stats in balances.values()),
        "haber": sum(stats["haber"] for stats in balances.values()),
        "saldo_final": sum((stats["saldo_final"] if stats["movimientos"] else stats["saldo_inicial"]) for stats in balances.values()),
    }

    html = f"""
    <!DOCTYPE html>
    <html><head><meta charset="utf-8"><meta name="viewport" content="width=device-width, initial-scale=1"><title>Balanza de comprobación</title>
    <style>
    body {{ font-family: Arial, sans-serif; background:#f6f8fb; margin:0; padding:20px; }}
    .container {{ max-width: 1480px; margin:0 auto; }}
    .card {{ background:#fff; border:1px solid #e5e7eb; border-radius:10px; padding:16px; margin-bottom:16px; }}
    .toolbar {{ display:grid; grid-template-columns:repeat(auto-fit,minmax(180px,1fr)); gap:12px; }}
    input {{ width:100%; padding:8px 10px; border:1px solid #d1d5db; border-radius:8px; box-sizing:border-box; }}
    table {{ width:100%; border-collapse:collapse; }}
    th, td {{ padding:10px 12px; border-bottom:1px solid #e5e7eb; text-align:left; font-size:13px; vertical-align:top; }}
    th {{ background:#f3f4f6; }}
    .summary {{ display:grid; grid-template-columns:repeat(auto-fit,minmax(180px,1fr)); gap:12px; }}
    .summary .box {{ background:#111827; color:#fff; border-radius:10px; padding:14px; }}
    .summary .label {{ font-size:12px; opacity:.8; text-transform:uppercase; }}
    .summary .value {{ font-size:22px; font-weight:700; margin-top:6px; }}
    .button {{ display:inline-block; padding:10px 14px; border-radius:8px; text-decoration:none; background:#111827; color:#fff; border:none; cursor:pointer; }}
    .button.secondary {{ background:#e5e7eb; color:#111827; }}
    .muted {{ color:#6b7280; font-size:13px; }}
    </style></head>
    <body><div class="container">{render_top_navigation(current_empleado, "contabilidad")}{_contabilidad_subnav("balanza")}
        <div class="card">
            <h1 style="margin:0 0 8px 0;">Balanza de comprobación</h1>
            <p class="muted" style="margin:0 0 16px 0;">Vista operativa basada en el auxiliar importado. Usa saldo inicial previo al período, cargos, abonos y saldo final del mes seleccionado.</p>
            {f'<div style="background:#d1fae5;color:#065f46;border:1px solid #a7f3d0;border-radius:10px;padding:12px 14px;margin:0 0 16px 0;"><strong>✅ Éxito:</strong> {escape(success_msg)}</div>' if success_msg else ''}
            {f'<div style="background:#fee2e2;color:#991b1b;border:1px solid #fecaca;border-radius:10px;padding:12px 14px;margin:0 0 16px 0;"><strong>❌ Error:</strong> {escape(error_msg)}</div>' if error_msg else ''}
            <form method="GET" action="/admin/contabilidad/balanza" class="toolbar">
                <div><label>Año</label><input type="number" name="year" value="{selected_year}"></div>
                <div><label>Mes</label><input type="number" min="1" max="12" name="month" value="{selected_month}"></div>
                <div><label>Búsqueda</label><input type="text" name="q" value="{_html_value(selected_q)}" placeholder="Cuenta, nombre o concepto"></div>
                <div style="display:flex;align-items:end;gap:8px;flex-wrap:wrap;"><button type="submit" class="button">Filtrar</button><a href="/admin/contabilidad/balanza" class="button secondary">Limpiar</a><a href="/admin/contabilidad/balanza/export?year={selected_year}&month={selected_month}&q={quote(selected_q)}" class="button secondary">Exportar Excel</a><a href="/admin/contabilidad/balanza/export.pdf?year={selected_year}&month={selected_month}&q={quote(selected_q)}" class="button secondary">Exportar PDF</a></div>
            </form>
        </div>
        <div class="card">
            <div class="summary">
                <div class="box"><div class="label">Saldo inicial</div><div class="value">{format_currency(totals["saldo_inicial"])}</div></div>
                <div class="box"><div class="label">Debe</div><div class="value">{format_currency(totals["debe"])}</div></div>
                <div class="box"><div class="label">Haber</div><div class="value">{format_currency(totals["haber"])}</div></div>
                <div class="box"><div class="label">Saldo final</div><div class="value">{format_currency(totals["saldo_final"])}</div></div>
            </div>
        </div>
        <div class="card">
            <table>
                <thead><tr><th>Cuenta</th><th>Nombre</th><th>Saldo inicial</th><th>Debe</th><th>Haber</th><th>Saldo final</th><th>Movimientos</th></tr></thead>
                <tbody>{rows if rows else '<tr><td colspan="7" class="muted">Sin movimientos auxiliares para este período.</td></tr>'}</tbody>
            </table>
        </div>
    </div></body></html>
    """
    return html


