async def _validate_solicitud_terceros_fase(
    session: AsyncSession,
    *,
    empleado: Empleado,
    torneo_id_raw: str,
    fase_raw: str,
) -> Tuple[Optional[str], Optional[str]]:
    """Validate optional fase for standalone solicitud a terceros."""
    torneo_raw = (torneo_id_raw or "").strip()
    fase_st = (fase_raw or "").strip()
    if not fase_st:
        return None, None
    if torneo_raw == "__otro__" or not torneo_raw:
        return (
            "Fase/Subproyecto no aplica cuando el proyecto es manual.",
            None,
        )
    try:
        torneo_uuid = UUIDType(torneo_raw)
    except (ValueError, TypeError):
        return "El proyecto seleccionado no es válido.", None

    t_row = await session.get(Tournament, torneo_uuid)
    if not t_row:
        return "El proyecto indicado no existe.", None
    if not bool(getattr(t_row, "active", True)):
        return "Debe seleccionar un proyecto activo.", None

    vis_err = visibility_validation_error(t_row, empleado)
    if vis_err:
        return vis_err, None

    raw_etapas = getattr(t_row, "etapas", None)
    allowed: List[str] = []
    if raw_etapas and isinstance(raw_etapas, list):
        allowed = [str(x).strip() for x in raw_etapas if x is not None and str(x).strip()]
    if not allowed:
        return (
            "Este torneo/proyecto no tiene fases configuradas; deje Fase/Subproyecto vacío.",
            None,
        )
    if fase_st not in allowed:
        return (
            "La fase no corresponde al torneo/proyecto seleccionado.",
            None,
        )
    return None, fase_st


def _post_action_cta_html(
    *,
    primary_href: Optional[str],
    primary_label: Optional[str],
    home_href: str = "/panel",
    home_label: str = "Volver al inicio",
) -> str:
    actions: List[str] = []
    if primary_href and primary_label:
        actions.append(
            f'<a href="{escape(primary_href)}" class="button primary">{escape(primary_label)}</a>'
        )
    actions.append(
        f'<a href="{escape(home_href)}" class="button secondary">{escape(home_label)}</a>'
    )
    return (
        '<div class="inline-actions" style="margin-top:12px;">'
        + "".join(actions)
        + "</div>"
    )


def _document_primary_action(documento: Documento, *, approval_mode: bool = False) -> Tuple[str, str]:
    if approval_mode:
        return "/documentos/pendientes", "Realizar otra aprobación"
    if documento.tipo == "SOLICITUD":
        if getattr(documento, "cuenta_gastos_id", None):
            return (
                f"/informes-de-gastos/{documento.cuenta_gastos_id}/nueva-solicitud",
                "Realizar otra solicitud",
            )
        return "/documentos/nueva-solicitud-terceros", "Realizar otra solicitud"
    if documento.tipo == "INFORME":
        if documento.cuenta_gastos_id:
            return (
                f"/gastos/nuevo?cuenta_gastos_id={documento.cuenta_gastos_id}",
                "Registrar otro gasto",
            )
        return "/informes-de-gastos/crear", "Crear otro informe"
    return "/gastos/nuevo", "Registrar otro gasto"


def _document_success_actions_html(
    documento: Documento,
    *,
    approval_mode: bool = False,
) -> str:
    primary_href, primary_label = _document_primary_action(
        documento,
        approval_mode=approval_mode,
    )
    return _post_action_cta_html(
        primary_href=primary_href,
        primary_label=primary_label,
    )


def _cuenta_success_actions_html(
    *,
    cuenta_id: UUIDType,
    cuenta_estado: str,
    success_code: Optional[str],
) -> str:
    success_code_normalized = (success_code or "").strip().lower()
    if success_code_normalized == "creada":
        return _post_action_cta_html(
            primary_href="/informes-de-gastos/crear",
            primary_label="Crear otro informe",
        )
    if success_code_normalized == "solicitud_creada" and cuenta_estado == "abierta":
        return _post_action_cta_html(
            primary_href=f"/informes-de-gastos/{cuenta_id}/nueva-solicitud",
            primary_label="Crear otra solicitud",
        )
    if success_code_normalized in {"gastos_adjuntados", "editada"} and cuenta_estado == "abierta":
        return _post_action_cta_html(
            primary_href=f"/gastos/nuevo?cuenta_gastos_id={cuenta_id}",
            primary_label="Registrar otro gasto",
        )
    if success_code_normalized == "saldada":
        return _post_action_cta_html(
            primary_href="/informes-de-gastos",
            primary_label="Abrir otro informe",
        )
    if success_code_normalized == "cerrada":
        return _post_action_cta_html(
            primary_href="/informes-de-gastos/crear",
            primary_label="Crear otro informe",
        )
    return _post_action_cta_html(
        primary_href=f"/informes-de-gastos/{cuenta_id}",
        primary_label="Volver al informe",
    )


def extract_uuid_from_qr_or_url(text: str) -> Optional[str]:
    """
    Extract CFDI UUID from QR code text or URL.
    
    Mexico CFDI QR codes typically contain uuid=... parameter.
    Also handles direct UUID strings and various URL formats.
    
    Returns normalized UUID (uppercase, canonical) or None if not found.
    """
    if not text or not text.strip():
        return None
    
    text = text.strip()
    
    # Try to extract UUID from URL parameters (uuid=...)
    try:
        # Parse as URL
        parsed = urlparse(text)
        params = parse_qs(parsed.query)
        
        # Check for uuid parameter (case-insensitive)
        for key in params:
            if key.lower() == 'uuid':
                uuid_val = params[key][0] if params[key] else None
                if uuid_val:
                    # Validate and normalize UUID
                    try:
                        uuid_obj = UUIDType(uuid_val)
                        return str(uuid_obj).upper()
                    except ValueError:
                        pass
    except (AttributeError, TypeError, ValueError):
        pass
    
    # Try to find UUID pattern in text (standard UUID format: 8-4-4-4-12 hex digits)
    uuid_pattern = r'[0-9A-Fa-f]{8}-[0-9A-Fa-f]{4}-[0-9A-Fa-f]{4}-[0-9A-Fa-f]{4}-[0-9A-Fa-f]{12}'
    matches = re.findall(uuid_pattern, text)
    if matches:
        try:
            uuid_obj = UUIDType(matches[0])
            return str(uuid_obj).upper()
        except ValueError:
            pass
    
    # Try to parse as direct UUID
    try:
        uuid_obj = UUIDType(text)
        return str(uuid_obj).upper()
    except ValueError:
        pass
    
    return None


def format_value(value) -> str:
    """Format a value for display."""
    if value is None:
        return "-"
    if isinstance(value, datetime):
        return value.strftime("%Y-%m-%d")
    return str(value)


def format_currency(value, currency: str = "MXN") -> str:
    """Format a numeric value as currency."""
    code = normalize_currency(currency)
    symbol = {"MXN": "$", "USD": "US$", "EUR": "€"}.get(code, f"{code} ")
    if value is None:
        return f"{symbol}0.00"
    try:
        return f"{symbol}{float(value):,.2f}"
    except (ValueError, TypeError):
        return str(value)


def _currency_options(selected: str = "MXN") -> str:
    selected_code = normalize_currency(selected)
    codes = list(COMMON_CURRENCIES)
    if selected_code not in codes:
        codes.append(selected_code)
    return "".join(
        f'<option value="{code}"{" selected" if code == selected_code else ""}>{code}</option>'
        for code in codes
    )


def _currency_totals_html(totals: Dict[str, Decimal]) -> str:
    if not totals:
        totals = {"MXN": Decimal("0")}
    return "<br>".join(
        f"{escape(code)}: {format_currency(amount, code)}"
        for code, amount in sorted(totals.items())
    )


def _format_empleado_display_name(empleado) -> str:
    """Return a resilient display label for Empleado-like objects."""
    nombre = getattr(empleado, "nombre", None) or ""
    apellido = getattr(empleado, "apellido", None) or ""
    full_name = f"{nombre} {apellido}".strip()
    if full_name:
        return full_name
    return (
        getattr(empleado, "correo", None)
        or getattr(empleado, "email", None)
        or "—"
    )


def _adjunto_meta_id(meta) -> Optional[UUIDType]:
    """Read attachment metadata ids across old/new metadata shapes."""
    return getattr(meta, "adjunto_id", None) or getattr(meta, "id", None)


def _render_auto_number_formatter_script(field_pairs: List[Dict[str, str]]) -> str:
    """Render a client-side formatter that keeps a raw numeric field in sync."""
    if not field_pairs:
        return ""

    field_pairs_json = json.dumps(field_pairs)
    return f"""
    <script>
        (function() {{
            const fieldPairs = {field_pairs_json};

            function normalizeRawValue(value) {{
                const rawValue = String(value || '');
                const cleanedValue = rawValue.replace(/,/g, '').replace(/[^\\d.]/g, '');
                if (!cleanedValue) {{
                    return '';
                }}

                const hasDecimalPoint = cleanedValue.includes('.');
                const parts = cleanedValue.split('.');
                const integerCandidate = (parts.shift() || '').replace(/^0+(?=\\d)/, '');
                const integerPart = integerCandidate || '0';
                const decimalPart = parts.join('').slice(0, 2);

                if (hasDecimalPoint) {{
                    return `${{integerPart}}.${{decimalPart}}`;
                }}

                return integerPart;
            }}

            function toFixedRawValue(rawValue) {{
                const normalizedRaw = normalizeRawValue(rawValue);
                if (!normalizedRaw) {{
                    return '';
                }}

                const [integerPartRaw, decimalPartRaw = ''] = normalizedRaw.split('.');
                const integerPart = integerPartRaw || '0';
                const decimalPart = (decimalPartRaw + '00').slice(0, 2);
                return `${{integerPart}}.${{decimalPart}}`;
            }}

            function formatDisplayValue(rawValue) {{
                if (!rawValue) {{
                    return '';
                }}

                const hasDecimalPoint = rawValue.includes('.');
                const [integerPartRaw, decimalPart = ''] = rawValue.split('.');
                const integerPart = integerPartRaw || '0';
                const formattedInteger = integerPart.replace(/\\B(?=(\\d{{3}})+(?!\\d))/g, ',');

                if (hasDecimalPoint) {{
                    return `${{formattedInteger}}.${{decimalPart}}`;
                }}

                return formattedInteger;
            }}

            function countNumericChars(value) {{
                return String(value || '').replace(/[^\\d.]/g, '').length;
            }}

            function mapRawCursorToFormatted(rawValue, rawCursorPos) {{
                if (rawCursorPos <= 0) {{
                    return 0;
                }}

                const formattedValue = formatDisplayValue(rawValue);
                let seenNumericChars = 0;

                for (let index = 0; index < formattedValue.length; index += 1) {{
                    if (/[0-9.]/.test(formattedValue[index])) {{
                        seenNumericChars += 1;
                    }}
                    if (seenNumericChars >= rawCursorPos) {{
                        return index + 1;
                    }}
                }}

                return formattedValue.length;
            }}

            function resolveCurrency(fieldPair) {{
                if (fieldPair.currency) {{
                    return fieldPair.currency;
                }}
                if (fieldPair.currencySelectName) {{
                    const currencySelect = document.querySelector(
                        `select[name="${{fieldPair.currencySelectName}}"]`
                    );
                    if (currencySelect) {{
                        return currencySelect.value || 'MXN';
                    }}
                }}
                if (fieldPair.currencyInputId) {{
                    const currencyInput = document.getElementById(fieldPair.currencyInputId);
                    if (currencyInput) {{
                        return (currencyInput.value || 'MXN').trim();
                    }}
                }}
                return 'MXN';
            }}

            fieldPairs.forEach(function(fieldPair) {{
                const displayInput = document.getElementById(fieldPair.displayId);
                const rawInput = document.getElementById(fieldPair.rawId);
                const wordsPreview = fieldPair.wordsPreviewId
                    ? document.getElementById(fieldPair.wordsPreviewId)
                    : null;
                let wordsPreviewTimer = null;
                let wordsPreviewRequestId = 0;

                if (!displayInput || !rawInput) {{
                    return;
                }}

                function syncWordsPreview(rawValue) {{
                    if (!wordsPreview) {{
                        return;
                    }}

                    const normalizedRaw = normalizeRawValue(rawValue);
                    if (wordsPreviewTimer) {{
                        window.clearTimeout(wordsPreviewTimer);
                    }}

                    if (!normalizedRaw) {{
                        wordsPreview.value = '';
                        return;
                    }}

                    const requestId = ++wordsPreviewRequestId;
                    const currency = resolveCurrency(fieldPair);
                    wordsPreviewTimer = window.setTimeout(function() {{
                        fetch(`/api/cantidad-en-letra?monto=${{encodeURIComponent(normalizedRaw)}}&currency=${{encodeURIComponent(currency)}}`, {{
                            headers: {{
                                Accept: 'application/json'
                            }}
                        }})
                            .then(function(response) {{
                                if (!response.ok) {{
                                    throw new Error('Preview request failed');
                                }}
                                return response.json();
                            }})
                            .then(function(payload) {{
                                if (requestId === wordsPreviewRequestId) {{
                                    wordsPreview.value = payload.text || '';
                                }}
                            }})
                            .catch(function() {{
                                if (requestId === wordsPreviewRequestId) {{
                                    wordsPreview.value = '';
                                }}
                            }});
                    }}, 120);
                }}

                function syncFromDisplay(forceFixedDecimals) {{
                    const cursorPosition = displayInput.selectionStart || 0;
                    const rawCursorPos = countNumericChars(displayInput.value.slice(0, cursorPosition));
                    const normalizedRaw = normalizeRawValue(displayInput.value);
                    const nextRawValue = forceFixedDecimals ? toFixedRawValue(normalizedRaw) : normalizedRaw;
                    const formattedDisplay = formatDisplayValue(nextRawValue);

                    rawInput.value = nextRawValue;
                    displayInput.value = formattedDisplay;
                    syncWordsPreview(nextRawValue);

                    if (!forceFixedDecimals && document.activeElement === displayInput) {{
                        const nextCursorPos = mapRawCursorToFormatted(nextRawValue, rawCursorPos);
                        displayInput.setSelectionRange(nextCursorPos, nextCursorPos);
                    }}
                }}

                displayInput.addEventListener('input', function() {{
                    syncFromDisplay(false);
                }});
                displayInput.addEventListener('blur', function() {{
                    syncFromDisplay(true);
                }});

                if (displayInput.form) {{
                    displayInput.form.addEventListener('submit', function() {{
                        syncFromDisplay(true);
                    }});
                }}

                if (rawInput.value) {{
                    const fixedRawValue = toFixedRawValue(rawInput.value);
                    rawInput.value = fixedRawValue;
                    displayInput.value = formatDisplayValue(fixedRawValue);
                    syncWordsPreview(fixedRawValue);
                }} else if (displayInput.value) {{
                    syncFromDisplay(true);
                }} else if (wordsPreview) {{
                    wordsPreview.value = '';
                }}

                if (fieldPair.currencySelectName) {{
                    const currencySelect = document.querySelector(
                        `select[name="${{fieldPair.currencySelectName}}"]`
                    );
                    if (currencySelect) {{
                        currencySelect.addEventListener('change', function() {{
                            syncWordsPreview(rawInput.value);
                        }});
                    }}
                }}
            }});
        }})();
    </script>
    """


@router.get("/api/cantidad-en-letra", response_class=JSONResponse)
async def api_cantidad_en_letra(
    monto: Optional[str] = Query(None),
    currency: Optional[str] = Query("MXN"),
    current_empleado: Empleado = Depends(get_current_empleado),
) -> JSONResponse:
    raw_monto = (monto or "").strip()
    if not raw_monto:
        return JSONResponse(content={"text": ""})

    try:
        text_value = _cantidad_en_letra(float(raw_monto), currency=currency or "MXN")
    except (TypeError, ValueError):
        text_value = ""

    return JSONResponse(content={"text": text_value})


_RESTAURANT_KEYWORDS = (
    "restaurante",
    "restaurant",
    "cafeteria",
    "cafetería",
    "cafe",
    "bar",
    "comida",
    "alimento",
    "consumo",
)


def _is_restaurant_concept(concepto: Optional[str]) -> bool:
    if not concepto:
        return False
    lower = concepto.lower()
    return any(k in lower for k in _RESTAURANT_KEYWORDS)


def _classify_cfdi_match(
    gasto_total: float,
    cfdi_total: float,
    concepto: Optional[str] = None,
) -> tuple[str, float]:
    """
    Classify CFDI vs gasto matching.

    Returns:
        (status, delta)
        status in {"exact", "tip_tolerated", "mismatch"}
    """
    delta = round(float(gasto_total or 0) - float(cfdi_total or 0), 2)
    abs_delta = abs(delta)

    if abs_delta <= 1.0:
        return "exact", delta

    # Restaurants can include tip in card charge while CFDI excludes it.
    if delta > 0 and _is_restaurant_concept(concepto):
        tip_cap = max(30.0, round(float(gasto_total or 0) * 0.18, 2))
        if delta <= tip_cap:
            return "tip_tolerated", delta

    return "mismatch", delta


def get_documento_display_info(expense: ExpenseReport) -> tuple[str, str]:
    """
    Get display information for Solicitud and Informe columns.
    
    Returns:
        tuple: (solicitud_html, informe_html) - HTML strings for each column
    """
    from html import escape
    
    solicitud_html = "—"
    informe_html = "—"
    
    # First, check explicit fields
    solicitud_doc = getattr(expense, 'solicitud_documento', None)
    informe_doc = getattr(expense, 'informe_documento', None)
    
    if solicitud_doc:
        # Format: numero_referencia (full UUID in tooltip)
        solicitud_html = f'<a href="/documentos/{solicitud_doc.id}" style="color: #4CAF50; text-decoration: none;" title="{solicitud_doc.id}">{escape(solicitud_doc.numero_referencia)}</a>'
    
    if informe_doc:
        # Format: numero_referencia (full UUID in tooltip)
        informe_html = f'<a href="/documentos/{informe_doc.id}" style="color: #4CAF50; text-decoration: none;" title="{informe_doc.id}">{escape(informe_doc.numero_referencia)}</a>'
    
    # Backwards compatibility: if explicit fields are NULL but documento_id exists
    if (not solicitud_doc and not informe_doc) and expense.documento_id:
        # We need to load the documento to check its tipo
        # This should be loaded via selectinload in the query
        documento = getattr(expense, 'documento', None)
        if documento:
            doc_link = f'<a href="/documentos/{documento.id}" style="color: #4CAF50; text-decoration: none;" title="{documento.id}">{escape(documento.numero_referencia)}</a>'
            
            if documento.tipo == 'SOLICITUD':
                solicitud_html = doc_link
            elif documento.tipo == 'INFORME':
                informe_html = doc_link
    
    return solicitud_html, informe_html


def determine_redirect_url(next_param: Optional[str], documento_id: UUIDType, default_to_detail: bool = True) -> str:
    """
    Determine the redirect URL after an action.
    
    Args:
        next_param: The 'next' parameter from query string or form
        documento_id: The documento ID (used for detail page fallback)
        default_to_detail: If True, defaults to documento detail page; if False, defaults to /panel
    
    Returns:
        Redirect URL string
    """
    next_url = _safe_internal_redirect_url(next_param)
    if next_url:
        return next_url
    
    # Default redirect
    if default_to_detail:
        return f"/documentos/{documento_id}"
    else:
        return "/panel"


def _safe_internal_redirect_url(next_param: Optional[str]) -> Optional[str]:
    if not next_param:
        return None
    next_url = unquote(next_param).strip()
    if next_url.startswith("/") and not next_url.startswith("//"):
        return next_url
    return None


def _is_documentos_pendientes_queue_path(next_param: Optional[str]) -> bool:
    next_url = _safe_internal_redirect_url(next_param)
    if not next_url:
        return False
    return urlparse(next_url).path == "/documentos/pendientes"


async def _find_next_documento_pendiente_url(
    session: AsyncSession,
    *,
    current_empleado: Empleado,
    current_documento_id: UUIDType,
) -> Optional[str]:
    if current_empleado.rol in ("superadmin", "super_admin"):
        query = (
            select(Documento.id)
            .where(
                and_(
                    Documento.estado == "enviado",
                    Documento.id != current_documento_id,
                )
            )
            .order_by(
                Documento.enviado_en.desc().nulls_last(),
                Documento.creado_en.desc(),
            )
        )
    else:
        query = (
            select(Documento.id)
            .join(Empleado, Documento.empleado_id == Empleado.id)
            .where(
                and_(
                    Documento.estado == "enviado",
                    Documento.id != current_documento_id,
                    or_(
                        Empleado.aprobador_id == current_empleado.id,
                        Empleado.aprobador_id.is_(None),
                    ),
                )
            )
            .order_by(
                Documento.enviado_en.desc().nulls_last(),
                Documento.creado_en.desc(),
            )
        )

    result = await session.execute(query.limit(1))
    next_documento_id = result.scalar_one_or_none()
    if next_documento_id is None:
        return None
    return (
        f"/documentos/{next_documento_id}"
        f"?next={quote('/documentos/pendientes')}"
    )


async def _resolve_documento_queue_redirect_url(
    session: AsyncSession,
    *,
    current_empleado: Empleado,
    current_documento_id: UUIDType,
    next_param: Optional[str],
    default_to_detail: bool = True,
) -> str:
    if _is_documentos_pendientes_queue_path(next_param):
        next_documento_url = await _find_next_documento_pendiente_url(
            session,
            current_empleado=current_empleado,
            current_documento_id=current_documento_id,
        )
        if next_documento_url:
            return next_documento_url
    return determine_redirect_url(
        next_param,
        current_documento_id,
        default_to_detail=default_to_detail,
    )


class _CustomerSuccessHeartbeatRequest:
    def __init__(
        self,
        *,
        session_key: str,
        page_path: str,
        page_title: Optional[str] = None,
        page_url: Optional[str] = None,
        tournament_id: Optional[str] = None,
        tournament_name: Optional[str] = None,
        customer_label: Optional[str] = None,
        observed_at: Optional[str] = None,
    ):
        self.session_key = session_key
        self.page_path = page_path
        self.page_title = page_title
        self.page_url = page_url
        self.tournament_id = tournament_id
        self.tournament_name = tournament_name
        self.customer_label = customer_label
        self.observed_at = observed_at


def _parse_customer_success_heartbeat_payload(payload: Dict[str, Any]) -> _CustomerSuccessHeartbeatRequest:
    session_key = str(payload.get("session_key") or "").strip()
    page_path = str(payload.get("page_path") or "").strip()
    if not session_key or not page_path:
        raise HTTPException(status_code=400, detail="session_key and page_path are required")
    return _CustomerSuccessHeartbeatRequest(
        session_key=session_key[:120],
        page_path=page_path[:400],
        page_title=str(payload.get("page_title") or "").strip()[:300] or None,
        page_url=str(payload.get("page_url") or "").strip()[:600] or None,
        tournament_id=str(payload.get("tournament_id") or "").strip()[:120] or None,
        tournament_name=str(payload.get("tournament_name") or "").strip()[:220] or None,
        customer_label=str(payload.get("customer_label") or "").strip()[:160] or None,
        observed_at=str(payload.get("observed_at") or "").strip() or None,
    )


@router.post("/api/customer-success/heartbeat", response_class=JSONResponse)
async def api_customer_success_heartbeat(
    request: Request,
    session: AsyncSession = Depends(get_db_session),
    current_empleado: Empleado = Depends(get_current_empleado),
) -> JSONResponse:
    payload = await request.json()
    parsed = _parse_customer_success_heartbeat_payload(payload if isinstance(payload, dict) else {})
    observed_at = None
    if parsed.observed_at:
        try:
            normalized = parsed.observed_at.replace("Z", "+00:00")
            observed_at = datetime.fromisoformat(normalized)
        except ValueError:
            observed_at = None
    result = await record_customer_success_usage_heartbeat(
        session,
        empleado_id=str(current_empleado.id),
        session_key=parsed.session_key,
        page_path=parsed.page_path,
        page_title=parsed.page_title,
        page_url=parsed.page_url,
        tournament_id=parsed.tournament_id,
        tournament_name=parsed.tournament_name,
        customer_label=parsed.customer_label,
        observed_at=observed_at,
    )
    return JSONResponse(content=result)


async def generate_documento_reference_number(
    session: AsyncSession,
    tipo: str,
    empleado_id: UUIDType
) -> str:
    """Compatibility wrapper around the shared documento reference allocator."""
    return await service_generate_documento_reference_number(session, tipo, empleado_id)


