@router.post("/panel/telegram-console/enviar-pendientes")
async def panel_telegram_console_send_pending(
    current_empleado: Empleado = Depends(get_current_empleado),
    session: AsyncSession = Depends(get_db_session),
) -> RedirectResponse:
    """Send pending Telegram outbox notifications (finanzas/admin)."""
    role = (current_empleado.rol or "").strip().lower()
    if role not in OUTBOX_CONSOLE_ROLES:
        raise HTTPException(status_code=403, detail="Sin permiso para enviar notificaciones")

    stats = await flush_pending_outbox_notifications(session)
    return RedirectResponse(
        url=(
            "/panel/telegram-console"
            f"?flush_sent={stats['sent']}&flush_failed={stats['failed']}"
        ),
        status_code=303,
    )


