@router.post("/panel/mi-telegram")
async def panel_mi_telegram_post(
    request: Request,
    session: AsyncSession = Depends(get_db_session),
    current_empleado: Empleado = Depends(get_current_empleado),
    telegram_user_id: Optional[str] = Form(None),
) -> RedirectResponse:
    """Update own telegram_user_id (nullable)."""
    parsed, err = _parse_telegram_user_id_self_service(telegram_user_id)
    if err:
        return RedirectResponse(
            url=f"/panel/mi-telegram?error_msg={quote(err)}",
            status_code=303,
        )

    if parsed is not None:
        dup = await session.execute(
            text(
                """
                SELECT id FROM empleados
                WHERE telegram_user_id = :tid AND id != :eid
                LIMIT 1
                """
            ),
            {"tid": parsed, "eid": current_empleado.id},
        )
        if dup.fetchone():
            dup_msg = (
                "Ese ID de Telegram ya está asignado a otro empleado. "
                "Si es un error, contacta a un administrador."
            )
            return RedirectResponse(
                url=f"/panel/mi-telegram?error_msg={quote(dup_msg)}",
                status_code=303,
            )

    await session.execute(
        text(
            """
            UPDATE empleados
            SET telegram_user_id = :tid, actualizado_en = NOW()
            WHERE id = :eid
            """
        ),
        {"tid": parsed, "eid": current_empleado.id},
    )
    await session.commit()
    logger.info(
        "Self-service telegram_user_id updated for empleado %s -> %s",
        current_empleado.id,
        parsed,
    )
    return RedirectResponse(url="/panel/mi-telegram?ok=1", status_code=303)


@router.post("/panel/cambiar-contrasena")
async def panel_cambiar_contrasena_post(
    request: Request,
    session: AsyncSession = Depends(get_db_session),
    current_empleado: Empleado = Depends(get_current_empleado),
    old_password: str = Form(...),
    password: str = Form(...),
    password_confirm: str = Form(...),
) -> RedirectResponse:
    """Apply self-service password change."""
    result = await session.execute(
        text("SELECT password_hash FROM empleados WHERE id = :id"),
        {"id": current_empleado.id},
    )
    row = result.fetchone()
    stored_hash = row[0] if row else None

    valid, err_msg = validate_self_service_password_change(
        old_password=old_password,
        new_password=password,
        new_confirm=password_confirm,
        stored_hash=stored_hash,
    )
    if not valid:
        return RedirectResponse(
            url=f"/panel/cambiar-contrasena?error_msg={quote(err_msg)}",
            status_code=303,
        )

    new_hash = get_password_hash(password.strip())
    await session.execute(
        text(
            "UPDATE empleados SET password_hash = :h, actualizado_en = NOW() WHERE id = :id"
        ),
        {"h": new_hash, "id": current_empleado.id},
    )
    await session.commit()
    logger.info("Self-service password updated for empleado %s", current_empleado.id)
    return RedirectResponse(url="/panel/cambiar-contrasena?ok=1", status_code=303)


@router.get("/panel/operaciones-console", response_class=HTMLResponse)
async def panel_operaciones_console(
    request: Request,
    session: AsyncSession = Depends(get_db_session),
    current_empleado: Empleado = Depends(get_current_empleado),
    tournament_id: Optional[str] = Query(None),
    drill_document: Optional[str] = Query(None),
) -> str:
    """Visible operations/folders console with operational and budget signals."""
    nav = render_top_navigation(current_empleado, "operacion")
    role_value = str(current_empleado.rol or "empleado")
    can_operate = role_value.lower() in {
        "coordinador",
        "admin",
        "superadmin",
        "super_admin",
        "finanzas",
    } or has_permission(current_empleado, "operations.folders.read")

    tournament_rows = (
        await session.execute(
            select(Tournament.id, Tournament.name).order_by(Tournament.name.asc())
        )
    ).all()
    tournaments = [
        {"id": str(row[0]), "name": str(row[1] or "")}
        for row in tournament_rows
    ]
    selected_tournament = None
    if tournament_id:
        selected_tournament = next(
            (item for item in tournaments if item["id"] == str(tournament_id)),
            None,
        )
    if selected_tournament is None and tournaments:
        selected_tournament = tournaments[0]

    snapshot_data: dict[str, Any] = {"summary": {}, "alerts": [], "budget": None}
    if can_operate and selected_tournament:
        result = await operations_folder_planner_snapshot_adapter(
            session,
            context=AssistantContext(
                tournament_id=selected_tournament["id"],
                tournament_name=selected_tournament["name"],
                edition="2026",
            ),
            payload={
                "tournament_id": selected_tournament["id"],
                "tournament_name": selected_tournament["name"],
                "edition_year": 2026,
                "limit": 120,
            },
        )
        snapshot_data = result.data or snapshot_data

    summary = snapshot_data.get("summary") or {}
    alerts = list(snapshot_data.get("alerts") or [])
    budget = snapshot_data.get("budget") or {}
    budget_forecast = budget.get("forecast") or {}
    budget_alerts = list(budget.get("executive_alerts") or [])
    top_alert = alerts[0] if alerts else {}
    top_budget_alert = budget_alerts[0] if budget_alerts else {}
    tournament_commitments = (
        await list_budget_tournament_commitments(
            session,
            edition_year=2026,
            tournament_id=selected_tournament["id"],
            tournament_name=selected_tournament["name"],
            tournament_code=None,
            limit=12,
        )
        if can_operate and selected_tournament
        else []
    )
    active_commitment = next(
        (
            item
            for item in tournament_commitments
            if str(item.get("documento_id") or "") == str(drill_document or "")
        ),
        None,
    )
    active_commitment_expense = build_budget_commitment_expense_preview(active_commitment)
    selected_tournament_name = selected_tournament["name"] if selected_tournament else "Sin torneo"

    filter_chips = [
        f'<span class="ops-filter-chip">Torneo · {escape(selected_tournament_name)}</span>',
        (
            f'<span class="ops-filter-chip">Documento · {escape(str(active_commitment.get("numero_referencia") or "-"))}</span>'
            if active_commitment
            else '<span class="ops-filter-chip ops-filter-chip-muted">Documento · ninguno fijado</span>'
        ),
        (
            '<span class="ops-filter-chip">Permiso · operativo</span>'
            if can_operate
            else '<span class="ops-filter-chip ops-filter-chip-muted">Permiso · sin scope explícito</span>'
        ),
        f'<span class="ops-filter-chip ops-filter-chip-muted">Edición · 2026</span>',
    ]

    tournament_options = "".join(
        f'<option value="{escape(item["id"])}" {"selected" if selected_tournament and item["id"] == selected_tournament["id"] else ""}>{escape(item["name"])}</option>'
        for item in tournaments
    )
    commitment_rows = "".join(
        f"""
        <tr>
            <td><a href="/panel/operaciones-console?tournament_id={quote(str(selected_tournament['id']))}&drill_document={quote(str(item.get('documento_id') or ''))}" style="color:#0f172a;text-decoration:none;font-weight:700;">{escape(str(item.get("numero_referencia") or "-"))}</a></td>
            <td><span class="ops-pill">{escape(str(item.get("estado") or "-"))}</span></td>
            <td>{escape(str(item.get("proveedor_nombre") or "-"))}</td>
            <td>{escape(str(item.get("concepto_pago") or "-"))}</td>
            <td>${float(item.get("monto_total") or 0):,.2f}<div class="ops-cell-sub">{escape(str(item.get("estado") or "-"))}</div></td>
            <td>{int(item.get("related_expense_count") or 0)}<div class="ops-cell-sub">${float(item.get("related_expense_total") or 0):,.2f}</div></td>
            <td>{
                f'<a href="{escape(str(build_budget_commitment_expense_preview(item).get("generated_expense_href") or ""))}" style="color:#1d4ed8;text-decoration:none;font-weight:700;">{escape(str(build_budget_commitment_expense_preview(item).get("generated_expense_reference") or "Ver gasto"))}</a>'
                if build_budget_commitment_expense_preview(item).get("generated_expense_href")
                else '<span style="color:#94a3b8;">Sin gasto</span>'
            }</td>
        </tr>
        """
        for item in tournament_commitments
    )
    active_commitment_html = (
        f"""
        <div class="meta-grid">
            <div class="meta-card">
                <span>Documento</span>
                <strong style="font-size:1rem;">{escape(str(active_commitment.get("numero_referencia") or "-"))}</strong>
                <small>{escape(str(active_commitment.get("estado") or "-"))} · {escape(str(active_commitment.get("proveedor_nombre") or "-"))}</small>
            </div>
            <div class="meta-card">
                <span>Compromiso</span>
                <strong style="font-size:1rem;">${float(active_commitment.get("monto_total") or 0):,.2f}</strong>
                <small>{escape(str(active_commitment.get("concepto_pago") or "Sin concepto"))}</small>
            </div>
            <div class="meta-card">
                <span>Gastos relacionados</span>
                <strong style="font-size:1rem;">{int(active_commitment_expense.get("related_expense_count") or 0)}</strong>
                <small>${float(active_commitment_expense.get("related_expense_total") or 0):,.2f} · último {escape(str(active_commitment_expense.get("related_expense_latest_date") or "-"))}</small>
            </div>
            <div class="meta-card">
                <span>Gasto generado</span>
                <strong style="font-size:1rem;">{escape(str(active_commitment_expense.get("generated_expense_reference") or "Sin gasto"))}</strong>
                <small>{escape(str(active_commitment_expense.get("generated_expense_state") or "pendiente"))}</small>
            </div>
        </div>
        <div style="display:flex;flex-wrap:wrap;gap:8px;margin-top:12px;">
            <a href="/documentos/{escape(str(active_commitment.get('documento_id') or ''))}" class="button secondary">Abrir documento</a>
            {f'<a href="{escape(str(active_commitment_expense.get("generated_expense_href") or ""))}" class="button primary">Ver gasto generado</a>' if active_commitment_expense.get("generated_expense_href") else ''}
        </div>
        """
        if active_commitment
        else '<div class="section-note">Selecciona un compromiso del torneo para fijar la navegación hacia documento y gasto.</div>'
    )
    quick_cards_html = "".join(
        [
            f"""
            <div class="ops-stat-card ops-stat-card-primary">
                <div class="ops-stat-label">Compromisos abiertos</div>
                <div class="ops-stat-value">{int(summary.get("commitments_count") or 0)}</div>
                <div class="ops-stat-note">Incluye pagos, cobros, riesgos y tareas de carpeta registradas.</div>
            </div>
            """,
            f"""
            <div class="ops-stat-card ops-stat-card-danger">
                <div class="ops-stat-label">Vencidos</div>
                <div class="ops-stat-value">{int(summary.get("overdue_open_count") or 0)}</div>
                <div class="ops-stat-note">Compromisos abiertos con fecha ya rebasada.</div>
            </div>
            """,
            f"""
            <div class="ops-stat-card ops-stat-card-warning">
                <div class="ops-stat-label">Próximos 30 días</div>
                <div class="ops-stat-value">{int(summary.get("due_next_30_open_count") or 0)}</div>
                <div class="ops-stat-note">Carpetas con entregable o pago/cobro cercano.</div>
            </div>
            """,
            f"""
            <div class="ops-stat-card ops-stat-card-info">
                <div class="ops-stat-label">Salud presupuesto</div>
                <div class="ops-stat-value">{escape(str(budget_forecast.get("health") or "sin dato"))}</div>
                <div class="ops-stat-note">Lectura ejecutiva traída del snapshot presupuestal canónico.</div>
            </div>
            """,
        ]
    )
    spotlight_cards = "".join(
        [
            f"""
            <div class="ops-spotlight-card">
                <div class="ops-spotlight-label">Compromiso fijado</div>
                <div class="ops-spotlight-title">{escape(str(active_commitment.get("numero_referencia") or "Sin selección")) if active_commitment else "Sin selección"}</div>
                <div class="ops-spotlight-meta">{escape(str(active_commitment.get("proveedor_nombre") or "Ningún proveedor")) if active_commitment else "Selecciona un documento para fijar la navegación."}</div>
            </div>
            """,
            f"""
            <div class="ops-spotlight-card">
                <div class="ops-spotlight-label">Playbook principal</div>
                <div class="ops-spotlight-title">{escape(str(top_budget_alert.get("title") or "Sin alerta"))}</div>
                <div class="ops-spotlight-meta">{escape(str(top_budget_alert.get("playbook") or "No hay playbook presupuestal activo."))}</div>
            </div>
            """,
            f"""
            <div class="ops-spotlight-card">
                <div class="ops-spotlight-label">Riesgo operativo líder</div>
                <div class="ops-spotlight-title">{escape(str(top_alert.get("title") or "Sin alertas"))}</div>
                <div class="ops-spotlight-meta">{escape(str(top_alert.get("detail") or "No hay alertas de carpetas activas."))}</div>
            </div>
            """,
            f"""
            <div class="ops-spotlight-card">
                <div class="ops-spotlight-label">Gasto generado</div>
                <div class="ops-spotlight-title">{escape(str(active_commitment_expense.get("generated_expense_reference") or "Sin gasto"))}</div>
                <div class="ops-spotlight-meta">{escape(str(active_commitment_expense.get("generated_expense_state") or "pendiente"))} · {int(active_commitment_expense.get("related_expense_count") or 0)} relacionados</div>
            </div>
            """,
        ]
    )
    operational_alert_rows = "".join(
        f"""
        <tr>
            <td><span class="status-chip {escape(str(item.get("severity") or "info"))}">{escape(str(item.get("severity") or "info"))}</span></td>
            <td>{escape(str(item.get("title") or ""))}</td>
            <td>{escape(str(item.get("detail") or "—"))}</td>
        </tr>
        """
        for item in alerts[:20]
    )
    budget_alert_cards = "".join(
        f"""
        <div class="alert-card severity-{escape(str(item.get("severity") or "info"))}">
            <strong>{escape(str(item.get("title") or ""))}</strong>
            <p>{escape(str(item.get("detail") or ""))}</p>
            <small>{escape(str(item.get("playbook") or ""))}</small>
        </div>
        """
        for item in budget_alerts
    )

    hero_actions = """
        <a href="/panel" class="button secondary">Volver al panel</a>
    """
    side_html = f"""
        <div class="eyebrow">Slice</div>
        <div style="font-size:20px;font-weight:800;letter-spacing:-.03em;color:var(--shell-ink);">Carpetas / operaciones</div>
        <div class="section-note" style="margin-top:8px;">Lectura visible de compromisos operativos y presión presupuestal sobre el mismo torneo.</div>
        <div class="meta-grid" style="margin-top:14px;">
            <div class="meta-card">
                <span>Torneo</span>
                <strong style="font-size:1rem;">{escape(selected_tournament["name"] if selected_tournament else "Sin torneo")}</strong>
                <small>Scope activo para esta lectura.</small>
            </div>
            <div class="meta-card">
                <span>Rol</span>
                <strong style="font-size:1rem;">{escape(role_value)}</strong>
                <small>{'Puede operar y leer carpetas.' if can_operate else 'Sin permisos explícitos de carpetas.'}</small>
            </div>
        </div>
    """

    empty_state = ""
    if not can_operate:
        empty_state = """
            <div class="notice warn" style="margin-bottom:16px;">
                Tu sesión no tiene permisos explícitos de carpetas/operaciones. La consola queda visible como punto de entrada, pero sin snapshot operativo.
            </div>
        """
    elif not selected_tournament:
        empty_state = """
            <div class="notice warn" style="margin-bottom:16px;">
                No hay torneos disponibles todavía para construir la lectura operativa.
            </div>
        """

    html = f"""
    <!DOCTYPE html>
    <html>
    <head>
        <title>Consola Operaciones - Copa Telmex</title>
        <meta name="viewport" content="width=device-width, initial-scale=1.0">
        <meta charset="utf-8">
        <style>
            {_workspace_shell_styles("1180px")}
        .alert-grid {{
                display:grid;
                grid-template-columns:repeat(auto-fit, minmax(240px, 1fr));
                gap:10px;
            }}
            .ops-toolbar {{
                display:grid;
                gap:16px;
                margin-bottom:18px;
            }}
            .ops-filter-strip {{
                display:flex;
                gap:8px;
                flex-wrap:wrap;
            }}
            .ops-filter-chip {{
                display:inline-flex;
                align-items:center;
                padding:8px 12px;
                border-radius:999px;
                background:#e2f3ee;
                color:#0f766e;
                font-size:12px;
                font-weight:700;
                border:1px solid rgba(15,118,110,.12);
            }}
            .ops-filter-chip-muted {{
                background:#fff;
                color:#64748b;
                border-color:#dbe2ea;
            }}
            .ops-control-card {{
                border:1px solid var(--shell-line);
                border-radius:22px;
                background:linear-gradient(180deg,#ffffff 0%,#f8fafc 100%);
                box-shadow:0 12px 30px rgba(15,23,42,.06);
                padding:18px;
            }}
            .ops-control-head {{
                display:flex;
                justify-content:space-between;
                align-items:flex-end;
                gap:16px;
                flex-wrap:wrap;
                margin-bottom:14px;
            }}
            .ops-control-head h2 {{
                margin:0;
                font-size:1.05rem;
                letter-spacing:-.02em;
            }}
            .ops-control-head p {{
                margin:6px 0 0;
                color:var(--shell-muted);
                font-size:13px;
                line-height:1.55;
            }}
            .ops-filter-grid {{
                display:grid;
                grid-template-columns:repeat(auto-fit,minmax(180px,1fr));
                gap:12px;
                align-items:end;
            }}
            .ops-filter-grid label {{
                display:block;
                margin-bottom:6px;
                color:#475569;
                font-size:12px;
                font-weight:700;
            }}
            .ops-action-cluster {{
                display:flex;
                gap:8px;
                flex-wrap:wrap;
                align-items:flex-end;
            }}
            .ops-stat-grid {{
                display:grid;
                grid-template-columns:repeat(auto-fit,minmax(220px,1fr));
                gap:14px;
            }}
            .ops-stat-card {{
                border-radius:20px;
                padding:18px;
                color:#fff;
                box-shadow:0 14px 28px rgba(15,23,42,.10);
            }}
            .ops-stat-card-primary {{ background:linear-gradient(135deg,#0f766e,#14b8a6); }}
            .ops-stat-card-danger {{ background:linear-gradient(135deg,#991b1b,#ef4444); }}
            .ops-stat-card-warning {{ background:linear-gradient(135deg,#b45309,#f59e0b); }}
            .ops-stat-card-info {{ background:linear-gradient(135deg,#1d4ed8,#38bdf8); }}
            .ops-stat-label {{
                font-size:11px;
                text-transform:uppercase;
                letter-spacing:.14em;
                opacity:.82;
            }}
            .ops-stat-value {{
                margin-top:10px;
                font-size:2rem;
                font-weight:800;
                letter-spacing:-.04em;
            }}
            .ops-stat-note {{
                margin-top:8px;
                font-size:12px;
                line-height:1.5;
                opacity:.82;
            }}
            .ops-spotlight-grid {{
                display:grid;
                grid-template-columns:repeat(auto-fit,minmax(220px,1fr));
                gap:14px;
            }}
            .ops-spotlight-card {{
                border:1px solid var(--shell-line);
                border-radius:18px;
                background:#fff;
                padding:16px;
                box-shadow:0 10px 24px rgba(15,23,42,.04);
            }}
            .ops-spotlight-label {{
                font-size:11px;
                text-transform:uppercase;
                letter-spacing:.12em;
                color:#64748b;
            }}
            .ops-spotlight-title {{
                margin-top:10px;
                font-size:1.15rem;
                font-weight:800;
                letter-spacing:-.03em;
                color:#0f172a;
            }}
            .ops-spotlight-meta {{
                margin-top:8px;
                font-size:12px;
                line-height:1.55;
                color:#475569;
            }}
            .ops-table-shell table {{
                width:100%;
                border-collapse:separate;
                border-spacing:0;
            }}
            .ops-table-shell thead th {{
                font-size:11px;
                text-transform:uppercase;
                letter-spacing:.11em;
                color:#64748b;
                background:#f8fafc;
                border-bottom:1px solid #dbe2ea;
            }}
            .ops-table-shell th, .ops-table-shell td {{
                text-align:left;
                padding:14px 12px;
                vertical-align:top;
            }}
            .ops-table-shell tbody tr:nth-child(odd) {{
                background:rgba(248,250,252,.65);
            }}
            .ops-table-shell tbody tr:hover {{
                background:rgba(226,232,240,.55);
            }}
            .ops-pill {{
                display:inline-flex;
                align-items:center;
                padding:5px 9px;
                border-radius:999px;
                background:#eff6ff;
                color:#1d4ed8;
                font-size:11px;
                font-weight:700;
                border:1px solid rgba(29,78,216,.10);
            }}
            .ops-cell-sub {{
                margin-top:4px;
                font-size:12px;
                color:#64748b;
                line-height:1.45;
            }}
            .alert-card {{
                background:#fff;
                border:1px solid var(--shell-line);
                border-radius:16px;
                padding:14px;
            }}
            .alert-card strong {{
                display:block;
                margin-bottom:6px;
                font-size:.95rem;
            }}
            .alert-card p {{
                margin:0 0 8px;
                color:var(--shell-muted);
                font-size:.88rem;
                line-height:1.35;
            }}
            .alert-card small {{
                color:#475569;
                line-height:1.35;
                display:block;
            }}
            .severity-critical {{ border-left:4px solid #b91c1c; }}
            .severity-warning {{ border-left:4px solid #d97706; }}
            .severity-info {{ border-left:4px solid #2563eb; }}
            .status-chip.critical {{ background:#fee2e2;color:#991b1b; }}
            .status-chip.warning {{ background:#fef3c7;color:#92400e; }}
            .status-chip.info {{ background:#dbeafe;color:#1d4ed8; }}
        </style>
    </head>
    <body>
        <div class="container">
            {nav}
            {_render_workspace_hero(
                eyebrow="Operaciones",
                title="Consola de Operaciones",
                description="Superficie visible para carpetas y seguimiento operativo. Junta alertas de compromisos, responsables y vencimientos con la lectura ejecutiva de presupuesto del mismo torneo.",
                actions_html=hero_actions,
                side_html=side_html,
            )}
            <div class="stack">
                {empty_state}
                <div class="ops-toolbar">
                    <div class="ops-filter-strip">
                        {"".join(filter_chips)}
                    </div>
                    <section class="ops-control-card">
                        <div class="ops-control-head">
                            <div>
                                <h2>Pulso ejecutivo</h2>
                                <p>Vista inspirada en ExpenseDesk: KPIs arriba, foco táctico al centro y drilldown operativo abajo.</p>
                            </div>
                        </div>
                        <form method="GET" action="/panel/operaciones-console">
                            <div class="ops-filter-grid">
                                <div>
                                    <label>Torneo</label>
                                    <select name="tournament_id">
                                        {tournament_options or '<option value="">Sin torneos</option>'}
                                    </select>
                                </div>
                                <div class="ops-action-cluster">
                                    <button type="submit" class="button primary">Cargar lectura</button>
                                    <a href="/panel/operaciones-console" class="button secondary">Limpiar</a>
                                </div>
                            </div>
                        </form>
                    </section>
                </div>
                <section class="surface">
                    <div class="section-head">
                        <div>
                            <h2>Resumen ejecutivo</h2>
                            <div class="section-note">Lectura rápida de carpetas y presupuesto para dirección y operaciones.</div>
                        </div>
                    </div>
                    <div class="ops-stat-grid">
                        {quick_cards_html}
                    </div>
                </section>
                <section class="surface">
                    <div class="section-head">
                        <div>
                            <h2>Spotlight</h2>
                            <div class="section-note">Los cuatro focos que más rápido explican el torneo activo: compromiso, playbook, riesgo y gasto generado.</div>
                        </div>
                    </div>
                    <div class="ops-spotlight-grid">
                        {spotlight_cards}
                    </div>
                </section>
                <section class="surface">
                    <div class="section-head">
                        <div>
                            <h2>Playbooks de presupuesto</h2>
                            <div class="section-note">Estas alertas salen del snapshot canónico de presupuesto; no son una interpretación paralela de la UI.</div>
                        </div>
                    </div>
                    <div class="alert-grid">
                        {budget_alert_cards or '<div class="meta-card"><span>Sin alertas</span><strong style="font-size:1rem;">Presupuesto estable</strong><small>No hay playbooks activos para el torneo seleccionado.</small></div>'}
                    </div>
                </section>
                <section class="surface">
                    <div class="section-head">
                        <div>
                            <h2>Compromisos del torneo</h2>
                            <div class="section-note">Mismo drilldown presupuestal ya cerrado en admin, ahora visible en operaciones para navegar de torneo a documento y gasto real.</div>
                        </div>
                    </div>
                    <div style="margin-bottom:14px;">
                        {active_commitment_html}
                    </div>
                    <div class="table-shell ops-table-shell">
                        <table>
                            <thead>
                                <tr>
                                    <th>Documento</th>
                                    <th>Estado</th>
                                    <th>Proveedor</th>
                                    <th>Concepto</th>
                                    <th>Total</th>
                                    <th>Gastos rel.</th>
                                    <th>Gasto generado</th>
                                </tr>
                            </thead>
                            <tbody>
                                {commitment_rows or '<tr><td colspan="7">Sin compromisos visibles para el torneo seleccionado.</td></tr>'}
                            </tbody>
                        </table>
                    </div>
                </section>
                <section class="surface">
                    <div class="section-head">
                        <div>
                            <h2>Alertas de carpetas</h2>
                            <div class="section-note">Vencimientos, riesgos y compromisos sin dueño tomados del planner snapshot operativo.</div>
                        </div>
                    </div>
                    <div class="table-shell ops-table-shell">
                        <table>
                            <thead>
                                <tr>
                                    <th>Severidad</th>
                                    <th>Alerta</th>
                                    <th>Detalle</th>
                                </tr>
                            </thead>
                            <tbody>
                                {operational_alert_rows or '<tr><td colspan="3">Sin alertas operativas activas.</td></tr>'}
                            </tbody>
                        </table>
                    </div>
                </section>
            </div>
        </div>
    </body>
    </html>
    """
    return html


@router.get("/panel", response_class=HTMLResponse)
async def panel(
    request: Request,
    session: AsyncSession = Depends(get_db_session),
    current_empleado: Empleado = Depends(get_current_empleado),
) -> str:
    """
    Main dashboard panel showing different sections based on user role.
    """
    nav = render_top_navigation(current_empleado, "panel")
    rol = current_empleado.rol or "empleado"

    def build_link_cards(items: list[tuple[str, str, str]], tone: str = "") -> str:
        return "".join(
            f"""
            <a href="{href}" class="action-card {tone}">
                <strong>{title}</strong>
                <p>{desc}</p>
            </a>
            """
            for href, title, desc in items
        )

    hero_actions_html = """
        <a href="/static/manual_usuario_gastos.pdf" target="_blank" class="button secondary">Manual PDF</a>
        <a href="https://drive.google.com/drive/u/0/folders/1cf-JOZodLSdZo-iiQrSsCwQtepatj7Gv" target="_blank" rel="noopener noreferrer" class="button secondary">Videos tutoriales</a>
    """
    hero_side_html = f"""
        <div class="eyebrow">Workspace</div>
        <div style="font-size:20px;font-weight:800;letter-spacing:-.03em;color:var(--shell-ink);">Panel de administración</div>
        <div class="section-note" style="margin-top:8px;">Entrada común para operación, solicitudes y gobierno del sistema sin cambiar de contexto.</div>
        <div class="meta-grid" style="margin-top:14px;">
            <div class="meta-card">
                <span>Rol activo</span>
                <strong style="font-size:1rem;">{escape(rol)}</strong>
                <small>Facultades heredadas del backend interno.</small>
            </div>
            <div class="meta-card">
                <span>Modo</span>
                <strong style="font-size:1rem;">Interno</strong>
                <small>Workspace compartido con React shell.</small>
            </div>
        </div>
    """

    entrenamiento_section = f"""
        <section class="surface">
            <div class="section-head">
                <div>
                    <div class="eyebrow">Entrenamiento</div>
                    <h2>Entrenamiento</h2>
                    <div class="section-note">Videos y guía de usuario para operación y finanzas.</div>
                </div>
            </div>
            <div class="action-grid">
                {build_link_cards([
                    ("https://drive.google.com/drive/u/0/folders/1cf-JOZodLSdZo-iiQrSsCwQtepatj7Gv", "Videos tutoriales", "Consulta los tutoriales en video del sistema."),
                    ("/static/manual_usuario_gastos.pdf", "Manual de usuario", "Descarga la guía del sistema para operación y finanzas."),
                ], "tone-slate")}
            </div>
        </section>
    """

    operaciones_section = f"""
        <section class="surface">
            <div class="section-head">
                <div>
                    <div class="eyebrow">Operaciones</div>
                    <h2>Gastos</h2>
                    <div class="section-note">Registro de gastos, informes y solicitudes.</div>
                </div>
            </div>
            <div class="action-grid">
                {build_link_cards([
                    ("/informes-de-gastos", "Informe de Gastos", "Administra solicitudes e informes."),
                    ("/gastos-terceros", "Solicitudes de transferencia", "Revisa solicitudes a proveedores o terceros."),
                ], "tone-blue")}
            </div>
        </section>
    """

    aprobaciones_section = ""
    if rol in ('finanzas', 'admin', 'superadmin', 'super_admin'):
        aprobaciones_links = [
            ("/documentos/pendientes", "Aprobaciones pendientes", "Valida solicitudes pendientes."),
            ("/documentos/historial-aprobador", "Historial de aprobaciones", "Consulta aprobaciones pasadas."),
        ]
        if rol in ('finanzas', 'admin', 'superadmin', 'super_admin'):
            aprobaciones_links.append(("/documentos/pendientes-pago", "Pagos pendientes", "Gestiona documentos listos para pago."))
        aprobaciones_section = f"""
            <section class="surface">
                <div class="section-head">
                    <div>
                        <div class="eyebrow">Operaciones</div>
                        <h2>Aprobaciones y pagos</h2>
                        <div class="section-note">Bandejas de revisión para no separar aprobación, pago y trazabilidad.</div>
                    </div>
                </div>
                <div class="action-grid">
                    {build_link_cards(aprobaciones_links, "tone-green")}
                </div>
            </section>
        """

    soporte_cards: list[tuple[str, str, str]] = [
        ("/soporte", "Mis tickets de soporte", "Consulta el estado de tus solicitudes."),
        ("/soporte/nuevo", "Abrir nuevo ticket", "Reporta una falla o pide ayuda al equipo."),
    ]
    if rol in ("superadmin", "super_admin"):
        soporte_cards.append(
            ("/admin/soporte", "Panel de soporte", "Triage y respuesta de los tickets recibidos.")
        )
    soporte_section = f"""
        <section class="surface">
            <div class="section-head">
                <div>
                    <div class="eyebrow">Soporte</div>
                    <h2>Ayuda y tickets</h2>
                    <div class="section-note">¿Algo no funciona o tienes una duda? Abre un ticket y el equipo lo atenderá.</div>
                </div>
            </div>
            <div class="action-grid">
                {build_link_cards(soporte_cards, "tone-amber")}
            </div>
        </section>
    """

    configuracion_cards: list[tuple[str, str, str]] = [
        ("/admin/proveedores-clientes", "Proveedores y clientes", "Gestionar catálogo comercial."),
    ]
