@router.get("/gastos/mis-gastos")
async def mis_gastos(
    request: Request,
    current_empleado: Empleado = Depends(get_current_empleado),
) -> RedirectResponse:
    """Deprecated: redirect legacy Mis gastos URL to Informes de Gastos."""
    url = "/informes-de-gastos"
    error_msg = (request.query_params.get("error_msg") or "").strip()
    error = (request.query_params.get("error") or "").strip()
    if error_msg or error:
        url = _append_error_params(
            url,
            error=error or None,
            error_msg=error_msg or None,
        )
    return RedirectResponse(url=url, status_code=303)


