@router.post("/admin/contabilidad/conciliacion/{movement_id}/link-aux")
async def contabilidad_conciliacion_link_aux(
    movement_id: UUIDType,
    aux_entry_id: UUIDType = Form(...),
    session: AsyncSession = Depends(get_db_session),
    current_empleado: Empleado = require_admin_finanzas(),
):
    movement_result = await session.execute(select(BankMovement).where(BankMovement.id == movement_id))
    movement = movement_result.scalar_one_or_none()
    if not movement:
        raise HTTPException(status_code=404, detail="Movimiento bancario no encontrado")

    aux_result = await session.execute(select(AuxLedgerEntry).where(AuxLedgerEntry.id == aux_entry_id))
    aux = aux_result.scalar_one_or_none()
    if not aux:
        raise HTTPException(status_code=404, detail="Auxiliar no encontrado")

    before_state = _movement_snapshot(movement)
    movement.matched_aux_entry_id = aux.id
    movement.related_poliza_id = aux.related_poliza_id
    movement.conciliacion_estado = _recompute_conciliacion_estado(movement)
    await _log_reconciliation_action(
        session,
        movement,
        current_empleado,
        "link_aux",
        before_state,
        {"aux_entry_id": str(aux.id), "related_poliza_id": str(aux.related_poliza_id) if aux.related_poliza_id else None},
    )
    await session.commit()
    return RedirectResponse(url=f"/admin/contabilidad/conciliacion/{movement_id}", status_code=303)


