@router.post("/admin/contabilidad/conciliacion/{movement_id}/link-proveedor")
async def contabilidad_conciliacion_link_proveedor(
    movement_id: UUIDType,
    proveedor_id: Optional[str] = Form(None),
    session: AsyncSession = Depends(get_db_session),
    current_empleado: Empleado = require_admin_finanzas(),
):
    movement_result = await session.execute(select(BankMovement).where(BankMovement.id == movement_id))
    movement = movement_result.scalar_one_or_none()
    if not movement:
        raise HTTPException(status_code=404, detail="Movimiento bancario no encontrado")

    proveedor = None
    if proveedor_id:
        if not is_valid_uuid(proveedor_id):
            raise HTTPException(status_code=400, detail="Proveedor inválido")
        proveedor_result = await session.execute(select(ProveedorCliente).where(ProveedorCliente.id == UUIDType(proveedor_id)))
        proveedor = proveedor_result.scalar_one_or_none()
        if not proveedor:
            raise HTTPException(status_code=404, detail="Proveedor no encontrado")

    before_state = _movement_snapshot(movement)
    movement.proveedor_cliente_id = proveedor.id if proveedor else None
    movement.conciliacion_estado = _recompute_conciliacion_estado(movement)
    await _log_reconciliation_action(
        session,
        movement,
        current_empleado,
        "link_proveedor",
        before_state,
        {"proveedor_id": str(proveedor.id) if proveedor else None, "proveedor_nombre": proveedor.nombre if proveedor else None},
    )
    await session.commit()
    return RedirectResponse(url=f"/admin/contabilidad/conciliacion/{movement_id}", status_code=303)


