@router.post("/documentos/nueva-solicitud")
async def crear_nueva_solicitud(
    request: Request,
    session: AsyncSession = Depends(get_db_session),
    current_empleado: Empleado = Depends(get_current_empleado),
    monto_solicitado: str = Form(...),
    proveedor_cliente_id: str = Form(...),
    torneo_id: Optional[str] = Form(None),
    fecha_pago: Optional[str] = Form(None),
    concepto_pago: str = Form(...),
    numero_factura: Optional[str] = Form(None),
    referencia_pago: Optional[str] = Form(None),
    fecha_inicio: Optional[str] = Form(None),
    fecha_fin: Optional[str] = Form(None),
    notas: Optional[str] = Form(None),
) -> RedirectResponse:
    """
    Create a new SOLICITUD (transfer request) without expenses.
    """
    # Validate monto_solicitado
    try:
        monto = float(monto_solicitado)
        if monto <= 0:
            return RedirectResponse(
                url=_append_error_params(
                    "/documentos/nueva-solicitud",
                    error="invalid_monto",
                    error_msg="El monto solicitado debe ser mayor a cero.",
                ),
                status_code=303
            )
    except ValueError:
        return RedirectResponse(
            url=_append_error_params(
                "/documentos/nueva-solicitud",
                error="invalid_monto",
                error_msg="El monto solicitado debe ser un número válido.",
            ),
            status_code=303
        )
    
    # Parse dates if provided
    fecha_inicio_dt = None
    fecha_fin_dt = None
    fecha_pago_dt = None
    if fecha_inicio:
        try:
            fecha_inicio_dt = datetime.strptime(fecha_inicio, "%Y-%m-%d")
        except ValueError:
            pass
    if fecha_fin:
        try:
            fecha_fin_dt = datetime.strptime(fecha_fin, "%Y-%m-%d")
        except ValueError:
            pass
    if fecha_pago:
        try:
            from datetime import date
            fecha_pago_dt = datetime.strptime(fecha_pago, "%Y-%m-%d").date()
        except ValueError:
            return RedirectResponse(
                url=_append_error_params(
                    "/documentos/nueva-solicitud",
                    error="invalid_fecha_pago",
                    error_msg="La fecha de pago no es válida.",
                ),
                status_code=303
            )
    
    # Parse torneo_id if provided
    torneo_uuid = None
    if torneo_id:
        try:
            torneo_uuid = UUIDType(torneo_id)
            # Verify tournament exists
            torneo_result = await session.execute(
                select(Tournament).where(Tournament.id == torneo_uuid)
            )
            if not torneo_result.scalar_one_or_none():
                torneo_uuid = None
        except ValueError:
            torneo_uuid = None
    
    # Parse and validate proveedor_cliente_id (required)
    if not proveedor_cliente_id or proveedor_cliente_id.strip() == "":
        return RedirectResponse(
            url=_append_error_params(
                "/documentos/nueva-solicitud",
                error="missing_proveedor",
                error_msg="El proveedor/cliente es requerido.",
            ),
            status_code=303
        )
    
    try:
        proveedor_cliente_uuid = UUIDType(proveedor_cliente_id)
    except (ValueError, TypeError):
        return RedirectResponse(
            url=_append_error_params(
                "/documentos/nueva-solicitud",
                error="invalid_proveedor",
                error_msg="El ID del proveedor/cliente no es válido.",
            ),
            status_code=303
        )
    
    # Verify proveedor_cliente exists and is active
    proveedor_result = await session.execute(
        select(ProveedorCliente).where(
            and_(
                ProveedorCliente.id == proveedor_cliente_uuid,
                ProveedorCliente.activo == True
            )
        )
    )
    if not proveedor_result.scalar_one_or_none():
        return RedirectResponse(
            url=_append_error_params(
                "/documentos/nueva-solicitud",
                error="invalid_proveedor",
                error_msg="Proveedor/Cliente inválido o inactivo.",
            ),
            status_code=303
        )
    
    # Validate concepto_pago (required)
    if not concepto_pago or not concepto_pago.strip():
        return RedirectResponse(
            url=_append_error_params(
                "/documentos/nueva-solicitud",
                error="missing_concepto",
                error_msg="El concepto de pago es requerido.",
            ),
            status_code=303
        )
    
    # Generate reference number for SOLICITUD
    numero_referencia = await generate_documento_reference_number(
        session, 'SOLICITUD', current_empleado.id
    )
    
    # Create documento
    documento = Documento(
        empleado_id=current_empleado.id,
        tipo='SOLICITUD',
        numero_referencia=numero_referencia,
        estado='borrador',
        fecha_inicio=fecha_inicio_dt,
        fecha_fin=fecha_fin_dt,
        monto_solicitado=monto,
        monto_total=monto,  # Set monto_total = monto_solicitado for now
        torneo_id=torneo_uuid,
        proveedor_cliente_id=proveedor_cliente_uuid,
        fecha_pago=fecha_pago_dt,
        concepto_pago=concepto_pago.strip() if concepto_pago else None,
        numero_factura=numero_factura.strip() if numero_factura else None,
        referencia_pago=referencia_pago.strip() if referencia_pago else None,
        notas=notas.strip() if notas else None,
    )
    
    session.add(documento)
    await session.commit()
    
    logger.info(f"Created empty SOLICITUD {documento.id} ({numero_referencia}) for empleado {current_empleado.id}")
    
    # Redirect to documento detail page with success message
    return RedirectResponse(
        url=_append_success_params(
            f"/documentos/{documento.id}",
            success_msg=(
                "Solicitud creada exitosamente. "
                "Puedes asignar gastos más adelante desde 'Mis Gastos'."
            ),
        ),
        status_code=303
    )


@router.post("/documentos/crear-desde-gastos")
async def crear_documento_desde_gastos(
    request: Request,
    session: AsyncSession = Depends(get_db_session),
    current_empleado: Empleado = Depends(get_current_empleado),
    gasto_ids: List[UUIDType] = Form(...),
    tipo_documento: str = Form(...),
    torneo_id: Optional[str] = Form(None),
    fecha_inicio: Optional[str] = Form(None),
    fecha_fin: Optional[str] = Form(None),
    notas: Optional[str] = Form(None),
) -> RedirectResponse:
    """
    Create a new Documento (INFORME or SOLICITUD) from selected expenses.
    Uses current empleado from session.
    """
    
    # Validate tipo_documento
    if tipo_documento not in ['INFORME', 'SOLICITUD']:
        return RedirectResponse(
            url="/informes-de-gastos?error=invalid_tipo",
            status_code=303
        )
    
    # Validate at least one gasto selected
    if not gasto_ids:
        return RedirectResponse(
            url="/informes-de-gastos?error=no_gastos_selected",
            status_code=303
        )
    
    # Debug: log count of received gasto_ids (temporary for verification)
    logger.info(f"crear_documento_desde_gastos: Received {len(gasto_ids)} gasto_ids")
    
    # Verify all selected expenses belong to current empleado
    expenses_result = await session.execute(
        select(ExpenseReport).where(
            ExpenseReport.id.in_(gasto_ids),
            ExpenseReport.empleado_id == current_empleado.id
        )
    )
    expenses = expenses_result.scalars().all()
    
    if len(expenses) != len(gasto_ids):
        # Some expenses don't belong to current empleado
        return RedirectResponse(
            url=_append_error_params(
                "/informes-de-gastos",
                error="unauthorized_expenses",
                error_msg="No puedes seleccionar gastos que no te pertenecen.",
            ),
            status_code=303
        )
    
    # Enforce: no cancelled expenses
    cancelled_expenses = [exp for exp in expenses if exp.estado_gasto == 'cancelado']
    if cancelled_expenses:
        return RedirectResponse(
            url=_append_error_params(
                "/informes-de-gastos",
                error="cancelled_expenses",
                error_msg="No puedes seleccionar gastos cancelados.",
            ),
            status_code=303
        )
    
    # Enforce: no locked expenses (linked to documento with estado != 'borrador')
    # Batch load documentos to check lock status
    documento_ids = [exp.documento_id for exp in expenses if exp.documento_id]
    documento_estado_map = {}
    if documento_ids:
        doc_result = await session.execute(
            select(Documento).where(Documento.id.in_(documento_ids))
        )
        documentos = doc_result.scalars().all()
        documento_estado_map = {doc.id: doc.estado for doc in documentos}
    
    locked_expenses = []
    for exp in expenses:
        if exp.documento_id:
            doc_estado = documento_estado_map.get(exp.documento_id)
            if doc_estado and doc_estado != 'borrador':
                locked_expenses.append(exp)
    
    if locked_expenses:
        return RedirectResponse(
            url=_append_error_params(
                "/informes-de-gastos",
                error="locked_expenses",
                error_msg="No puedes seleccionar gastos ya enviados o aprobados en otro documento.",
            ),
            status_code=303
        )
    
    empleado_uuid = current_empleado.id
    
    # Generate reference number
    numero_referencia = await generate_documento_reference_number(
        session, tipo_documento, empleado_uuid
    )
    
    # Parse dates if provided
    fecha_inicio_dt = None
    fecha_fin_dt = None
    if fecha_inicio:
        try:
            fecha_inicio_dt = datetime.strptime(fecha_inicio, "%Y-%m-%d")
        except ValueError:
            pass
    if fecha_fin:
        try:
            fecha_fin_dt = datetime.strptime(fecha_fin, "%Y-%m-%d")
        except ValueError:
            pass
    
    # Parse torneo_id if provided
    torneo_uuid = None
    if torneo_id:
        try:
            torneo_uuid = UUIDType(torneo_id)
            # Verify tournament exists
            torneo_result = await session.execute(
                select(Tournament).where(Tournament.id == torneo_uuid)
            )
            if not torneo_result.scalar_one_or_none():
                torneo_uuid = None
        except ValueError:
            torneo_uuid = None
    
    # Calculate monto_total from selected expenses (exclude cancelled) using Decimal
    monto_total_decimal = sum(Decimal(str(exp.gasto_cantidad)) for exp in expenses if exp.estado_gasto != 'cancelado')
    monto_total = float(monto_total_decimal.quantize(Decimal("0.01"), rounding=ROUND_HALF_UP))
    
    # Create documento
    documento = Documento(
        empleado_id=empleado_uuid,
        tipo=tipo_documento,
        numero_referencia=numero_referencia,
        estado='borrador',
        fecha_inicio=fecha_inicio_dt,
        fecha_fin=fecha_fin_dt,
        monto_total=monto_total,
        torneo_id=torneo_uuid,
        notas=notas.strip() if notas else None,
    )
    
    session.add(documento)
    await session.flush()  # Get the documento.id
    
    # Update each selected expense to link to the documento
    for expense in expenses:
        expense.documento_id = documento.id
    
    await session.commit()
    
    logger.info(f"Created documento {documento.id} ({numero_referencia}) with {len(expenses)} expenses")
    
    # Redirect to documento detail page with success message
    return RedirectResponse(
        url=_append_success_params(
            f"/documentos/{documento.id}",
            success_msg="Documento creado exitosamente",
        ),
        status_code=303
    )


@router.post("/documentos/{documento_id}/asignar-gastos")
async def asignar_gastos_a_documento(
    documento_id: UUIDType,
    request: Request,
    session: AsyncSession = Depends(get_db_session),
    current_empleado: Empleado = Depends(get_current_empleado),
    gasto_ids: List[UUIDType] = Form(...),
) -> RedirectResponse:
    """
    Attach selected existing expenses to an existing document.
    """
    
    # Validate at least one gasto selected
    if not gasto_ids:
        return RedirectResponse(
            url=f"/documentos/{documento_id}?error=no_gastos_selected",
            status_code=303
        )
    
    # Debug: log count of received gasto_ids (temporary for verification)
    logger.info(f"asignar_gastos_a_documento: Received {len(gasto_ids)} gasto_ids for documento {documento_id}")
    
    # Load documento
    doc_result = await session.execute(
        select(Documento).where(Documento.id == documento_id)
    )
    documento = doc_result.scalar_one_or_none()
    
    if not documento:
        return RedirectResponse(
            url=_append_error_params(
                "/informes-de-gastos",
                error="documento_not_found",
                error_msg="Documento no encontrado.",
            ),
            status_code=303
        )
    
    # Validate tipo == 'INFORME'
    if documento.tipo != 'INFORME':
        return RedirectResponse(
            url=_append_error_params(
                "/informes-de-gastos",
                error="invalid_tipo",
                error_msg="Solo se pueden asignar gastos a documentos de tipo INFORME.",
            ),
            status_code=303
        )
    
    # Validate estado == 'borrador'
    if documento.estado != 'borrador':
        return RedirectResponse(
            url=_append_error_params(
                "/informes-de-gastos",
                error="documento_not_borrador",
                error_msg="No se pueden asignar gastos a un documento que no esté en borrador.",
            ),
            status_code=303
        )
    
    # Validate permission:
    # - empleado/coordinador: only their own borrador informe; only their own gastos (see loop below)
    # - finanzas/admin can assign to any borrador informe and any gastos
    if current_empleado.rol not in ('finanzas', 'admin', 'superadmin', 'super_admin'):
        if documento.empleado_id != current_empleado.id:
            return RedirectResponse(
                url=_append_error_params(
                    "/informes-de-gastos",
                    error="permission_denied",
                    error_msg="No tienes permiso para asignar gastos a este informe. Solo puedes asignar a tus propios informes en borrador.",
                ),
                status_code=303
            )
    
    # Load expenses
    expenses_result = await session.execute(
        select(ExpenseReport).where(ExpenseReport.id.in_(gasto_ids))
    )
    expenses = expenses_result.scalars().all()
    
    # Verify all expenses belong to current empleado (unless user has privileged role)
    if current_empleado.rol not in ['finanzas', 'admin', 'superadmin', 'super_admin']:
        for expense in expenses:
            if expense.empleado_id != current_empleado.id:
                raise HTTPException(status_code=403, detail="No puede asignar gastos que no le pertenecen")
    
    # B) Validate selected expenses: no cancelled expenses
    cancelled_expenses = [exp for exp in expenses if exp.estado_gasto == 'cancelado']
    if cancelled_expenses:
        return RedirectResponse(
            url=_append_error_params(
                f"/documentos/{documento_id}",
                error="cancelled_expenses",
                error_msg="No puedes asignar gastos cancelados.",
            ),
            status_code=303
        )
    
    # C) Validate selected expenses: no locked expenses (except if already linked to THIS documento)
    # Batch load documentos to check lock status
    documento_ids = [exp.documento_id for exp in expenses if exp.documento_id and exp.documento_id != documento_id]
    documento_estado_map = {}
    if documento_ids:
        doc_result = await session.execute(
            select(Documento).where(Documento.id.in_(documento_ids))
        )
        documentos = doc_result.scalars().all()
        documento_estado_map = {doc.id: doc.estado for doc in documentos}
    
    locked_expenses = []
    for exp in expenses:
        # Skip if already linked to THIS documento (no-op, handle gracefully)
        if exp.documento_id == documento_id:
            continue
        # Check if locked in another documento
        if exp.documento_id:
            doc_estado = documento_estado_map.get(exp.documento_id)
            if doc_estado and doc_estado != 'borrador':
                locked_expenses.append(exp)
    
    if locked_expenses:
        return RedirectResponse(
            url=_append_error_params(
                f"/documentos/{documento_id}",
                error="locked_expenses",
                error_msg="No puedes asignar gastos ya enviados o aprobados en otro documento.",
            ),
            status_code=303
        )
    
    # Update each expense to link to the documento
    for expense in expenses:
        expense.documento_id = documento.id
    
    # Recalculate monto_total (exclude cancelled) using Decimal
    all_expenses_result = await session.execute(
        select(ExpenseReport).where(
            and_(
                ExpenseReport.documento_id == documento_id,
                ExpenseReport.estado_gasto != 'cancelado'
            )
        )
    )
    all_expenses = all_expenses_result.scalars().all()
    total_decimal = sum(Decimal(str(exp.gasto_cantidad)) for exp in all_expenses)
    documento.monto_total = float(total_decimal.quantize(Decimal("0.01"), rounding=ROUND_HALF_UP))
    
    await session.commit()
    
    logger.info(f"Assigned {len(expenses)} expenses to documento {documento_id}")
    
    # Redirect back to documento detail with success message
    return RedirectResponse(
        url=_append_success_params(
            f"/documentos/{documento_id}",
            success_msg="Gastos asignados al documento exitosamente",
        ),
        status_code=303
    )


@router.post("/documentos/{documento_id}/enviar")
async def enviar_documento(
    documento_id: UUIDType,
    request: Request,
    session: AsyncSession = Depends(get_db_session),
    current_empleado: Empleado = Depends(get_current_empleado),
    next: Optional[str] = Form(None),
) -> RedirectResponse:
    """
    Move a document from borrador to enviado.
    Only allowed if current estado is borrador and document belongs to current empleado.
    Document must have at least one gasto.
    
    Args:
        next: Optional redirect URL after action (from form field or query param)
    """
    try:
        await transition_documento_workflow(
            session,
            documento_id=documento_id,
            actor_id=current_empleado.id,
            action="send",
        )
    except DocumentoWorkflowPermissionError as exc:
        if exc.code == "owner_mismatch":
            raise HTTPException(status_code=403, detail=exc.message)
        raise
    except DocumentoWorkflowValidationError as exc:
        if exc.code == "documento_not_found":
            raise HTTPException(status_code=404, detail=exc.message)
        redirect_url = determine_redirect_url(
            next, documento_id, default_to_detail=True
        )
        return RedirectResponse(
            url=_append_error_params(
                redirect_url,
                error=exc.code,
                error_msg=exc.message,
            ),
            status_code=303,
        )
    except Exception:
        await session.rollback()
        logger.exception(
            "Unexpected error sending documento for approval",
            extra={
                "documento_id": str(documento_id),
                "actor_id": str(current_empleado.id),
                "action": "send",
            },
        )
        redirect_url = determine_redirect_url(next, documento_id, default_to_detail=True)
        return RedirectResponse(
            url=_append_error_params(
                redirect_url,
                error="unexpected_documento_workflow",
                error_msg=(
                    "Ocurrió un error al procesar la acción sobre el documento. "
                    "Intente nuevamente."
                ),
            ),
            status_code=303,
        )
    
    logger.info(f"Documento {documento_id} enviado para aprobación")
    
    # Determine redirect URL
    redirect_url = determine_redirect_url(next, documento_id, default_to_detail=True)
    redirect_with_msg = _append_success_params(
        redirect_url,
        success_msg="Documento enviado para aprobación",
    )
    
    return RedirectResponse(
        url=redirect_with_msg,
        status_code=303
    )


@router.post("/documentos/{documento_id}/aprobar")
async def aprobar_documento(
    documento_id: UUIDType,
    request: Request,
    session: AsyncSession = Depends(get_db_session),
    current_empleado: Empleado = Depends(get_current_empleado),
    comentario: Optional[str] = Form(None),
    next: Optional[str] = Form(None),
) -> RedirectResponse:
    """
    Approve a document.
    Only allowed if estado is enviado and user has appropriate role.
    Document must have at least one gasto.
    
    Args:
        next: Optional redirect URL after action (from form field or query param)
    """
    try:
        await transition_documento_workflow(
            session,
            documento_id=documento_id,
            actor_id=current_empleado.id,
            action="approve",
            comentario=comentario,
        )
    except DocumentoWorkflowPermissionError as exc:
        if exc.code == "insufficient_role":
            raise HTTPException(status_code=403, detail=exc.message)
        raise
    except DocumentoWorkflowValidationError as exc:
        if exc.code == "documento_not_found":
            raise HTTPException(status_code=404, detail=exc.message)
        redirect_url = determine_redirect_url(next, documento_id, default_to_detail=True)
        if exc.code == "not_assigned_approver":
            return RedirectResponse(
                url=_append_error_params(
                    redirect_url,
                    error_msg=exc.message,
                ),
                status_code=303,
            )
        return RedirectResponse(
            url=_append_error_params(
                redirect_url,
                error=exc.code,
                error_msg=exc.message,
            ),
            status_code=303,
        )
    except Exception:
        await session.rollback()
        logger.exception(
            "Unexpected error approving documento",
            extra={
                "documento_id": str(documento_id),
                "actor_id": str(current_empleado.id),
                "action": "approve",
            },
        )
        redirect_url = determine_redirect_url(next, documento_id, default_to_detail=True)
        return RedirectResponse(
            url=_append_error_params(
                redirect_url,
                error="unexpected_documento_workflow",
                error_msg=(
                    "Ocurrió un error al procesar la acción sobre el documento. "
                    "Intente nuevamente."
                ),
            ),
            status_code=303,
        )
    
    logger.info(f"Documento {documento_id} aprobado por {current_empleado.id}")
    
    # Determine redirect URL (default to /documentos/pendientes for approver workflows)
    redirect_url = await _resolve_documento_queue_redirect_url(
        session,
        current_empleado=current_empleado,
        current_documento_id=documento_id,
        next_param=next,
        default_to_detail=True,
    )
    redirect_with_msg = _append_success_params(
        redirect_url,
        success_msg="Documento aprobado exitosamente",
    )
    
    return RedirectResponse(
        url=redirect_with_msg,
        status_code=303
    )


