@router.get("/documentos/{documento_id}/exportar-diot.xlsx", response_model=None)
async def exportar_diot_excel(
    documento_id: UUIDType,
    session: AsyncSession = Depends(get_db_session),
    current_empleado: Empleado = Depends(get_current_empleado),
) -> Union[Response, RedirectResponse]:
    try:
        documento, expenses, _ = await _build_documento_coi_bundle(
            documento_id, session, current_empleado
        )
    except HTTPException as exc:
        if exc.status_code == 400:
            return RedirectResponse(
                url=_append_error_params(
                    f"/documentos/{documento_id}",
                    error="no_gastos",
                    error_msg="No hay gastos activos asociados para generar DIOT.",
                ),
                status_code=303,
            )
        if exc.status_code == 409:
            return RedirectResponse(
                url=_append_error_params(
                    f"/documentos/{documento_id}",
                    error="informe_not_approved",
                    error_msg="La DIOT se habilita cuando el INFORME esté aprobado.",
                ),
                status_code=303,
            )
        raise

    export = build_diot_export(expenses)
    xlsx_bytes = create_diot_excel(export)
    filename = f"DIOT_{documento.numero_referencia}.xlsx"
    return Response(
        content=xlsx_bytes,
        media_type=(
            "application/vnd.openxmlformats-officedocument.spreadsheetml.sheet"
        ),
        headers={"Content-Disposition": f'attachment; filename="{filename}"'},
    )


@router.get("/documentos/{documento_id}/exportar-diot.txt", response_model=None)
async def exportar_diot_txt(
    documento_id: UUIDType,
    session: AsyncSession = Depends(get_db_session),
    current_empleado: Empleado = Depends(get_current_empleado),
) -> Union[Response, RedirectResponse]:
    try:
        documento, expenses, _ = await _build_documento_coi_bundle(
            documento_id, session, current_empleado
        )
    except HTTPException as exc:
        if exc.status_code == 400:
            return RedirectResponse(
                url=_append_error_params(
                    f"/documentos/{documento_id}",
                    error="no_gastos",
                    error_msg="No hay gastos activos asociados para generar DIOT.",
                ),
                status_code=303,
            )
        if exc.status_code == 409:
            return RedirectResponse(
                url=_append_error_params(
                    f"/documentos/{documento_id}",
                    error="informe_not_approved",
                    error_msg="La DIOT se habilita cuando el INFORME esté aprobado.",
                ),
                status_code=303,
            )
        raise

    export = build_diot_export(expenses)
    txt_bytes = generate_diot_txt(export)
    filename = f"DIOT_{documento.numero_referencia}.txt"
    return Response(
        content=txt_bytes,
        media_type="text/plain; charset=utf-8",
        headers={"Content-Disposition": f'attachment; filename="{filename}"'},
    )


@router.get("/gastos/{gasto_id}/exportar-coi.xlsx", response_model=None)
async def exportar_coi_poliza_gasto_excel(
    gasto_id: UUIDType,
    session: AsyncSession = Depends(get_db_session),
    current_empleado: Empleado = Depends(get_current_empleado),
) -> Union[Response, RedirectResponse]:
    """Export one COI poliza XLSX for a single limpieza-ready expense."""
    expense = await load_expense_for_coi_export(session, gasto_id)
    if expense is None:
        raise HTTPException(status_code=404, detail="Gasto no encontrado")

    if (
        expense.empleado_id != current_empleado.id
        and current_empleado.rol
        not in ["coordinador", "finanzas", "admin", "superadmin", "super_admin"]
    ):
        raise HTTPException(status_code=403, detail="Access denied")

    try:
        expense_cfdi = await build_expense_cfdi_for_export(session, expense)
        xlsx_bytes = generate_coi_poliza_xlsx([expense_cfdi])
    except ValueError as exc:
        return RedirectResponse(
            url=_append_error_params(
                f"/gastos/{gasto_id}",
                error="coi_not_ready",
                error_msg=str(exc),
            ),
            status_code=303,
        )
    except Exception as exc:
        logger.error(
            "Error generating COI poliza XLSX for gasto %s: %s",
            gasto_id,
            exc,
            exc_info=True,
        )
        return RedirectResponse(
            url=_append_error_params(
                f"/gastos/{gasto_id}",
                error="coi_generation_error",
                error_msg="Ocurrió un error al generar la póliza COI.",
            ),
            status_code=303,
        )

    filename_base = _safe_export_filename(
        expense.numero_referencia or str(expense.id)[:8]
    )
    filename = f"Poliza_COI_{filename_base}.xlsx"
    return Response(
        content=xlsx_bytes,
        media_type=(
            "application/vnd.openxmlformats-officedocument.spreadsheetml.sheet"
        ),
        headers={"Content-Disposition": f'attachment; filename="{filename}"'},
    )


