# Message when DB is missing v1.0.19 columns (tipo_cuenta, torneo_id, fase)
_SCHEMA_OUTDATED_MSG = (
    "La base de datos no tiene las columnas de clasificación (tipo_cuenta, torneo_id, fase). "
    "Ejecute la migración v1.0.19 en el servidor: DATABASE_URL=... python scripts/apply_migration_v1_0_19.py"
)


def _schema_outdated_html_response() -> HTMLResponse:
    """Return an HTML error page when DB schema is missing columns (e.g. cuenta_gastos_id, tipo_cuenta)."""
    html = f"""<!DOCTYPE html>
<html>
<head><title>Base de datos desactualizada - Copa Telmex</title></head>
<body style="font-family: Arial, sans-serif; max-width: 600px; margin: 40px auto; padding: 20px;">
    <h1 style="color: #856404;">Base de datos desactualizada</h1>
    <p>{escape(_SCHEMA_OUTDATED_MSG)}</p>
    <p>Si el problema persiste, verifique las migraciones v1.0.18, v1.0.19 (columnas tipo_cuenta/torneo_id/fase) y v1.0.22 (reglas de informe / torneo obligatorio).</p>
    <p><a href="/informes-de-gastos">Volver a Informes de Gastos</a></p>
</body>
</html>"""
    return HTMLResponse(content=html, status_code=503)


CUENTA_INFORME_TIPOS_VALIDOS = frozenset({"local", "viaje", "nacional", "extranjero"})


def _cuenta_informe_tipo_label(tipo_code: str) -> str:
    labels = {
        "local": "Local",
        "viaje": "Viaje",
        "nacional": "Nacional",
        "extranjero": "Extranjero",
    }
    key = (tipo_code or "").strip().lower()
    return labels.get(key, (key or "local").capitalize())


def _get_cuenta_fase_raw(cuenta) -> str:
    try:
        v = getattr(cuenta, "fase", None)
        return (str(v) if v is not None else "").strip()
    except (ProgrammingError, OperationalError, Exception):
        return ""


def _cuenta_etapas_map_for_js(torneos: List[Any]) -> Dict[str, List[str]]:
    out: Dict[str, List[str]] = {}
    for t in torneos:
        etapas = getattr(t, "etapas", None)
        if etapas and isinstance(etapas, list):
            out[str(t.id)] = [
                str(x).strip() for x in etapas if x is not None and str(x).strip()
            ]
        else:
            out[str(t.id)] = []
    return out


def _tournament_categories_map_for_js(torneos: List[Any]) -> Dict[str, List[str]]:
    return {str(t.id): configured_categories(t) for t in torneos}


async def _tournament_budget_concepts_map_for_js(
    session: AsyncSession,
    torneos: List[Any],
) -> Dict[str, List[Dict[str, str]]]:
    concept_rows = await list_budget_concepts(session, active_only=True, limit=5000)
    by_tournament: Dict[str, List[Dict[str, str]]] = {}
    for torneo in torneos:
        aliases = budget_alias_candidates(getattr(torneo, "name", "") or "")
        items = [
            {
                "id": str(item.get("id") or ""),
                "label": str(item.get("concept_name") or ""),
                "global": budget_concept_matches_fase(item, None)
                and not (
                    (item.get("metadata") or {}).get("applicable_phase_keys")
                    or (item.get("metadata") or {}).get("applicable_subproject_keys")
                ),
                "applicable_keys": sorted(
                    {
                        str(key).strip()
                        for key in (
                            list((item.get("metadata") or {}).get("applicable_phase_keys") or [])
                            + list((item.get("metadata") or {}).get("applicable_subproject_keys") or [])
                        )
                        if str(key).strip()
                    }
                ),
            }
            for item in concept_rows
            if str(item.get("tournament_id") or "") == str(torneo.id)
            or (
                aliases
                and budget_alias_candidates(
                    item.get("tournament_code") or "",
                    item.get("tournament_name") or "",
                )
                & aliases
            )
        ]
        by_tournament[str(torneo.id)] = sorted(
            items,
            key=lambda entry: str(entry.get("label") or "").lower(),
        )
    return by_tournament


def _html_budget_concept_options(
    concepts: List[Dict[str, str]],
    selected_id: Optional[str],
    *,
    required: bool,
) -> str:
    placeholder = (
        '<option value="" disabled selected>— Seleccione partida presupuestal —</option>'
        if not selected_id
        else '<option value="">— Seleccione partida presupuestal —</option>'
    )
    options = [placeholder]
    for concept in concepts:
        concept_id = str(concept.get("id") or "")
        label = str(concept.get("label") or "")
        if not concept_id or not label:
            continue
        selected_attr = ' selected' if concept_id == str(selected_id or "") else ""
        options.append(
            f'<option value="{escape(concept_id)}"{selected_attr}>{escape(label)}</option>'
        )
    if not required:
        options[0] = (
            '<option value="" selected>— Sin partida presupuestal —</option>'
            if not selected_id
            else '<option value="">— Sin partida presupuestal —</option>'
        )
    return "".join(options)


def _filter_budget_concepts_for_fase(
    concepts: List[Dict[str, Any]],
    fase: Optional[str],
) -> List[Dict[str, Any]]:
    if not (fase or "").strip():
        return concepts
    return [
        concept
        for concept in concepts
        if budget_concept_matches_fase(
            {
                "metadata": {
                    "applicable_phase_keys": concept.get("applicable_keys") or [],
                    "applicable_subproject_keys": concept.get("applicable_keys") or [],
                }
            },
            fase,
        )
    ]


async def _budget_concepts_for_cuenta(
    session: AsyncSession,
    cuenta: CuentaDeGastos,
) -> List[Dict[str, Any]]:
    """Active partidas presupuestales for a cuenta's torneo, filtered by fase."""
    torneo_id = getattr(cuenta, "torneo_id", None)
    if torneo_id is None:
        return []
    rows = await list_budget_concepts(
        session,
        tournament_id=str(torneo_id),
        active_only=True,
        limit=500,
    )
    return _filter_budget_concepts_for_fase(
        [
            {
                "id": str(item.get("id") or ""),
                "label": str(item.get("concept_name") or ""),
                "applicable_keys": sorted(
                    {
                        str(key).strip()
                        for key in (
                            list((item.get("metadata") or {}).get("applicable_phase_keys") or [])
                            + list((item.get("metadata") or {}).get("applicable_subproject_keys") or [])
                        )
                        if str(key).strip()
                    }
                ),
                "global": not (
                    (item.get("metadata") or {}).get("applicable_phase_keys")
                    or (item.get("metadata") or {}).get("applicable_subproject_keys")
                ),
            }
            for item in rows
        ],
        getattr(cuenta, "fase", None),
    )


def _render_budget_concept_sync_script(
    *,
    concept_map: Dict[str, List[Dict[str, str]]],
    tournament_select_id: str,
    concept_select_id: str,
    selected_id: Optional[str],
    required: bool,
    phase_select_id: Optional[str] = None,
) -> str:
    concept_map_json = json.dumps(concept_map)
    selected_json = json.dumps(selected_id or "")
    placeholder = (
        "— Seleccione partida presupuestal —"
        if required
        else "— Sin partida presupuestal —"
    )
    return f"""
    <script>
        (function() {{
            var conceptMap = {concept_map_json};
            var tournamentSelect = document.getElementById({json.dumps(tournament_select_id)});
            var conceptSelect = document.getElementById({json.dumps(concept_select_id)});
            var phaseSelect = document.getElementById({json.dumps(phase_select_id)}) || null;
            var selectedId = {selected_json};
            if (!tournamentSelect || !conceptSelect) return;
            function normalizeScopeKey(value) {{
                if (!value) return "";
                var normalized = String(value)
                    .trim()
                    .toLowerCase()
                    .normalize("NFD")
                    .replace(/[\u0300-\u036f]/g, "")
                    .replace(/[^a-z0-9]+/g, "_")
                    .replace(/^_+|_+$/g, "")
                    .replace(/^fase_/, "");
                return normalized;
            }}
            function itemMatchesPhase(item) {{
                if (!phaseSelect) return true;
                var selectedKey = normalizeScopeKey(phaseSelect.value || "");
                if (!selectedKey) return true;
                if (item.global) return true;
                var keys = Array.isArray(item.applicable_keys) ? item.applicable_keys : [];
                return keys.indexOf(selectedKey) >= 0 || keys.indexOf("fase_" + selectedKey) >= 0;
            }}
            function syncBudgetConcepts() {{
                var items = (conceptMap[tournamentSelect.value] || []).filter(itemMatchesPhase);
                conceptSelect.innerHTML = "";
                var placeholder = document.createElement("option");
                placeholder.value = "";
                placeholder.textContent = {json.dumps(placeholder)};
                placeholder.disabled = {json.dumps(required)};
                placeholder.selected = !selectedId;
                conceptSelect.appendChild(placeholder);
                items.forEach(function(item) {{
                    var option = document.createElement("option");
                    option.value = item.id;
                    option.textContent = item.label;
                    option.selected = item.id === selectedId;
                    conceptSelect.appendChild(option);
                }});
                conceptSelect.disabled = items.length === 0;
                conceptSelect.required = items.length > 0 && {json.dumps(required)};
            }}
            tournamentSelect.addEventListener("change", function() {{
                selectedId = "";
                syncBudgetConcepts();
            }});
            if (phaseSelect) {{
                phaseSelect.addEventListener("change", function() {{
                    selectedId = "";
                    syncBudgetConcepts();
                }});
            }}
            syncBudgetConcepts();
        }})();
    </script>
    """


def _html_category_options(categories: List[str], selected: List[str]) -> str:
    selected_set = set(selected)
    return "".join(
        f'<option value="{escape(category)}"'
        f'{" selected" if category in selected_set else ""}>{escape(category)}</option>'
        for category in categories
    )


def _render_category_sync_script(
    *,
    category_map: Dict[str, List[str]],
    tournament_select_id: str,
    category_select_id: str,
) -> str:
    category_map_json = json.dumps(category_map)
    return f"""
    <script>
        (function() {{
            var categoryMap = {category_map_json};
            var tournamentSelect = document.getElementById({json.dumps(tournament_select_id)});
            var categorySelect = document.getElementById({json.dumps(category_select_id)});
            if (!tournamentSelect || !categorySelect) return;
            function syncCategories() {{
                var categories = categoryMap[tournamentSelect.value] || [];
                categorySelect.innerHTML = '';
                categories.forEach(function(category) {{
                    var option = document.createElement('option');
                    option.value = category;
                    option.textContent = category;
                    option.selected = true;
                    categorySelect.appendChild(option);
                }});
            }}
            tournamentSelect.addEventListener('change', syncCategories);
            syncCategories();
        }})();
    </script>
    """


async def _validate_expense_metadata_for_tournament(
    session: AsyncSession,
    *,
    torneo_id: UUIDType,
    categorias_raw: List[str],
    edicion_raw: object,
    currency_raw: Optional[str],
) -> Tuple[Optional[str], List[str], Optional[int], Optional[str]]:
    try:
        edition = normalize_edition(edicion_raw, default_current_year=True)
        currency = normalize_currency(currency_raw)
    except ValueError as exc:
        return str(exc), [], None, None
    if not categorias_raw:
        return None, [], edition, currency
    tournament = await session.get(Tournament, torneo_id)
    if not tournament:
        return "El torneo/proyecto indicado no existe.", [], None, None
    try:
        categories = normalize_categories(categorias_raw, tournament)
    except ValueError as exc:
        return str(exc), [], None, None
    return None, categories, edition, currency


def _html_fase_options_for_etapas(
    etapas: List[str],
    selected: str,
    *,
    legacy_value: Optional[str] = None,
) -> str:
    opts: List[str] = [
        '<option value="">— Sin fase / subproyecto —</option>',
    ]
    sel_norm = (selected or "").strip()
    for e in etapas:
        sel = " selected" if e == sel_norm else ""
        opts.append(f'<option value="{escape(e)}"{sel}>{escape(e)}</option>')
    if legacy_value and legacy_value.strip():
        lv = legacy_value.strip()
        if lv not in etapas:
            sel = " selected" if lv == sel_norm else ""
            opts.append(
                f'<option value="{escape(lv)}"{sel}>(Valor actual) {escape(lv)}</option>'
            )
    return "".join(opts)


async def _validate_cuenta_informe_proyecto_fields(
    session: AsyncSession,
    *,
    empleado: Empleado,
    tipo_cuenta_raw: str,
    torneo_id_raw: str,
    fase_raw: str,
    require_torneo_active: bool,
) -> Tuple[Optional[str], Optional[str], Optional[UUIDType], Optional[str]]:
    """
    Validate informe/cuenta project fields. Returns
    (error_message, normalized_tipo, torneo_uuid, fase_or_none).
    """
    tipo = (tipo_cuenta_raw or "").strip().lower() or "local"
    if tipo not in CUENTA_INFORME_TIPOS_VALIDOS:
        return "Tipo de gasto no válido.", None, None, None
    if not (torneo_id_raw and str(torneo_id_raw).strip()):
        return "Debe seleccionar Torneo/Proyecto.", None, None, None
    try:
        torneo_uuid = UUIDType(str(torneo_id_raw).strip())
    except (ValueError, TypeError):
        return "Torneo/Proyecto inválido.", None, None, None

    t_row = await session.get(Tournament, torneo_uuid)
    if not t_row:
        return "El torneo/proyecto indicado no existe.", None, None, None
    if require_torneo_active and not bool(getattr(t_row, "active", True)):
        return "Debe seleccionar un torneo/proyecto activo.", None, None, None

    vis_err = visibility_validation_error(t_row, empleado)
    if vis_err:
        return vis_err, None, None, None

    raw_etapas = getattr(t_row, "etapas", None)
    allowed: List[str] = []
    if raw_etapas and isinstance(raw_etapas, list):
        allowed = [str(x).strip() for x in raw_etapas if x is not None and str(x).strip()]

    fase_st = (fase_raw or "").strip()
    if fase_st:
        if not allowed:
            return (
                "Este torneo/proyecto no tiene fases configuradas; deje Fase/Subproyecto vacío.",
                None,
                None,
                None,
            )
        if fase_st not in allowed:
            return (
                "La fase no corresponde al torneo/proyecto seleccionado.",
                None,
                None,
                None,
            )
        return None, tipo, torneo_uuid, fase_st
    return None, tipo, torneo_uuid, None


def _get_cuenta_tipo_torneo_fase(cuenta) -> tuple:
    """Safely get (tipo_cuenta, torneo_name, fase) from a CuentaDeGastos. Uses defaults if columns missing."""
    try:
        tipo = (getattr(cuenta, "tipo_cuenta", None) or "local").strip().lower() or "local"
    except (ProgrammingError, OperationalError, Exception):
        tipo = "local"
    torneo_name = "—"
    try:
        if getattr(cuenta, "torneo_id", None):
            t = getattr(cuenta, "torneo", None)
            torneo_name = t.name if t else "—"
    except (ProgrammingError, OperationalError, Exception):
        pass
    try:
        fase_raw = getattr(cuenta, "fase", None)
        fase = (str(fase_raw).strip() if fase_raw is not None else "") or "—"
    except (ProgrammingError, OperationalError, Exception):
        fase = "—"
    return (tipo, torneo_name, fase)


async def _create_cuenta_de_gastos_with_informe(
    session: AsyncSession,
    *,
    empleado: Empleado,
    nombre: Optional[str],
    tipo_cuenta: str,
    torneo_id: UUIDType,
    fase: Optional[str],
    categorias: List[str],
    edicion: Optional[int],
    currency: str,
) -> Tuple[Optional[CuentaDeGastos], Optional[str]]:
    """Create CuentaDeGastos + INFORME documento (borrador). Returns (cuenta, error_msg)."""
    referencia_base_final: Optional[str] = None
    for _ in range(25):
        referencia_base_try = generate_referencia_base()
        existing = await session.execute(
            select(CuentaDeGastos).where(
                CuentaDeGastos.empleado_id == empleado.id,
                CuentaDeGastos.referencia_base == referencia_base_try,
            )
        )
        if existing.scalar_one_or_none():
            continue
        referencia_base_final = referencia_base_try
        break
    if referencia_base_final is None:
        return None, "No se pudo generar una referencia interna única. Intente de nuevo."

    try:
        cuenta = CuentaDeGastos(
            empleado_id=empleado.id,
            referencia_base=referencia_base_final,
            nombre=nombre,
            estado="abierta",
            tipo_cuenta=tipo_cuenta,
            torneo_id=torneo_id,
            fase=fase,
            categorias=categorias,
            edicion=edicion,
            currency=currency,
        )
        session.add(cuenta)
        await session.flush()
        ro_informe = await allocate_referencia_operaciones_for_empleado(
            session, empleado
        )
        informe = Documento(
            empleado_id=empleado.id,
            tipo="INFORME",
            numero_referencia=f"I-{referencia_base_final}",
            estado="borrador",
            referencia_base=referencia_base_final,
            referencia_operaciones=ro_informe,
            cuenta_gastos_id=cuenta.id,
            categorias=categorias,
            edicion=edicion,
            currency=currency,
        )
        session.add(informe)
        await session.commit()
        return cuenta, None
    except (ProgrammingError, OperationalError):
        await session.rollback()
        return None, _SCHEMA_OUTDATED_MSG


def generate_referencia_base() -> str:
    """Generate a unique numeric referencia_base (6 digits)."""
    import random
    return str(random.randint(100000, 999999))


# Stable PostgreSQL advisory lock key for global Referencia Operaciones allocation.
_REFERENCIA_OPERACIONES_ADVISORY_LOCK_KEY = 5_842_910_472_931


async def allocate_next_referencia_operaciones(session: AsyncSession) -> str:
    """Compatibility wrapper around the shared referencia_operaciones allocator."""
    return await service_allocate_next_referencia_operaciones(session)


async def _informe_documento_for_cuenta(
    session: AsyncSession, cuenta_id: UUIDType
) -> Optional[Documento]:
    """Return the primary INFORME document for a Cuenta de Gastos (oldest by creado_en)."""
    r = await session.execute(
        select(Documento)
        .where(
            Documento.cuenta_gastos_id == cuenta_id,
            Documento.tipo == "INFORME",
        )
        .order_by(Documento.creado_en.asc())
        .limit(1)
    )
    return r.scalar_one_or_none()


def _safe_internal_next(next_param: Optional[str], fallback: str) -> str:
    if next_param:
        next_url = unquote(next_param).strip()
        if next_url.startswith("/") and not next_url.startswith("//"):
            return next_url
    return fallback


def _append_query_params(url: str, params: Dict[str, str]) -> str:
    sep = "&" if "?" in url else "?"
    return url + sep + "&".join(
        f"{key}={quote(str(value))}" for key, value in params.items()
    )


def _append_success_params(
    url: str,
    *,
    success_msg: Optional[str] = None,
    success: Optional[str] = None,
    msg: Optional[str] = None,
) -> str:
    params: Dict[str, str] = {}
    if success_msg is not None:
        params["success_msg"] = success_msg
    if success is not None:
        params["success"] = success
    if msg is not None:
        params["msg"] = msg
    return _append_query_params(url, params)


def _append_error_params(
    url: str,
    *,
    error_msg: Optional[str] = None,
    error: Optional[str] = None,
) -> str:
    params: Dict[str, str] = {}
    if error is not None:
        params["error"] = error
    if error_msg is not None:
        params["error_msg"] = error_msg
    return _append_query_params(url, params)


async def _count_active_cuenta_expenses(
    session: AsyncSession, cuenta_id: UUIDType
) -> int:
    result = await session.execute(
        select(func.count(ExpenseReport.id)).where(
            ExpenseReport.cuenta_gastos_id == cuenta_id,
            ExpenseReport.estado_gasto != "cancelado",
        )
    )
    return int(result.scalar_one() or 0)


async def _sync_informe_documento_to_enviado(
    session: AsyncSession,
    *,
    cuenta: CuentaDeGastos,
    informe_doc: Documento,
    actor: Empleado,
) -> bool:
    """Send a linked INFORME document to approval when closing its cuenta."""
    if informe_doc.estado != "borrador":
        return False

    active_expenses = await _count_active_cuenta_expenses(session, cuenta.id)
    if active_expenses == 0:
        raise DocumentoWorkflowValidationError(
            "no_gastos",
            "El informe debe tener al menos un gasto activo antes de poder cerrarse.",
        )

    now = datetime.utcnow()
    informe_doc.estado = "enviado"
    informe_doc.enviado_en = now
    session.add(
        Aprobacion(
            tipo_entidad="documento",
            entidad_id=informe_doc.id,
            aprobador_id=actor.id,
            accion="enviar",
            comentario="Enviado automáticamente al cerrar el informe de gastos.",
            fecha=now,
        )
    )
    return True


@router.get("/api/informes-de-gastos/activas", response_class=JSONResponse)
async def api_cuentas_de_gastos_activas(
    session: AsyncSession = Depends(get_db_session),
    current_empleado: Empleado = Depends(get_current_empleado),
) -> JSONResponse:
    """
    API endpoint to get active (abierta) cuentas de gastos for current user.
    Used by the dropdown in /informes-de-gastos.
    """
    try:
        query = select(CuentaDeGastos).where(
            CuentaDeGastos.empleado_id == current_empleado.id,
            CuentaDeGastos.estado == 'abierta'
        ).order_by(CuentaDeGastos.created_at.desc())
        
        result = await session.execute(query)
        cuentas = result.scalars().all()
    except (ProgrammingError, OperationalError):
        return JSONResponse(
            content={"error": _SCHEMA_OUTDATED_MSG, "cuentas": []},
            status_code=503
        )
    
    return JSONResponse(content={
        "cuentas": [
            {
                "id": str(c.id),
                "referencia_base": c.referencia_base,
                "nombre": getattr(c, "nombre", None),
                "estado": c.estado,
                "created_at": c.created_at.isoformat() if c.created_at else None,
            }
            for c in cuentas
        ]
    })


